-- Phase 7 INSERT part 04/6 (250 cards)
-- 자동 생성: scripts_phase7/02_json_to_sql.py

insert into public.qas
  (doctor_id, type, category, status, published,
   question, answer, keywords,
   post_year, post_slug, external_url, pubmed_ref,
   created_at, updated_at)
values
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스는 한 번 맞으면 평생 맞아야 하나요?$AAQ$, $AAA$보톡스는 한 번 맞아도 평생 맞을 필요는 없고, 원할 때 맞고 언제든 중단할 수 있습니다. 다만 보톡스 효과는 **3~5개월 정도 지속되다가** 사라지기 때문에, 주름이 펴진 모습을 본 뒤 다시 주름이 생기면 견디기 어려워 본인이 찾아 맞게 되는 거예요. 그래서 못 끊는다는 오해가 생긴 겁니다.

새치 염색과 비슷한 결인데, 안 해도 되지만 젊어진 모습을 보면 다시 안 하기 어렵다는 점이 닮았어요. 한편 가만히 있을 때도 골이 잡혀 있는 깊은 주름은 보톡스로 펴지지 않습니다. **그래도 안 맞으면 주름이 점점 더 깊어지므로 예방 차원에서 권유**하고, 깊지 않은 주름은 1~2년 꾸준히 맞으면 고정된 주름도 어느 정도 펴지는 효과가 있어요. 정말 깊은 골진 주름은 보톡스로 잡은 뒤 필러나 쥬베룩 같은 시술을 더해야 합니다.$AAA$, array['보톡스지속기간', '보톡스중단', '주름보톡스', '깊은주름', '보톡스예방효과']::text[], 2025, 'YRaF1DQ4QUA-1', 'https://youtu.be/YRaF1DQ4QUA?t=37s', null, '2025-02-11 00:00:00+00'::timestamptz, '2025-02-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$주름 보톡스와 스킨 보톡스는 어떻게 다른가요?$AAQ$, $AAA$주름 보톡스는 근육층에 작용하고 스킨 보톡스는 피부 얕은 층에 작용한다는 점에서 기능과 목적이 완전히 다른 시술입니다. **주름 보톡스는 근육의 움직임을 줄여** 미간을 찡그릴 때, 눈웃음 칠 때, 이마를 올릴 때처럼 움직일 때 접히는 주름을 안 접히게 해주는 시술이에요. 보통 눈가, 미간, 이마에 놓습니다.

반면 스킨 보톡스는 보톡스를 묽게 해서 피부의 굉장히 얕은 층에 쫙 깔아 줍니다. 그러면 **피부결이 맨질맨질해지고 모공이 줄어들며 유분기가 많은 분은 피지 조절도 어느 정도 가능**해요. 전반적으로 광이 나고 반질반질해 보이는 효과가 있죠. 이름은 비슷하지만 한쪽은 근육 움직임으로 생기는 주름을, 다른 한쪽은 피부 표면 결과 광택을 다루는 시술이라는 점을 구분해서 선택하시면 됩니다.$AAA$, array['주름보톡스', '스킨보톡스', '근육층보톡스', '피지조절', '보톡스차이']::text[], 2025, 'YRaF1DQ4QUA-2', 'https://youtu.be/YRaF1DQ4QUA?t=147s', null, '2025-02-11 00:00:00+00'::timestamptz, '2025-02-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사각턱 보톡스 맞고 볼이 패였는데 영구적인가요?$AAQ$, $AAA$사각턱 보톡스 후 생긴 볼 패임은 영구적이지 않고, 보톡스 효과가 사라져 근육이 돌아오면 함께 회복됩니다. 사각턱 보톡스는 턱뼈를 감싸는 교근에 놓아 근육을 줄임으로써 갸름하게 보이게 하는 시술인데, 근육이 너무 많이 줄면 마치 텐트의 폴대가 가라앉은 것처럼 그 위를 덮고 있던 피부도 함께 아래로 처져 패여 보이게 됩니다.

즉 볼이 실제로 패인 것이 아니라 **근육 높이가 줄면서 피부가 같이 꺼져 보이는 현상**이며, 시간이 지나 보톡스 효과가 사라지면 다시 돌아옵니다. 다만 그동안 퀭해 보여 스트레스가 크기 때문에, **이런 경험이 있었다는 사실을 다음 시술 전에 미리 의료진과 상의**하시는 게 예방에 도움이 됩니다. 사람마다 교근 크기와 피부 두께가 달라 같은 양에도 반응이 다르므로, 본인 경험을 공유해 용량과 위치를 조정하는 게 좋아요.$AAA$, array['사각턱보톡스', '볼패임', '교근보톡스', '보톡스부작용', '보톡스용량조절']::text[], 2025, 'YRaF1DQ4QUA-3', 'https://youtu.be/YRaF1DQ4QUA?t=199s', null, '2025-02-11 00:00:00+00'::timestamptz, '2025-02-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터 치료, 35~40%만 좋아져도 받을 가치가 있나요?$AAQ$, $AAA$여드름 흉터는 굉장히 깊지 않은 한 대부분 치료 전보다 개선되므로, 일부 개선이라도 받아 보시는 것을 권합니다. 흉터는 피부 굴곡이라 메이크업 커버도 잘 안 돼 스트레스가 크지만, 치료 자체가 티가 나고 시간도 걸려 결정이 어렵다는 점은 충분히 이해됩니다.

그래도 권유하는 이유는 **여드름 흉터 치료가 받은 만큼 좋아지는 정직한 치료**이기 때문이에요. 흉터의 모양·깊이, 피부 두께에 따라 레이저 종류와 에너지, 도트필 강도를 시뮬레이션해 사람마다 다르게 진행하기 때문에 시술자에게도 어려운 치료이지만, **잘 받으면 받는 만큼 개선이 보이는 점**이 장점입니다. 또한 치료 초반에는 프락셀 후 붉어짐이나 색소침착으로 일시적으로 더 심해 보일 수 있는데, 시간이 지나면서 살이 차오르며 개선됩니다. 100%는 어렵더라도 시술 전보다 분명히 좋아질 수 있어요.$AAA$, array['여드름흉터치료', '프락셀자국', '흉터레이저효과', '도트필', '흉터회복기간']::text[], 2025, 'YRaF1DQ4QUA-4', 'https://youtu.be/YRaF1DQ4QUA?t=384s', null, '2025-02-11 00:00:00+00'::timestamptz, '2025-02-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거는 몇 번 정도 받아야 하나요?$AAQ$, $AAA$눈썹 문신은 보통 3~5번, 일반 문신은 적어도 8~10번 정도 레이저 시술을 받아야 합니다. 문신 제거 레이저가 벼락 맞는 것 같은 통증이 있어 마취 연고와 주사 마취를 함께 하는 편이고, 시간이 오래 걸려 포기하시는 분도 많습니다.

예전에는 **한 번 시술 후 3~4주 기다렸다가 다시 받아야 했지만**, 최근에는 R0 테크닉으로 하루에 3~4번 연달아 레이저를 쏠 수 있게 되었습니다. 이는 레이저 직후 피부에 생기는 하얀 기포층, 즉 백화현상을 PFD 약물로 단시간에 녹여 다시 레이저가 들어갈 수 있게 해 주기 때문이에요. **예전에는 10번 방문해야 했던 치료를 3~4번 내원으로 단축**할 수 있습니다. 다만 레이저 에너지를 너무 세게 주면 주변 피부도 다치므로 강도를 높이는 게 아니라 같은 강도로 여러 번 쏘는 방식입니다.$AAA$, array['문신제거횟수', '문신제거레이저', 'R0테크닉', 'PFD약물', '백화현상']::text[], 2025, 'HNGSScdAWfw-1', 'https://youtu.be/HNGSScdAWfw?t=47s', null, '2025-02-13 00:00:00+00'::timestamptz, '2025-02-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$디스크라이브 패치와 R0 테크닉은 어떻게 다른가요?$AAQ$, $AAA$디스크라이브 패치와 R0 테크닉은 모두 PFD 약물을 이용하지만, 패치는 약물을 실리콘 안에 가둬 휘발을 막고 더 높은 에너지를 안전하게 쓸 수 있다는 점에서 다릅니다. R0 테크닉에서 쓰는 PFD는 휘발성이 강해 잘 날아가는데, 미국에서는 이를 실리콘 패치 안에 가두어 용액이 날아가지 않도록 만들었어요.

패치 자체가 피부를 보호하는 역할도 하기 때문에, 한 논문에서는 **디스크라이브 패치 사용 시 1.5~1.8배 정도 더 강한 레이저를 사용할 수 있고 그만큼 문신도 더 빨리 지워졌다고** 보고합니다. 사진 비교에서도 패치를 쓴 쪽이 훨씬 많이 지워진 모습이 확인됩니다. R0 테크닉은 액상 PFD를 도포하고 다시 레이저, 도포하고 다시 레이저를 반복하는 방식인 반면, **패치는 한 번 부착으로 휘발 걱정 없이 고에너지를 안전하게 적용**할 수 있다는 차이입니다.$AAA$, array['디스크라이브패치', 'R0테크닉', 'PFD실리콘패치', '문신제거에너지', '휘발성약물']::text[], 2025, 'HNGSScdAWfw-2', 'https://youtu.be/HNGSScdAWfw?t=263s', null, '2025-02-13 00:00:00+00'::timestamptz, '2025-02-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$R0 테크닉과 프랙타트 중 어떤 게 더 좋은가요?$AAQ$, $AAA$R0 테크닉은 회복이 빠르고 자극이 덜한 편이라 눈썹 같은 예민한 부위에, 프랙타트는 색소가 진하거나 피부가 두꺼운 분에게 적합한 시술입니다. R0 테크닉은 **피부색이 밝고 색소량이 적은 흉터 가능성이 낮은 문신**과 민감한 피부에 좋아요.

반면 프랙타트는 프랙셔널 레이저로 피부에 미세한 격자 구멍을 먼저 뚫어 빨대 역할을 만든 뒤 문신 제거 레이저를 쏘는 방식입니다. 한 논문에서는 **프랙셔널 레이저 선행 시 붓기가 3일 더 빨리 아물고 총 시술 횟수도 30% 정도 감소**했다고 보고됩니다. **문신 색소가 정말 진하거나 피부색이 어둡고 여러 번 덮어서 한 문신, 피부가 두꺼운 분들에게 효과적**이지만 시술 후 약간의 회복 기간이 필요해요. 결국 피부 상태, 문신의 깊이와 색상, 원하는 치료 간격을 종합 고려해 전문의와 상담 후 선택하는 게 중요합니다.$AAA$, array['R0테크닉', '프랙타트', '프랙셔널레이저', '문신제거선택', '회복기간비교']::text[], 2025, 'HNGSScdAWfw-3', 'https://youtu.be/HNGSScdAWfw?t=325s', null, '2025-02-13 00:00:00+00'::timestamptz, '2025-02-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 레이저는 어떻게 색소를 없애나요?$AAQ$, $AAA$문신 제거는 레이저로 큰 색소 덩어리를 작은 조각으로 부수면 면역세포가 이를 잡아가는 원리로 진행됩니다. 큰 바위를 그냥 밀어선 안 움직이지만 작게 부수면 운반할 수 있는 것과 같아, **레이저로 문신 색소를 작게 부수면 피를 타고 다니는 면역세포가 잡아서 가져갑니다**.

이 과정에서 색소가 순간적으로 엄청난 열을 받아 펑 터지면서 피부 속에 기포가 생기는데, 이를 백화현상이라고 해요. **이 기포들은 우산처럼 그 아래 문신에 레이저가 더 닿지 못하도록 막는 역할**을 합니다. 기포는 자연적으로 사라지는 데 오래 걸려, 예전에는 한 번 시술 후 3~4주 기다려야 했어요. 다만 강도를 무리하게 높이면 주변 피부도 다치므로, 같은 강도로 여러 번 쏘면서 백화 층을 PFD 같은 약물로 녹여 가며 반복합니다. 색소 입자가 충분히 작아져 면역세포가 청소할 수 있는 크기가 될 때까지 여러 회 필요해요.$AAA$, array['문신제거원리', '백화현상', '면역세포색소제거', 'Q스위치레이저', '색소입자분쇄']::text[], 2025, 'HNGSScdAWfw-4', 'https://youtu.be/HNGSScdAWfw?t=129s', null, '2025-02-13 00:00:00+00'::timestamptz, '2025-02-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨케어 첫 단계에 쓰기 좋은 펩타이드 제품은 무엇인가요?$AAQ$, $AAA$스킨케어 첫 단계에는 6종 펩타이드가 든 코스알엑스 더 6 펩타이드 스킨 부스터 세럼이 적합합니다. 토너와 에센스 사이 정도의 제형이라 세안 후 바로 바르면 적당한 수분감을 주면서 **유분기는 전혀 없어 모든 피부 타입에 부담이 없고**, 특히 지성이나 수분 부족형 지성에게 잘 맞아요.

6종 펩타이드 각각의 기능이 다른데, 콜라겐 생성 명령을 전달하는 펩타이드, 피부를 탱탱하게 만드는 펩타이드, 주름을 펴주는 펩타이드, 피부 재생을 돕는 펩타이드가 포함됩니다. 여기에 **피지를 조절해 모공 케어를 돕는 나이아신아마이드까지 더해져 민감 피부도 안심하고 사용**할 수 있어요. 보습 성분도 풍부해 건조한 피부에도 좋고, 단독으로 끝내기보다 이걸로 첫 단계를 잡고 비타민C 세럼이나 크림으로 마무리하는 방식이 추천됩니다. 한 가지 제품으로 여러 효과를 원할 때 좋아요.$AAA$, array['펩타이드세럼', '코스알엑스', '스킨부스터세럼', '나이아신아마이드', '수분부족지성']::text[], 2025, 'ilsThC5yjmA-1', 'https://youtu.be/ilsThC5yjmA?t=355s', null, '2025-02-18 00:00:00+00'::timestamptz, '2025-02-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀과 비타민C가 같이 든 세럼은 누구에게 맞나요?$AAQ$, $AAA$레티놀과 비타민C가 함께 든 세럼은 칙칙한 피부톤이 신경 쓰이고 미백과 항노화를 동시에 원하는 분에게 적합합니다. 스트라이벡틴 멀티액션 슈퍼C 레티놀 비타민C 세럼은 **레티놀 0.095%가 들어 있어 레티놀 효과를 충분히 볼 수 있는 농도**예요. 비타민C는 순수 비타민C와 안정화 유도체가 함께 들어 있고, 알부틴·나이아신아마이드 등 멜라닌 억제 성분이 더해져 미백 효과를 상승시켜 줍니다.

레티놀이 처음이라 입문용이 필요하다면 **레티놀 농도가 0.015%로 무난한 프리메라 유스래디언스 비타티놀 세럼**이 좋습니다. 보습 성분과 판테놀, 마데카소사이드 같은 진정 성분이 알차게 들어 있어 로션 정도의 촉촉함이 있고, 20대 후반에서 30대의 미백·탄력 관리나 피부가 예민해 강하지 않은 기능성 제품을 원할 때 적합해요. 두 제품 모두 향료에 민감한 분은 주의가 필요합니다.$AAA$, array['레티놀세럼', '비타민C유도체', '스트라이벡틴', '프리메라비타티놀', '레티놀입문']::text[], 2025, 'ilsThC5yjmA-2', 'https://youtu.be/ilsThC5yjmA?t=549s', null, '2025-02-18 00:00:00+00'::timestamptz, '2025-02-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$PHA·AHA 세럼은 어떤 피부에 좋나요?$AAQ$, $AAA$PHA·AHA 산 성분 세럼은 자극 없이 순한 각질 케어와 보습을 동시에 하고 싶은 민감성 피부에 잘 맞습니다. 엑스비앙스 레디언스 세럼은 PHA·AHA 산 성분에서 전통 있는 브랜드의 제품으로, **각질을 잘 정리해 피부결을 매끄럽고 광이 나게 만들어 줍니다**.

각질이 메마르고 들뜨면 지저분하고 건조하게 보이는데, 이 제품은 **각질에 수분을 줘 피부를 약간 플럼핑시키고 필요 없는 각질은 적절히 탈락**시키는 방식으로 정리해요. 그래서 굉장히 부드럽고 매끄럽게 광이 나는 결을 만들어 줍니다. PHA와 AHA의 시너지 효과가 가장 큰 장점이고, 민감성 피부가 아니더라도 각질 케어와 보습을 함께 하고 싶은 분에게 추천돼요. 다만 산 성분 제품을 쓸 때는 자외선 차단제를 꼭 챙겨 주시고, 자극이 느껴지면 사용 빈도를 조절하셔야 합니다.$AAA$, array['PHAAHA세럼', '엑스비앙스레디언스', '각질케어세럼', '민감성피부각질', '산성분스킨케어']::text[], 2025, 'ilsThC5yjmA-3', 'https://youtu.be/ilsThC5yjmA?t=1342s', null, '2025-02-18 00:00:00+00'::timestamptz, '2025-02-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$올인원 화장품 고를 때 무엇을 봐야 하나요?$AAQ$, $AAA$올인원 화장품은 내가 원하는 효과의 핵심 성분이 들어 있는지, 내 피부 타입에 맞는 제형인지 두 가지를 기준으로 골라야 합니다. **하나를 발라도 내 피부에 필요한 핵심 성분이 들어 있는 제품이 우선**이에요. 예를 들어 건성이고 안티에이징이 필요하면 보습 성분과 펩타이드가 든 제품, 지성이고 모공 고민이 있으면 피지 조절·모공 케어 성분이 든 제품이 적합합니다.

그리고 이런 올인원으로 가볍게 접해 본 뒤 미백·항산화에 집중하고 싶다든지, 안티에이징에 더 집중하고 싶다는 방향이 정해지면 **각각 개별 성분이 충분히 잘 포함된 제품을 추가로 사용하시면 원하는 효과를 더 잘 얻을 수 있어요**. 또한 향료에 민감한 분, 레티놀이 처음인 분, 지성이라 끈적임이 부담스러운 분은 제형 후기까지 확인해서 선택하시고, 새 제품 도입 시에는 적어도 한 달 이상 꾸준히 발라 보고 효과를 판단해 주세요.$AAA$, array['올인원화장품', '핵심성분', '피부타입제형', '스킨케어선택법', '기능성화장품']::text[], 2025, 'ilsThC5yjmA-4', 'https://youtu.be/ilsThC5yjmA?t=1742s', null, '2025-02-18 00:00:00+00'::timestamptz, '2025-02-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터인지 단순 자국인지 어떻게 구분하나요?$AAQ$, $AAA$핸드폰 플래시를 얼굴에 수직으로 비춰 보면 진짜 흉터와 단순 자국을 쉽게 구분할 수 있습니다. 거울 앞에서 빛이 얼굴에 **90도 수직으로 떨어지게 비추면 피부결이 적나라하게 드러나는데**, 이때 피부가 움푹 패여 보이면 진짜 여드름 흉터이고, 그냥 색깔만 달라 보이면 자국입니다.

여드름 흉터라고 부르는 것들은 사실 같지 않아요. 붉은 자국은 여드름 자리가 빨갛게 남은 것, 색소침착은 거뭇거뭇한 갈색 자국으로 둘 다 진짜 흉터가 아닌 자국이에요. **반면 패인 흉터나 튀어나온 흉터는 피부결이 매끄럽지 않고 울퉁불퉁해진 진짜 흉터로 치료 접근이 완전히 다릅니다**. 흰 천에 비유하면 자국은 커피 얼룩처럼 세탁으로 지워지지만, 진짜 흉터는 천이 찢어진 것과 같아 기워야 해요. 그래서 구분이 치료 선택의 출발점이 됩니다.$AAA$, array['여드름흉터구분', '핸드폰플래시진단', '패인흉터', '색소침착', '붉은자국']::text[], 2025, 'iZUrjz7HnNs-1', 'https://youtu.be/iZUrjz7HnNs?t=66s', null, '2025-02-20 00:00:00+00'::timestamptz, '2025-02-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 붉은 자국에는 어떤 홈케어가 효과 있나요?$AAQ$, $AAA$여드름 붉은 자국에는 아젤라익산과 트라넥삼산 성분이 효과적입니다. 붉은 자국은 여드름 염증이 심할 때 늘어난 혈관 때문에 생기므로, 염증을 잡고 피부 재생을 돕는 성분이 필요해요. **아젤라익산은 항염 작용과 피부 재생을 촉진**해 일반의약품으로 약국에서 아젤리아 크림으로 살 수 있습니다.

트라넥삼산은 색소침착·기미에 잘 알려진 성분으로 먹는 기미약의 주성분이기도 한데, 여드름 붉은 자국에도 효과가 있다는 논문 보고가 있어요. **트라넥삼산과 나이아신아마이드가 든 코스드바하 TN 세럼은 붉은기와 색소침착을 동시에 개선**할 수 있어 일석이조 제품이에요. 아젤리아 크림은 빛에 민감하므로 저녁 1회, TN 세럼은 아침·저녁 사용이 적합하고 두 제품을 함께 발라도 됩니다. 노스카나겔 같은 흉터 연고는 붉은 자국 개선에 한계가 있어 효과 면에서는 위 두 성분이 우선됩니다.$AAA$, array['아젤라익산', '트라넥삼산', '여드름붉은자국', '아젤리아크림', 'TN세럼']::text[], 2025, 'iZUrjz7HnNs-2', 'https://youtu.be/iZUrjz7HnNs?t=204s', null, '2025-02-20 00:00:00+00'::timestamptz, '2025-02-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$패인 여드름 흉터도 화장품으로 좋아지나요?$AAQ$, $AAA$패인 여드름 흉터는 홈케어로 해결되지 않고 전문 치료가 필요합니다. 패인 흉터는 흰 천이 찢어진 것처럼 **피부 속의 구조가 실제로 망가져 부분이 파괴되어 없어진 상태**이기 때문에, 위에 크림이나 에센스를 아무리 좋은 걸 발라도 채워지지 않아요.

그래서 패인 부위가 보이면 병원에 가서 상담하고 치료를 받는 게 필요합니다. **패인 흉터는 오래될수록 치료가 어려워지고, 생긴 지 얼마 안 된 흉터일수록 치료 반응이 빠르고 효과가 좋아요**. 여드름이 가라앉은 초기에는 패인 흉터가 안 보이다가 시간이 지나며 보이는 부위가 생기기도 하므로, 핸드폰 플래시로 종종 확인해 패인 곳이 있으면 빨리 병원에 가시는 게 좋습니다. 또한 어떤 자국이든 자외선 차단제가 가장 중요해서, 아무리 좋은 제품을 발라도 자외선 차단을 안 하면 색소침착이 다시 생깁니다.$AAA$, array['패인여드름흉터', '흉터전문치료', '흉터골든타임', '자외선차단제', '피부구조파괴']::text[], 2025, 'iZUrjz7HnNs-3', 'https://youtu.be/iZUrjz7HnNs?t=425s', null, '2025-02-20 00:00:00+00'::timestamptz, '2025-02-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$색소침착 자국에 좋은 성분은 무엇인가요?$AAQ$, $AAA$여드름 후 갈색 색소침착에는 순수 비타민C와 트라넥삼산·나이아신아마이드·알파-알부틴 같은 미백 성분이 효과적입니다. 갈색 자국은 여드름 염증 때문에 피부가 멜라닌 색소를 필요 이상으로 많이 만들어 낸 결과이기 때문에 **멜라닌 생성을 억제하는 성분이 핵심**이에요.

넘버즈인 5번 글루타치온C 흔적 앰플에는 **나이아신아마이드 5%, 트라넥삼산 4%, 알파-알부틴**까지 들어 있어 색소침착 자국 케어에 적합합니다. 다만 순수 비타민C 농도가 1% 미만이라 비타민C 효과를 극대화하려면 별도 비타민C 제품과 함께 쓰는 것이 좋아요. 폴라초이스 클리니컬 디스컬러레이션 리페어 세럼은 트라넥삼산·나이아신아마이드 외에 토코페롤과 레티놀 대체 성분인 바쿠치올까지 더해져 색소·재생·보습을 한 번에 다룹니다. 레티놀이나 레티날 제품이 이미 있다면 굳이 추가 구매 없이 꾸준히 발라도 자국 개선에 도움이 됩니다.$AAA$, array['색소침착자국', '트라넥삼산세럼', '알파알부틴', '바쿠치올', '레티노이드자국']::text[], 2025, 'iZUrjz7HnNs-4', 'https://youtu.be/iZUrjz7HnNs?t=337s', null, '2025-02-20 00:00:00+00'::timestamptz, '2025-02-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스 효과는 얼마나 유지되나요?$AAQ$, $AAA$레디어스 효과는 보통 **1년에서 2년 정도** 유지됩니다. 보통 한 달 간격으로 두세 번 시술해 충분한 토대를 마련하면, 그 뒤로는 1년에서 2년에 한 번씩만 시술해도 잘 유지돼요. 히알루론산 필러가 6개월에서 1년, 쥬베룩이 10개월에서 1년, 스컬트라가 약 1년인 데 비해 레디어스는 콜라겐 부스터 시술 중 가장 오래 가는 편입니다.

다만 효과 발현에는 시간이 필요합니다. **하루 운동했다고 근육이 생기지 않듯이 콜라겐을 직접 채우는 시술이 아니라, 천천히 피부가 자라나오며 탄력이 생기는 방식**이에요. 한 번만 받아도 효과는 있지만, 더 확실하고 오래가는 효과를 만들려면 두세 번 시술로 토대를 잡는 게 좋고, 1~2주 정도 지나면 피부가 점점 쫀쫀해지면서 탄력이 차오르는 게 느껴집니다. 사람마다 피부 상태와 노화 정도가 다르므로 횟수가 정해진 건 아니에요.$AAA$, array['레디어스지속기간', '콜라겐부스터', '레디어스시술횟수', '필러유지기간', '쥬베룩스컬트라비교']::text[], 2025, 'V-jTztD01M8-1', 'https://youtu.be/V-jTztD01M8?t=153s', null, '2025-02-21 00:00:00+00'::timestamptz, '2025-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스가 쥬베룩·리쥬란과 어떻게 다른가요?$AAQ$, $AAA$레디어스는 1형 콜라겐만이 아니라 엘라스틴·혈관·프로테오글리칸 등 피부 전 구성 요소를 함께 만들어 낸다는 점에서 쥬베룩·리쥬란과 본질적으로 다릅니다. 필러나 쥬베룩 볼륨은 진피 내 90% 이상을 차지하는 1형 콜라겐을 주로 만들어 볼륨감을 채우는 시술이에요.

반면 **레디어스는 칼슘하이드록시아파타이트 성분이 피부 전반에 깔리며 3형 콜라겐, 프로테오글리칸, 엘라스틴, 혈관까지 만들어 진짜 내 피부처럼 자연스럽게 좋아집니다**. 그래서 미용 시술보다 재생의학에 가깝다는 평가를 받아요. 비교하자면 **리쥬란은 수분 공급, 쥬베룩은 볼륨감을 주는 시술이라면 레디어스는 피부 자체를 개선시키는 운동 같은 시술**입니다. 희석 비율을 달리해 볼륨이 필요하면 묽게, 전반적 개선이 필요하면 더 묽게 스킨부스터처럼 깔아 놓는 등 다양한 모습으로 활용할 수 있다는 점도 차이입니다.$AAA$, array['레디어스쥬베룩차이', '리쥬란수분', '칼슘하이드록시아파타이트', '엘라스틴재생', '재생의학시술']::text[], 2025, 'V-jTztD01M8-2', 'https://youtu.be/V-jTztD01M8?t=338s', null, '2025-02-21 00:00:00+00'::timestamptz, '2025-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스가 팔자주름·마리오네트에도 좋나요?$AAQ$, $AAA$팔자주름과 마리오네트에는 레디어스가 가장 자연스럽게 효과를 내는 부위입니다. 이 부위는 표정과 대화로 계속 움직이고 피부가 얇고 우글거리는 편이라 **볼륨도 필요하지만 탄력이 함께 필요한 위치**예요. 필러로 채우면 움직일 때 어색해지거나 이동될 수 있고, 쥬베룩은 결절 위험 때문에 시술이 꺼려지는 부위였습니다.

레디어스는 **인위적으로 볼륨을 만드는 게 아니라 콜라겐을 자연스럽게 생성해 구겨진 종이가 펴지듯 탄탄해지며 차오르는 느낌**을 주기 때문에 이 부위에 잘 맞습니다. 나이가 들면서 일부는 꺼지고 일부는 패이며 어떤 데는 볼륨이 남아 튀어나오는 울퉁불퉁한 부위라서, 단단히 채우는 필러보다 깔아 주는 방식이 자연스러워요. 다만 볼이나 옆볼처럼 많이 꺼진 부위, 이마처럼 볼륨을 충분히 채워 올려야 하는 위치에는 레디어스보다 필러나 쥬베룩 볼륨이 더 효과적입니다.$AAA$, array['레디어스팔자주름', '마리오네트레디어스', '필러이동', '결절위험부위', '콜라겐자연재생']::text[], 2025, 'V-jTztD01M8-3', 'https://youtu.be/V-jTztD01M8?t=240s', null, '2025-02-21 00:00:00+00'::timestamptz, '2025-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스 칼슘 성분이 얼굴에서 딱딱해지지 않나요?$AAQ$, $AAA$레디어스의 칼슘하이드록시아파타이트는 입자가 매우 작고 수용성이라 얼굴에서 돌처럼 딱딱하게 굳지 않습니다. 들어가는 칼슘 입자는 **머리카락 굵기의 약 1만 분의 1 정도 크기로 매우 작아**, 뼈의 칼슘처럼 덩어리지지 않아요. 과거에 칼슘 필러라는 표현이 쓰였지만, 얼굴에 집어넣는 시술을 통칭해 필러라 부르던 시절의 명칭일 뿐 실제로 필러처럼 채워 넣는 시술이 아닙니다.

시술 방식은 **물에 잔뜩 타서 묽게 희석한 뒤 작은 입자들을 얼굴 전체에 한 방울씩 깔아주는 방식**이에요. 물에 잘 녹는 수용성이라 굳을 일이 없고, 피부 속 청소부 역할의 세포들이 와서 분해해 가며 거름처럼 피부 토양에 생착되면 그 자리에서 피부가 자라 올라오는 느낌의 시술입니다. 효과가 1도 없다고 느끼는 경우는 보통 시간이 필요한 시술의 특성, 시술자의 희석·위치·주입 방법 차이, 또는 볼륨 채움이 더 필요한 상태에 잘못 적용된 경우입니다.$AAA$, array['칼슘하이드록시아파타이트', '레디어스안전성', '레디어스희석', '수용성칼슘입자', '칼슘필러오해']::text[], 2025, 'V-jTztD01M8-4', 'https://youtu.be/V-jTztD01M8?t=854s', null, '2025-02-21 00:00:00+00'::timestamptz, '2025-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$뾰루지는 언제 짜고 언제 두는 게 좋나요?$AAQ$, $AAA$뾰루지는 노랗게 익어 짜면 나올 것 같을 때 짜고, 빨갛고 작기만 한 구진 상태나 깊은 결절 형태는 절대 건드리지 않아야 합니다. 빨갛고 작게 튀어나와 있을 때는 균과 백혈구가 싸우는 단계라 짤만한 게 없는데, **이때 셀프 압출하면 염증이 자극되어 점점 깊어지고 옆으로 번지기까지** 해요. 손이 더러워 바깥 피부에서 감염이 일어나 진물이 나는 일도 흔합니다.

반면 잘 익어 노랗고 하얗게 튀어나올 때는 짜면 됩니다. **피지와 염증 성분을 모두 빼내 흉지지 않고 빨리 회복되도록 돕기 위함**이에요. 한편 짜도 안 나올 것 같고 깊게 단단히 만져지는 결절 형태는 가만히 두면 염증이 커지고 흉터를 남길 가능성이 높아 무조건 병원에 가야 합니다. 또 좁쌀 같은 비염증성 면포 1~2개는 집에서 짜도 되지만 얼굴 전체에 많다면 피부과에서 전체적인 압출 관리를 받아야 합니다.$AAA$, array['뾰루지셀프압출', '결절성여드름', '구진뾰루지', '여드름압출시기', '면포관리']::text[], 2025, 'Fr78THIXUmg-1', 'https://youtu.be/Fr78THIXUmg?t=149s', null, '2025-02-25 00:00:00+00'::timestamptz, '2025-02-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 패치는 언제 붙여야 하나요?$AAQ$, $AAA$여드름 패치는 **셀프 압출을 완벽히 한 뒤에** 붙여야 효과가 있고, 압출 전에 붙이면 오히려 염증을 깊어지게 만들 수 있습니다. 패치 성분인 하이드로콜로이드는 상처 회복에 도움이 되지만, 압출 전 상태에 붙이면 공기가 더 안 통하게 되어 산소를 싫어하고 피지를 좋아하는 여드름균이 더 잘 번식하는 환경이 됩니다.

그래서 **짤만한 게 없는 빨간 구진 형태나 깊은 결절에 패치를 붙이면 염증이 더 깊어질 수 있어요**. 잘 익은 상태에서 깨끗하게 짠 후 붙여야 회복을 돕는 본래 기능을 합니다. 다만 본인이 스스로 통제가 안 돼 뭐가 났을 때 자꾸 만지게 된다면, 차라리 패치를 붙여 손이 닿지 않게 하는 편이 낫기는 합니다. 손은 더러워 건드릴수록 깊어지고 번지기 때문이에요. 결국 패치는 압출 후 마무리 도구이지 압출 전 진정 도구가 아니라는 점을 기억하시면 됩니다.$AAA$, array['여드름패치사용법', '하이드로콜로이드', '셀프압출후관리', '여드름균번식', '패치오용']::text[], 2025, 'Fr78THIXUmg-2', 'https://youtu.be/Fr78THIXUmg?t=257s', null, '2025-02-25 00:00:00+00'::timestamptz, '2025-02-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 자국 빨간 자국은 결혼식 전 어떻게 빨리 없애나요?$AAQ$, $AAA$여드름 빨간 자국이 결혼식이나 중요한 행사 직전이라면 GV 레이저나 브이빔 같은 혈관 레이저가 빠른 방법입니다. 빨간 자국은 미세 혈관이 늘어나 있어 보이는 것이라 **혈관을 타겟하는 레이저가 도움이 되고, 한 번만으로도 충분히 좋아질 수 있어 행사 직전에 권유**됩니다.

노스카나겔 같은 흉터 연고는 솔직히 마음의 위안 정도일 뿐 붉은 자국이 빨리 좋아지지는 않아요. 한편 갈색 자국이나 검은 자국으로 변한 색소침착에는 멜라닝 크림을 저녁에 1회 소량 도포하는 게 도움이 되고, **빨리 없애고 싶다면 레이저 토닝을 1~2주 간격으로 10회 정도 부지런히 받으셔야** 합니다. 원래 염증 이후 색소침착은 6~12개월에 걸쳐 서서히 빠지지만, 옅어질 만하면 새 뾰루지가 나서 흔적이 반복되는 게 문제이므로 새로 생기는 뾰루지를 함께 관리해 주시는 게 핵심입니다.$AAA$, array['빨간자국레이저', '브이빔레이저', '레이저토닝', '여드름색소침착', '결혼식피부케어']::text[], 2025, 'Fr78THIXUmg-3', 'https://youtu.be/Fr78THIXUmg?t=345s', null, '2025-02-25 00:00:00+00'::timestamptz, '2025-02-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 패인 흉터도 정말 치료가 될 수 있나요?$AAQ$, $AAA$여드름 패인 흉터도 꾸준히 잘 치료하면 분명히 좋아질 수 있는 정직한 치료입니다. 흉터 종류는 송곳으로 콕 찍은 듯한 좁고 깊은 흉터, 경계가 흐릿하고 우글우글하게 패인 흉터, 테두리가 명확하게 넓게 패인 흉터 등 모양과 깊이가 다 달라요. 흉터마다 좋아질 수 있는 정도와 치료 기간이 모두 다릅니다.

같은 여드름 흉터라도 **누구는 5번 만에 좋아지고 누구는 10번을 해도** 잘 없어지지 않을 수 있어요. 흉터가 얕으면 금방 차오르지만, 넓고 깊고 양이 많으면 치료 횟수가 훨씬 많이 필요하고 오래 걸립니다. 사람마다 살성이 달라 같은 치료여도 결과가 달라지죠. 흉터 치료는 단거리 경주가 아니라 마라톤 같아서 오늘 받았다고 짠 하고 사라지지 않습니다. 좌절하지 않고 꾸준히 받으면 분명히 좋아질 수 있어요.$AAA$, array['여드름흉터', '패인흉터', '치료가능성', '치료기간', '꾸준한치료']::text[], 2025, 's41FFNFwC6A-1', 'https://youtu.be/s41FFNFwC6A?t=63s', '{"pmid": "40973932", "doi": "10.1007/s10103-025-04647-w", "title": "The most influential research in laser therapy for acne and acne scars: A bibliometric analysis.", "journal": "Lasers Med Sci", "year": "2025", "authors_short": "Abdelwahab SI, Taha MME, Farasani A et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/40973932/", "doi_url": "https://doi.org/10.1007/s10103-025-04647-w"}'::jsonb, '2025-02-27 00:00:00+00'::timestamptz, '2025-02-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$프락셀 레이저와 예전 레이저는 어떻게 다른가요?$AAQ$, $AAA$프락셀 레이저는 바둑판처럼 일정 간격으로 일부 부위에만 레이저를 쏘아 회복이 빠르고 부작용이 적다는 점에서 예전 방식과 본질적으로 다릅니다. 예전에는 흉터 부위 피부를 다 깎아냈기 때문에 진물과 딱지가 생기고 며칠 동안 세수도 못하고 붉은기도 오래 갔어요. 색소침착이 생길 확률도 매우 높았습니다.

반면 프락셀(정식 명칭 프랙셔널 레이저)은 **레이저가 들어간 부위보다 안 들어간 부위가 훨씬 많은 방식**으로, 패인 부위를 차오르게 하기 위해 일부러 미세한 상처를 냅니다. 피부는 상처가 나면 콜라겐을 만들어 다시 채우는 성질이 있어 그 원리를 이용하는 거예요. 그래서 다 깎아냈던 옛 방식보다 **훨씬 회복이 빠르고 부작용이 적기 때문에** 흉터 치료에 프랙셔널 레이저를 씁니다.$AAA$, array['프락셀', '프랙셔널레이저', '여드름흉터', '회복기간', '콜라겐재생']::text[], 2025, 's41FFNFwC6A-2', 'https://youtu.be/s41FFNFwC6A?t=263s', '{"pmid": "41428599", "doi": "10.1111/jocd.70620", "title": "Treating Acne Scars in Fitzpatrick Skin Types I-VI Using a Novel 1550 nm Non-Ablative Resurfacing Laser With Focal Point Technology.", "journal": "J Cosmet Dermatol", "year": "2025", "authors_short": "Wang JV, Pomerantz H, Tran TN et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/41428599/", "doi_url": "https://doi.org/10.1111/jocd.70620"}'::jsonb, '2025-02-27 00:00:00+00'::timestamptz, '2025-02-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터는 언제부터 치료를 시작하는 게 좋나요?$AAQ$, $AAA$여드름 패인 흉터가 보이면 가능한 빨리 치료를 시작하시는 게 좋습니다. 흉터가 오래될수록 치료가 어려워지기 때문이에요. 흉터가 빨갛다는 것은 비교적 최근에 생겼다는 뜻이고, 살색이면 오래된 흉터라는 의미입니다. 언제 생긴 흉터냐에 따라 치료 효과가 많이 달라져요.

예를 들어 붉은기가 있을 때 치료를 시작한 분과 **20년 이상 된 흉터를 가진 분이 같은 레이저로 6개월 치료**해도 효과 차이가 분명히 납니다. 그래서 꼭 아셔야 할 것 세 가지가 있는데, 첫째는 가능한 빨리 치료를 시작하는 것, 둘째는 현재 여드름이 있다면 여드름 치료를 먼저 해 흉터를 예방하는 것, 셋째는 꾸준함입니다. 금방 개선되지 않으니 **피부과 전문의와 충분히 상담**하여 본인에게 맞는 치료 계획을 세우세요.$AAA$, array['여드름흉터', '치료시기', '붉은흉터', '오래된흉터', '치료계획']::text[], 2025, 's41FFNFwC6A-3', 'https://youtu.be/s41FFNFwC6A?t=160s', '{"pmid": "37454285", "doi": "10.1002/lsm.23708", "title": "1927nm fractional thulium fiber laser combined with 30% salicylic acid for the treatment of acne and acne scars: A prospective, randomized, and split-face study.", "journal": "Lasers Surg Med", "year": "2023", "authors_short": "Huang SL, Ye D, Xue H et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/37454285/", "doi_url": "https://doi.org/10.1002/lsm.23708"}'::jsonb, '2025-02-27 00:00:00+00'::timestamptz, '2025-02-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$넓고 깊게 패인 흉터에는 어떤 시술이 효과적인가요?$AAQ$, $AAA$넓고 깊게 패인 흉터에는 히알루론산 필러나 쥬베룩 같은 콜라겐 생성 유도 주사로 밑에서 받쳐주는 흉터 주사가 효과가 좋습니다. 넓은 부위를 레이저로만 채워 올리려면 시간이 오래 걸리고 효과가 부족할 수 있어요. 이럴 때 히알루론산 필러로 밑에서 받쳐주면 효과가 훨씬 좋습니다.

쥬베룩은 피부 속에서 콜라겐 생성을 촉진하는 성분이라 패인 흉터에 살을 채울 때 콜라겐을 더 빨리, 잘, 많이 만들도록 도와줍니다. 좁고 깊은 송곳 자국 같은 흉터는 바늘이 정확히 바닥까지 가기 어려워, **TCA라는 강한 산성 약물을 바르는 도트필**이 훨씬 효과적이에요. 그리고 모든 방법을 써도 잘 안 차오르는 흉터는 **밑에서 피부를 당기는 유착 조직을 끊어주는 서브시전**이 필요할 수 있습니다.$AAA$, array['흉터주사', '쥬베룩', '도트필', '서브시전', '히알루론산필러']::text[], 2025, 's41FFNFwC6A-4', 'https://youtu.be/s41FFNFwC6A?t=337s', '{"pmid": "42054473", "doi": "10.1097/DSS.0000000000005135", "title": "Subcision Versus Subcision With Suction for the Treatment of Atrophic Acne Scars: A Randomized, Split-Face Clinical Trial.", "journal": "Dermatol Surg", "year": "2026", "authors_short": "Diab S, Diab I, Khaddam J", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/42054473/", "doi_url": "https://doi.org/10.1097/DSS.0000000000005135"}'::jsonb, '2025-02-27 00:00:00+00'::timestamptz, '2025-02-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레스틸렌 비탈은 어떤 시술이고 일반 필러와 어떻게 다른가요?$AAQ$, $AAA$레스틸렌 비탈은 순수 히알루론산 성분으로 피부 속에 수분 저장 창고를 만들어주는 스킨부스터 시술입니다. 우리 몸에 원래 있는 히알루론산과 가장 비슷하게 만들어져서 피부가 이물질로 인식하지 않고 자연스럽게 받아들여요. 입자가 엄청 작지만 완전히 분해되지 않게 특수하게 만들어져 피부 안에서 오래 유지됩니다.

필러는 볼륨감을 주려고 **훨씬 더 큰 입자를 집어넣어 볼륨을 만들어주는** 시술인 반면, 레스틸렌 비탈은 입자 자체가 엄청 작아 마치 잉크젯 프린터처럼 정교하게 깔아주는 스킨부스터예요. 그래서 뭉치지 않고 자연스럽게 수분감이 좋아집니다. 볼이 꺼지거나 팔자주름이 깊은 분은 필러를, **피부가 건조하고 칙칙하고 탄력이 떨어지는 분께는 레스틸렌 비탈**을 권해 드립니다.$AAA$, array['레스틸렌비탈', '스킨부스터', '히알루론산', '필러비교', '수분충전']::text[], 2025, 'ptgJ2Rf7Sjw-1', 'https://youtu.be/ptgJ2Rf7Sjw?t=313s', null, '2025-02-28 00:00:00+00'::timestamptz, '2025-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레스틸렌 비탈 효과는 얼마나 가고 몇 번 받아야 하나요?$AAQ$, $AAA$레스틸렌 비탈은 시술 후 1~2주면 효과가 나타나기 시작해서 **3~6개월간 쭉 유지**됩니다. 보통 한 달 간격으로 세 번 정도 시술받으라고 권해 드리고, 그 후에는 3~4개월 간격으로 수분이 필요할 때마다 받으시면 됩니다. 시작부터 효과가 나타나 계속 좋아지면서 유지되는 느낌의 시술이에요.

받는 횟수는 정해진 게 없고 수분감이 얼마나 떨어져 있는지, 나이와 노화 정도에 따라 다릅니다. 수분감이 많이 부족하면 **한 달 간격 3회 시술 후 6개월간 효과 유지**되는 방식으로 안내드리고, 수분감이 조금 부족하거나 노화가 심하지 않은 분은 1~2회만 맞아도 효과가 충분해요. 리쥬란이 즉각 좋아졌다 가라앉는 느낌이고 쥬베룩이 여러 번에 걸쳐 천천히 콜라겐이 차오른다면, 레스틸렌 비탈은 시작부터 쭉 좋아지고 길게 유지되는 시술입니다.$AAA$, array['레스틸렌비탈', '효과지속', '시술횟수', '재시술간격', '수분지속']::text[], 2025, 'ptgJ2Rf7Sjw-2', 'https://youtu.be/ptgJ2Rf7Sjw?t=244s', null, '2025-02-28 00:00:00+00'::timestamptz, '2025-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레스틸렌 비탈 부작용과 다운타임은 어느 정도인가요?$AAQ$, $AAA$레스틸렌 비탈의 가장 흔한 부작용은 시술 후 피부가 살짝 울퉁불퉁해지는 엠보싱이며 거의 하루 만에 사라집니다. 입자가 미세해 한 방울씩 주입하기 때문에 엠보싱이 잘 생기지 않고, 혹시 1~2개가 오래 지속되더라도 히알루론산은 체내에서 자연 분해되는 성분이라 안전해요.

주사를 놓는 시술이라 멍이 들 수 있고 사람에 따라 1~2주 정도 갈 수 있습니다. 다만 **리도카인이라는 마취 성분이 들어있어 시술 통증은 생각보다 크지 않아요**. 엠보싱과 멍만 들지 않으면 1~2일이면 평상시처럼 생활하실 수 있고, 약간의 붓기나 멍 같은 가벼운 부작용은 며칠 있으면 다 괜찮아집니다. 엠보싱이 너무 걱정되시는 분은 **더 묽은 레스틸렌 비탈 라이트라는 제품**을 선택할 수도 있는데, 묽은 만큼 효과 지속은 다소 짧을 수 있어요.$AAA$, array['레스틸렌비탈', '엠보싱', '다운타임', '부작용', '멍']::text[], 2025, 'ptgJ2Rf7Sjw-3', 'https://youtu.be/ptgJ2Rf7Sjw?t=388s', null, '2025-02-28 00:00:00+00'::timestamptz, '2025-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레스틸렌 비탈은 어떤 피부 타입에 잘 맞나요?$AAQ$, $AAA$레스틸렌 비탈은 **건조하고 칙칙하고 잔주름이 많은 분**에게 잘 맞는 시술입니다. 히알루론산이 진피층에서 콜라겐 사이사이를 채워주니까 잔주름이 펴지고 모공이 개선되며 탄력이 생기는 전반적인 개선 효과가 있어요. 얼굴 피부에 수분이 가득 차면 빛이 고르게 반사되어 환하고 밝아 보입니다.

나이대별로는 30대부터 가장 많이 찾아오시고, 40대 이상은 확실한 노화 관리, 50대 이상은 전반적 피부 개선을 위해 받으시는 경우가 많습니다. 본격적인 피부 노화가 시작되는 20대 후반부터 관리 시작에 좋은 나이이고 예방 효과도 좋아요. 비교하자면 **리쥬란은 여드름·홍조 등 염증이 많은 분께**, 쥬베룩은 탄력 저하·모공·잔주름·볼륨감이 필요한 분께 잘 맞습니다. 보톡스·실리프팅, 써마지·울쎄라 같은 리프팅과도 시너지가 좋고 레이저와 병행도 가능합니다.$AAA$, array['레스틸렌비탈', '적응증', '건조피부', '잔주름', '병행시술']::text[], 2025, 'ptgJ2Rf7Sjw-4', 'https://youtu.be/ptgJ2Rf7Sjw?t=216s', null, '2025-02-28 00:00:00+00'::timestamptz, '2025-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사각턱 보톡스는 어떤 얼굴형에 잘 맞고 누가 주의해야 하나요?$AAQ$, $AAA$사각턱 보톡스는 입을 꽉 닫았을 때 옆 부분이 알처럼 튀어나오는 분에게 가장 적합한 시술입니다. 사각턱이라는 게 튀어나온 부분을 줄이는 시술이라 얼굴형에 맞춰 맞는 게 중요해요. 입을 꽉 닫아도 튀어나온 게 없다면 뼈나 살이 원인이라 보톡스 효과를 보기 어렵습니다.

주의해야 할 얼굴형도 있어요. **광대 밑이 푹 패여 있는 땅콩형 얼굴**은 라인을 더 낮게 잡거나 마르신 분은 용량을 줄이는 편입니다. 예전에 사각턱 보톡스 후 볼 패임을 경험한 분도 주의가 필요합니다. **심술보가 발달해 처지기 시작한 분께는 절대 권하지 않아요**. 볼륨이 어느 정도 있어야 심술보가 위로 당겨지는데 볼륨이 없으면 살이 밑으로 처지면서 부위는 튀어나오고 다른 부위는 들어가 보기 싫은 형태가 되기 때문이에요.$AAA$, array['사각턱보톡스', '땅콩형얼굴', '심술보', '얼굴형', '주의사항']::text[], 2025, 'Ot6An6aOL_k-1', 'https://youtu.be/Ot6An6aOL_k?t=62s', null, '2025-03-05 00:00:00+00'::timestamptz, '2025-03-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자갈턱 보톡스 맞고 미소가 비대칭이 되었는데 어떻게 해결하나요?$AAQ$, $AAA$자갈턱 보톡스의 가장 흔한 부작용인 비대칭 미소는 마비되지 않은 반대쪽에 한 포인트만 살짝 보톡스를 놓아 대칭을 맞춰 해결합니다. 비대칭은 아래입술 내림근이 마비되어 한쪽 입술이 내려오지 않아 생기는 현상이에요. 마비된 쪽은 올라가고 다른 쪽은 그대로 내려와 미소가 어긋나 보입니다.

반대쪽도 한 포인트로 살짝 보톡스를 놓으면 그쪽도 마비되어 대칭이 맞춰져요. 입술을 내리는 근육이기 때문에 크게 문제는 없지만 약간 무거운 느낌이 있을 수 있습니다. 보톡스의 장점이자 단점이 **효과도 길어야 4~6개월이고 부작용이 생겨도 길어야 4~6개월**이라는 점이에요. 그래서 결국 시간이 해결해 주지만 하염없이 기다릴 수는 없으니 **대칭을 맞춘 뒤 기다리면 둘 다 기능이 돌아오면서** 자연히 해결됩니다. 주걱턱처럼 턱이 앞으로 나온 분은 자갈턱 보톡스가 효과를 보기 어렵습니다.$AAA$, array['자갈턱보톡스', '비대칭미소', '부작용해결', '아래입술내림근', '보톡스지속']::text[], 2025, 'Ot6An6aOL_k-2', 'https://youtu.be/Ot6An6aOL_k?t=261s', null, '2025-03-05 00:00:00+00'::timestamptz, '2025-03-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$침샘 보톡스 후에 입 마름이 왜 그렇게 심하고 누가 받으면 좋나요?$AAQ$, $AAA$침샘 보톡스 후 입 마름이 심한 이유는 턱밑샘이 침 분비의 70% 이상을 담당하기 때문에 마비되면 거의 100% 입 마름이 옵니다. 귀밑샘만 맞으면 평소 침 분비의 10~15% 정도라 크게 불편하지 않지만, 턱밑샘까지 마비시키면 침이 안 도니 입 냄새도 나는 듯한 느낌이 들 수 있어요.

받기에 적합한지는 침샘이 만져지는지로 확인할 수 있는데, **턱 아래 포도알처럼 딱딱하게 만져지는 것이 턱밑샘**이고 귀 아래 사각턱 뒤쪽에 말랑말랑하게 만져지는 것이 귀밑샘입니다. 침샘이 별로 없는 분에게는 시술을 권하지 않아요. 침샘 보톡스는 양이 더 들어가고 반복 시술이 필요해 내성 걱정이 있을 수 있어 **제오민, 코어톡스 같은 내성이 덜 생기는 제품**을 권해 드립니다. 효과를 보고 있다면 4~6개월 간격으로 쭉 맞으시기를 권해 드려요.$AAA$, array['침샘보톡스', '턱밑샘', '입마름', '내성', '제오민']::text[], 2025, 'Ot6An6aOL_k-3', 'https://youtu.be/Ot6An6aOL_k?t=398s', null, '2025-03-05 00:00:00+00'::timestamptz, '2025-03-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사각턱 보톡스 후 볼이 패였는데 원래대로 돌아오나요?$AAQ$, $AAA$사각턱 보톡스를 처음 맞고 볼이 패였다고 느낀 경우라면 거의 원래대로 돌아옵니다. 다만 반복적으로 맞아서 볼이 패인 경우는 좀 더 생각해 봐야 하는 상황이에요. 30대 이상이고 볼살이 없는 분은 웬만하면 맞지 않는 게 좋습니다.

사각턱 보톡스의 부작용으로 **맞은 부위가 아니라 광대 밑이 볼록 튀어나오는 분**도 있어요. 아래 부위가 마비되어 그렇게 튀어나오는 것인데 이런 경우엔 그 볼록한 부위에 아주 살짝 터치업해 주면 좋습니다. **사각턱과 함께 관자 부위가 울룩불룩 튀어나오는 분**은 사각턱과 더불어 함께 잡아주시는 게 좋아요. 광대 밑이 꺼져 있거나 예전에 사각턱 보톡스 후 볼 패임을 경험한 분이라면 시술 전에 의료진과 충분히 상의하시기를 권해 드립니다.$AAA$, array['볼패임', '사각턱보톡스', '광대밑꺼짐', '터치업', '관자부위']::text[], 2025, 'Ot6An6aOL_k-4', 'https://youtu.be/Ot6An6aOL_k?t=125s', null, '2025-03-05 00:00:00+00'::timestamptz, '2025-03-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅 효과가 금방 떨어진다는 게 사실인가요?$AAQ$, $AAA$티타늄 리프팅 효과가 떨어지는 게 아니라 시술 직후 드라마틱한 효과가 몇 주에 걸쳐 자연스럽게 안정화되는 과정입니다. 받은 직후 피부가 드라마틱하게 끌어올려져 보이는데, 이게 너무 인상적이라 시간이 지나며 효과가 떨어졌다고 느끼시는 분들이 있어요. 사실은 의도된 효과 수준으로 돌아가는 것입니다.

피부 안쪽에서는 **피부 탄력에 도움이 되는 콜라겐, 엘라스틴이 6개월에 걸쳐 만들어지기** 때문에 시간이 지날수록 안에서 단단해지는 변화가 이어집니다. 받기 전과 몇 주 후 얼굴을 비교해 보면 확실히 다릅니다. 효과가 걱정되시면 **티타늄 리프팅 후 연달아서 고주파 시술을 병합**하시면 효과가 훨씬 오래갑니다. 비타란 스킨부스터를 함께 받는 것도 좋은데 다운타임이 거의 없고 피부를 촉촉하게 만들어주는 시너지가 있습니다.$AAA$, array['티타늄리프팅', '효과지속', '콜라겐엘라스틴', '고주파병합', '안정화']::text[], 2025, 'uHH6MW7Ey3w-1', 'https://youtu.be/uHH6MW7Ey3w?t=60s', null, '2025-03-06 00:00:00+00'::timestamptz, '2025-03-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 써마지나 울쎄라와 어떻게 다른가요?$AAQ$, $AAA$티타늄 리프팅은 시술 직후 즉각적인 BTS 효과(브라이트닝·타이트닝·슬리밍)가 나타나고 다운타임이 거의 없다는 점에서 써마지·울쎄라와 본질적으로 다릅니다. 써마지는 피부 탄력에 확실히 좋고 울쎄라는 처진 피부를 올려주거나 볼륨을 감소시키는 효과가 탁월합니다. 어느 하나만 받으라 하기는 어렵고 목적에 따라 선택하시면 됩니다.

티타늄 리프팅은 프로토콜이 두 가지로 디자인되어 있어요. **스택 방식은 한 부위에 집중적으로 에너지를 전달**해 울쎄라와 비슷한 느낌이지만 피부톤 개선에 더 탁월하고 마리오네트 주름·처진 볼·턱선에 효과적입니다. 러빙 방식은 부드럽게 문지르며 에너지를 전달해 써마지와 비슷한데 **즉각적인 슬리밍·라인 개선과 피부톤 개선 효과**가 더 큽니다. 마취 크림만 20분 정도 바르고 시술하며 아플락 말락 할 때쯤 끝납니다.$AAA$, array['티타늄리프팅', '써마지비교', '울쎄라비교', '스택방식', '러빙방식']::text[], 2025, 'uHH6MW7Ey3w-2', 'https://youtu.be/uHH6MW7Ey3w?t=358s', null, '2025-03-06 00:00:00+00'::timestamptz, '2025-03-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 다운타임이나 멍이 정말 없나요?$AAQ$, $AAA$티타늄 리프팅은 다운타임이 전혀 없고 멍도 들지 않습니다. 시술 후 생기는 멍이나 붉은 자국이 사라지는 데 걸리는 시간을 다운타임이라고 하는데, 티타늄 리프팅은 이런 게 없어 시술 다음 날 바로 광고 촬영을 가도 될 정도예요. 채정안 씨가 광고 촬영 전날 받았다는 일화가 대표적입니다.

그래서 **소개팅, 결혼식, 상견례, 파티, 촬영 직전에 많이들 받으십니다**. 마취 크림만 20분 정도 바르고 시술하고, 열이 쌓이면서 약간의 통증이 있을 수 있지만 아플락 말락 할 때 끝납니다. 시술 후 주의할 점이 몇 가지 있는데 **티타늄 리프팅 받기 전에 주사 시술을 받으면 화상을 입을 수 있으니 안 됩니다**. 필러·보톡스·리쥬란 같은 스킨부스터를 같이 하시려면 티타늄 후에 받거나, 주사 시술 후 시간차를 두고 티타늄을 받으시면 됩니다.$AAA$, array['티타늄리프팅', '다운타임', '멍', '시술전주의', '주사병행']::text[], 2025, 'uHH6MW7Ey3w-3', 'https://youtu.be/uHH6MW7Ey3w?t=732s', null, '2025-03-06 00:00:00+00'::timestamptz, '2025-03-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 왜 즉각적으로 예뻐 보이는 효과가 있나요?$AAQ$, $AAA$티타늄 리프팅은 받자마자 얼굴이 화사해지고 피부가 쫀쫀해지며 윤곽이 예뻐지는 BTS 효과를 즉각 만들어내는 시술입니다. BTS는 브라이트닝(밝아짐), 타이트닝(쫀쫀해짐), 슬리밍(슬림해짐)을 합친 표현이에요. 시술 직후 거울을 보여드리면 반쪽만 했어도 차이가 명확히 보입니다.

실제로 환자분께 얼굴 반쪽만 시술 후 거울을 보여드리고 마음에 안 들면 돈 안 내도 된다고 했는데 **다들 반대쪽도 하고 돈 다 내고 가셨어요**. 이렇게 즉각적인 효과가 나타나는 원리를 응용하면 **안면 비대칭 교정도 가능**합니다. 덜 처진 부위는 원래대로 시술하고 더 처지거나 볼륨이 큰 부위는 에너지를 더 많이 쏴드리면 대칭이 됩니다. 시술 후 안쪽에서는 6개월에 걸쳐 콜라겐과 엘라스틴이 만들어지면서 효과가 이어집니다.$AAA$, array['티타늄리프팅', 'BTS효과', '즉각효과', '비대칭교정', '브라이트닝']::text[], 2025, 'uHH6MW7Ey3w-4', 'https://youtu.be/uHH6MW7Ey3w?t=164s', null, '2025-03-06 00:00:00+00'::timestamptz, '2025-03-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살 크림이 정말 효과가 있나요?$AAQ$, $AAA$튼살 크림은 엄밀히 말하면 효과가 명확하지 않습니다. 이미 하얗게 된 튼살에는 효과가 없고, 2012년 튼살 크림 연구를 모은 리뷰 논문에서 세 가지 질문 모두에 대해 효과가 없다고 결론 내렸어요. 첫째 튼살 예방 효과 없음, 둘째 덜 심하게 생기게 하는 효과도 없음, 셋째 유효 성분별로도 효과 없음입니다.

다만 이후로 여러 성분의 튼살 크림 논문이 추가로 나왔고 일부에서는 효과를 보고했기 때문에 100% 효과가 전혀 없다고 단정하긴 어렵습니다. **선물 받은 게 있으면 버리지 말고 열심히 바르고**, 없으면 굳이 비싼 걸 살 필요는 없고 집에 있는 바디크림을 마사지하면서 발라도 된다는 정도로 안내드립니다. 이미 생긴 튼살에 효과를 볼 수 있는 연고는 따로 있는데, **트레티노인 성분의 투앤티 크림(스티바A 단종 후속)**이 붉은 튼살에 효과적이에요.$AAA$, array['튼살크림', '효과논란', '투앤티크림', '트레티노인', '리뷰논문']::text[], 2025, 'Ed-OE2iPysg-1', 'https://youtu.be/Ed-OE2iPysg?t=44s', null, '2025-03-07 00:00:00+00'::timestamptz, '2025-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$투앤티 크림으로 튼살을 어떻게 발라야 하나요?$AAQ$, $AAA$투앤티 크림은 자기 전에 한 번 완두콩 절반 정도 크기를 손등에 덜어 튼살 부위에 얇게 펴 바릅니다. 적어도 3~6개월 정도는 꾸준히 발라야 효과를 볼 수 있어요. 트레티노인 성분이 피부 표피층을 두껍게 만들고 콜라겐을 더 많이 만들어주는 역할을 하기 때문에 붉은 튼살에 효과가 있습니다.

트레티노인은 피부를 자극할 수 있어서 너무 자주 또는 많이 바르면 피부가 빨개지고 자극이 심해질 수 있어요. 원액을 발랐을 때 빨개지고 따갑다면 **본인이 쓰던 보습제 크림과 투앤티 크림을 반반 섞어 바르는 것**도 방법이 됩니다. 가장 중요한 주의 사항은 **임신 중에 트레티노인 성분을 쓰면 안 된다는 점**입니다. 임신 중 튼살을 발견했더라도 출산 전까지는 바르면 안 되고 출산 후에 바르셔야 해요. 생긴 지 얼마 안 된 빨간 튼살에 어느 정도 효과가 있지만 100%는 아닙니다.$AAA$, array['투앤티크림', '사용법', '트레티노인', '임신금기', '보습제혼합']::text[], 2025, 'Ed-OE2iPysg-2', 'https://youtu.be/Ed-OE2iPysg?t=237s', null, '2025-03-07 00:00:00+00'::timestamptz, '2025-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흰 튼살도 레이저 치료로 좋아질 수 있나요?$AAQ$, $AAA$흰 튼살도 미라젯·큐어젯 같은 레이저로 충분히 좋아질 수 있는 시대가 되었습니다. 예전에는 흰 튼살은 치료가 잘 안 된다는 논문이 대부분이었지만, 새 레이저들이 나오면서 효과가 꽤 괜찮은 것이 확인되었어요. 약물을 레이저에 장전해 공기총처럼 압력으로 피부에 쏘는 원리입니다.

압력이 세서 **튼살 부위 피부를 미세하게 찢으면서 약물이 피부 속에 박히는** 방식이에요. 튼살도 일종의 흉터라 패여 있는데, 미세하게 찢어주면 살이 차오르는 반응이 생기면서 다시 채워집니다. 시술 받을 때는 진짜 찢어지는 느낌이 비슷하게 아프지만 **끝나고 나면 또 전혀 안 아프고 화끈거리는 불편함도 없는** 점이 신기합니다. 청소년이나 특정 신체 부위에는 울트라펄스 같은 CO2 프랙셔널 레이저를 쓰기도 합니다. 보통 2~3번 치료하면 효과가 눈에 보이기 시작합니다.$AAA$, array['흰튼살', '미라젯', '큐어젯', '약물전달레이저', '튼살레이저']::text[], 2025, 'Ed-OE2iPysg-3', 'https://youtu.be/Ed-OE2iPysg?t=313s', null, '2025-03-07 00:00:00+00'::timestamptz, '2025-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살 치료는 언제 시작하는 게 가장 효과적인가요?$AAQ$, $AAA$튼살 치료는 생긴 지 얼마 안 돼서 붉을 때 시작하는 것이 효과가 가장 좋습니다. 튼살은 임신이나 사춘기처럼 몸이 갑자기 커지면서 피부 속살이 찢어지고, 처음에는 그 자리가 붉은색으로 보였다가 시간이 지나면 붉은 게 빠지고 하얀 선으로 남는 과정을 거칩니다.

붉은 튼살에는 트레티노인 성분의 **투앤티 크림을 꾸준히 3~6개월 발라보는 방법**도 있어요. 하얗게 변한 오래된 튼살도 레이저로 치료할 수는 있지만 더 많은 시간과 노력이 필요할 수 있습니다. 튼살이 흔하고 꼭 치료할 필요는 없지만 잘 보이는 부위에 생기거나 심하게 생긴 경우 없애고 싶어 하시는 분이 많습니다. **치료해도 100% 흔적 없이 사라지진 않지만**, 멀리서 보일 정도의 하얀 줄이 치료 후 가까이서 자세히 봐야 보이는 정도로 충분히 개선될 수 있어요.$AAA$, array['튼살치료시기', '붉은튼살', '흰튼살', '치료한계', '조기치료']::text[], 2025, 'Ed-OE2iPysg-4', 'https://youtu.be/Ed-OE2iPysg?t=445s', null, '2025-03-07 00:00:00+00'::timestamptz, '2025-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이마와 미간 보톡스는 한꺼번에 맞아도 되나요?$AAQ$, $AAA$이마·미간·눈가·팔자 보톡스는 한꺼번에 맞으셔도 됩니다. 내성 측면에서는 조금씩 자주 맞는 게 오히려 좋지 않은데, 노출이 그만큼 더 많이 되기 때문이에요. 입가·미간·눈가·팔자까지 맞아도 용량이 많이 들어가는 게 아닙니다. 다만 일반적으로 팔자주름에는 보톡스를 놓지 않습니다.

예외도 있는데, 환자가 연세가 있으시고 **눈을 뜨는데 이마 근육을 많이 쓰는 경우**에는 이마와 미간을 따로 시술합니다. 미간과 이마에 동시에 시술하면 눈 뜰 때 너무 불편하실 수 있기 때문이에요. 그런 경우 **한 군데 먼저 하고 마비가 적응되고 나면 그다음에 추가 시술**을 진행하는 편입니다. 결국 본인 근육 사용 패턴에 따라 동시 시술과 분할 시술이 달라지므로 상담을 통해 결정하시는 게 좋습니다.$AAA$, array['이마보톡스', '미간보톡스', '동시시술', '내성', '팔자주름']::text[], 2025, '60HHaLCPg68-1', 'https://youtu.be/60HHaLCPg68?t=49s', null, '2025-03-11 00:00:00+00'::timestamptz, '2025-03-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이마 보톡스 후 눈썹 위 주름이 더 심해지는 이유가 뭔가요?$AAQ$, $AAA$이마 보톡스 후 눈썹 위 주름이 더 심해지는 것은 한쪽 근육이 마비되면 연결된 다른 쪽이 보상성으로 더 과하게 수축하는 현상 때문입니다. 얼굴 근육은 서로 연결되어 있어 풍선의 한쪽을 쥐면 다른 쪽이 부풀어 오르듯 마비되지 않은 부위가 더 도드라져 보일 수 있어요. 미간이 더 강조되는 경우도 같은 원리입니다.

그래서 이마 시술 전 표정을 짓게 해 보고 **눈썹 바로 위에 주름이 생기는 분께는 교정이 쉽지 않다고 미리 말씀**드립니다. 눈썹 바로 위에 보톡스를 놓으면 눈썹이 아래로 내려오기 때문에 **눈썹으로부터 2cm 위부터 시술하라고 가이드라인**이 되어 있어요. 또는 그 부위에 아주 약하게 스킨보톡스를 놓는 경우도 있어 충분한 상담이 필요합니다. 또 눈을 뜰 때 이마를 쓰는 분은 같이 쓰는 근육을 마비시키면 당연히 힘들어, 약하게 놓고 EMS 장비로 부작용을 빨리 풀어드리기도 합니다.$AAA$, array['이마보톡스', '눈썹위주름', '보상성수축', '가이드라인', 'EMS장비']::text[], 2025, '60HHaLCPg68-2', 'https://youtu.be/60HHaLCPg68?t=115s', null, '2025-03-11 00:00:00+00'::timestamptz, '2025-03-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$라인보톡스는 어떤 시술이고 효과는 얼마나 가나요?$AAQ$, $AAA$라인보톡스는 넓은 목근을 타깃으로 턱 라인을 잡아주는 보톡스 시술이며 지속기간은 **보통 1~2달, 최대 4달 정도**입니다. 넓은 목근은 목에서 시작해 아래턱에 붙는 근육으로, 수축하면 턱 라인이 내려와 뭉개져 보입니다. 이 근육을 마비시켜 라인을 살리는 시술이에요.

시술은 턱 라인을 따라 **1~2줄에서 3줄 정도 주사**하며 일반적으로 스킨보톡스 형태로 농도를 묽게 해서 놓습니다. 일반 보톡스보다 지속기간이 짧은 편이지만 라인 잡아주는 효과는 굉장히 좋습니다. 그래서 **다른 리프팅 시술 받을 때 조합하는 경우도 많고** 권해 드리는 시술입니다. 보톡스는 하면 할수록 어떻게 보면 쉽지만 어렵기도 한 시술이라, 부작용을 줄이는 방향으로 시술하고 부작용이 생기면 빨리 해결해 드리는 게 핵심입니다.$AAA$, array['라인보톡스', '넓은목근', '턱라인', '지속기간', '스킨보톡스']::text[], 2025, '60HHaLCPg68-3', 'https://youtu.be/60HHaLCPg68?t=211s', null, '2025-03-11 00:00:00+00'::timestamptz, '2025-03-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$붉고 아픈 염증성 여드름엔 어떤 약국 연고를 발라야 하나요?$AAQ$, $AAA$막 올라오는 붉고 만지면 아픈 염증성 여드름에는 애크논을 발라주시면 됩니다. 아프다는 건 안에 염증이 생겼다는 뜻이라 빨리 관리해줄수록 빨리 없어져요. 두통이나 근육통에 진통소염제를 먹듯, 애크논에는 염증을 가라앉히는 진통소염제 성분이 있어 직접 발라주면 효과가 좋습니다.

바르는 방법은 **애크논을 짜서 여드름 부위에 얹은 다음 듀오덤 같은 걸 붙여 밀봉**하면 다음 날 염증이 많이 가라앉아 있을 거예요. 자국이 붉게 남았다면 노스카나겔을 자국이 없어질 때까지 계속 발라주시면 됩니다. 큰 염증이 가라앉은 후 무르익은 농이 올라오면 면봉으로 살살 짜주고, **짠 자리는 2차 감염 예방을 위해 에스로반을 발라주는 것**이 좋아요. 색소 침착이 남은 좁쌀 여드름에는 멜라닌 생성을 억제하는 아젤라익산 성분의 아젤리아 크림이 효과적입니다.$AAA$, array['애크논', '염증여드름', '듀오덤', '에스로반', '노스카나겔']::text[], 2025, 'fskQJJWST5s-1', 'https://youtu.be/fskQJJWST5s?t=46s', null, '2025-03-13 00:00:00+00'::timestamptz, '2025-03-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블랙헤드와 화이트헤드는 어떻게 다르고 어떻게 관리하나요?$AAQ$, $AAA$블랙헤드와 화이트헤드는 모공이 열려 있는지 막혀 있는지의 차이가 본질적인 차이입니다. 블랙헤드는 모공이 열린 상태에서 피지와 각질 덩어리가 공기와 만나 산화되어 검게 변한 여드름이고, 코·볼에 거뭇거뭇하게 올라오는 형태예요. 화이트헤드는 같은 피지·각질 알갱이가 모공이 막힌 상태로 피부 안에 갇혀 있는 것입니다.

블랙헤드는 다행히 염증을 동반하는 경우가 드물어 **피지·각질을 녹여주는 살리실산이 들어 있는 클리어틴을 톡톡 발라주시면** 됩니다. 화이트헤드도 일단 클리어틴을 발라보고 시간이 지나도 안 없어지면 **살짝 구멍을 내서 짜야 사라지는데**, 피지가 안에 갇혀 있어 약만으로 제대로 안 사라질 수 있어요. 확실히 제거하고 싶다면 피부과에서 압출을 받거나 피지를 감소시키는 아그네스 같은 레이저 시술을 권해 드립니다.$AAA$, array['블랙헤드', '화이트헤드', '클리어틴', '살리실산', '압출']::text[], 2025, 'fskQJJWST5s-2', 'https://youtu.be/fskQJJWST5s?t=131s', null, '2025-03-13 00:00:00+00'::timestamptz, '2025-03-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$색소 침착을 남기는 좁쌀 여드름엔 무엇을 발라야 하나요?$AAQ$, $AAA$색소 침착을 남기는 좁쌀 여드름엔 아젤라익산 성분이 들어 있는 아젤리아 크림을 발라주시면 됩니다. 어둡고 거뭇한 자국은 염증 반응으로 멜라닌 색소가 많이 만들어졌다는 뜻인데, **아젤라익산이 멜라닌 생성을 억제해 색소 침착 개선에 효과가 좋아요**. 이런 자국은 흉터가 아니라 여드름이 지나간 자국이라 시간은 걸려도 웬만하면 좋아질 수 있습니다.

아젤리아 크림은 **자연 유래 성분이라 임산부와 수유부도 사용**할 수 있다는 장점이 있어요. 보습제와 함께 쓸 때 피부가 따가울 수 있으니, 초반에는 여드름 있는 부위에만 콕콕 발라주시고 따갑지 않으면 전반적으로 깔아 주셔도 됩니다. 다만 따가운 정도가 다음 날까지 이어지고 붉고 염증이 심해지면 사용을 중단하셔야 해요. 보습제로는 끈적이지 않고 산뜻한 아토베리어 AI크림 MD를 권해 드립니다.$AAA$, array['아젤리아크림', '아젤라익산', '색소침착', '임산부', '보습제병행']::text[], 2025, 'fskQJJWST5s-3', 'https://youtu.be/fskQJJWST5s?t=259s', null, '2025-03-13 00:00:00+00'::timestamptz, '2025-03-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$약국 연고로 안 되는 여드름은 어떤 경우인가요?$AAQ$, $AAA$움푹 패인 흉터, 켈로이드 흉터, 깊은 화농성 여드름은 약국 연고로 개선이 안 되어 피부과 치료가 필요합니다. 패여 버린 흉터는 바르는 것으로 절대 되지 않아요. 패인 흉터, 울긋불긋한 자국, 거무튀튀한 색소 침착 중 **울퉁불퉁하게 패인 것만이 진짜 흉터**이고 나머지는 자국이라 약국 연고가 도움이 됩니다.

얼굴에 불난 것처럼 빨갛고 아프고 넓게 올라오는 **깊은 화농성 여드름은 무조건 약물 복용과 피부과 치료**가 필요합니다. 안 그러면 더 심해지고 패인 흉터를 영구적으로 남길 수 있어요. 약국 연고는 피부 깊숙한 곳까지 스며들지 못해 효과가 떨어지기 때문입니다. 켈로이드처럼 볼록 튀어나온 흉터는 **피부 구조 자체가 변형된 상태라 뭘 발라도 소용없습니다**. 약국 여드름 연고를 열심히 발랐는데도 안 들어가는 경우에도 병원에서 치료를 받으시는 게 좋습니다.$AAA$, array['패인흉터', '화농성여드름', '켈로이드', '약국연고한계', '피부과치료']::text[], 2025, 'fskQJJWST5s-4', 'https://youtu.be/fskQJJWST5s?t=597s', null, '2025-03-13 00:00:00+00'::timestamptz, '2025-03-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 붉은기에 좋은 레이저는 어떤 게 있나요?$AAQ$, $AAA$여드름 붉은기에 좋은 레이저로는 브이빔을 권해 드립니다. 부작용이 크게 없고 효과도 굉장히 좋은 시술이에요. 같은 위치에 염증이 반복되는 경우는 안쪽 피지가 다 빠져나오지 못해 재발하는 가능성이 있어 그 부위만 **피지선 파괴 시술**을 받아보는 것이 도움이 됩니다.

여름철 피지 분비가 갑자기 늘어 여드름이 많이 나는 분께는 **스킨보톡스를 강력 추천**합니다. 가성비가 좋고 잔주름과 탄력까지 잡아주는 시술이에요. 특정 부위에만 반복적으로 큰 염증성 여드름이 생긴다면 그 부분만 아그네스를 받는 것도 도움이 되는데, 아그네스가 피지선을 파괴해 주기 때문이에요. 다만 **시술 한 번으로는 모든 피지선을 제거하기 어려워 최소 3회 이상**의 시술을 권해 드립니다. 노스카나겔은 흉터에 도움이 되지만 몇 개월 꾸준히 발라야 효과가 나타나고, 파인 흉터나 튀어나온 흉터는 피부과 치료가 따로 필요합니다.$AAA$, array['브이빔', '여드름붉은기', '아그네스', '스킨보톡스', '피지선파괴']::text[], 2025, 'fskQJJWST5s-5', 'https://youtu.be/fskQJJWST5s?t=441s', null, '2025-03-13 00:00:00+00'::timestamptz, '2025-03-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스마트폰이 피부 트러블을 일으킬 수 있나요?$AAQ$, $AAA$스마트폰은 변기보다 약 10배 많은 세균이 검출될 정도로 오염도가 높아 피부 트러블의 원인이 될 수 있습니다. 미국 애리조나 대학교 연구에서 휴대폰의 세균량이 변기보다 10배 많았다고 보고됐고, 또 다른 연구에서는 휴대폰 오염의 17%가 분변에 오염되어 있다는 결과도 있어요.

스마트폰에서는 대장균, 황색포도상구균 등 다양한 세균이 검출되는데, 통화할 때 오염된 액정이 얼굴에 닿으면 여드름과 모낭염 같은 문제가 생길 수 있습니다. 기초 제품이나 메이크업 전에 손을 깨끗이 씻어도 카톡 답장 때문에 손이 다시 오염되면 의미가 없어요. 위생 관리는 다이소에서 파는 천 원짜리 알콜 스왑이나 소독용 알콜을 묻힌 솜으로 자주 닦아주시고, **통화 시에는 이어폰이나 스피커폰을 사용해서 액정이 얼굴에 닿지 않도록 하는 것이** 도움이 됩니다.$AAA$, array['스마트폰위생', '세균오염', '여드름', '모낭염', '피부트러블']::text[], 2025, 'MsNRy2pW8AQ-1', 'https://youtu.be/MsNRy2pW8AQ?t=86s', null, '2025-03-14 00:00:00+00'::timestamptz, '2025-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$올바른 세안법은 어떻게 하나요?$AAQ$, $AAA$세안의 핵심은 손부터 깨끗이 씻고 거품을 충분히 낸 뒤 살살 문지르는 것입니다. 과도하게 세안을 하면 화장품 찌꺼기뿐만 아니라 피부를 보호하는 보호 장벽까지 씻어내 오히려 문제가 생길 수 있어요. 마른 손에 클렌징폼을 짠 뒤 한두 번 비비고 바로 얼굴로 가져가시는 분들이 많은데, 이렇게 하시면 안 됩니다.

손을 깨끗이 씻고 손에서 충분히 거품을 낸 뒤 그 거품으로 얼굴을 살살 문지른다는 생각으로 세안해 주세요. 세안 시간이 너무 길어도 좋지 않습니다. 모공을 조이려고 찬물로 마무리하는 것도 좋지 않으며, **미온수로 온도 자극 없도록 하고 마무리도 수건으로 가볍게 톡톡 두드려** 주세요. 빡빡 문지르거나 클렌징 디바이스로 과도하게 자극을 주면 보호 장벽이 약해질 수 있으니 부드러운 손길이 가장 중요합니다.$AAA$, array['세안법', '클렌징', '피부장벽', '미온수세안', '보습관리']::text[], 2025, 'MsNRy2pW8AQ-2', 'https://youtu.be/MsNRy2pW8AQ?t=247s', null, '2025-03-14 00:00:00+00'::timestamptz, '2025-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$샤워할 때 얼굴에 물을 바로 맞아도 되나요?$AAQ$, $AAA$샤워기 물을 얼굴로 바로 맞는 것은 피부에 좋지 않으므로 피하는 것이 좋습니다. 몸 피부보다 얇고 예민한 얼굴 피부는 샤워기에서 뿜어져 나오는 수압에 쉽게 자극을 받고 손상되거든요. 물의 수압으로 피부 장벽이 손상되면 피부가 거칠어지면서 건조해지는 증상이 나타날 수 있습니다.

특히 쌀쌀한 날씨에 뜨거운 물을 얼굴로 맞으면 수압 자극에 온도 자극까지 더해지면서 자극이 누적됩니다. 이런 자극을 반복하면 **모공도 늘어지고 모세혈관이 확장되서 홍조가 생길 위험도 높아질 수 있어요**. 그래서 몸 샤워도 너무 뜨거운 물로 오래 하는 것은 피하시고, 세안하실 때에는 물을 받아서 해주셔야 합니다. 얼굴이 건조하거나 모공 탄력이 고민이신 분들은 뜨거운 물 샤워와 얼굴 직접 분사를 함께 금지하시는 것이 좋습니다.$AAA$, array['샤워습관', '수압자극', '모공늘어짐', '홍조예방', '얼굴세안']::text[], 2025, 'MsNRy2pW8AQ-3', 'https://youtu.be/MsNRy2pW8AQ?t=339s', null, '2025-03-14 00:00:00+00'::timestamptz, '2025-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$어떤 수면 습관이 주름을 만드나요?$AAQ$, $AAA$엎드리거나 옆으로 자는 습관은 베개에 피부가 장시간 눌려 주름의 원인이 됩니다. 잠을 자는 동안 베개에 피부가 지속적으로 눌리면 그 자국이 반복되면서 주름이 깊어질 수 있어요. 그래서 웬만하면 똑바로 누워서 자는 습관을 들이는 것이 좋습니다.

베개 청결도 큰 영향을 줍니다. 서울대 생명과학부 연구팀 조사에서 **베개에서 변기보다 96배나 많은 세균이 검출되었다고** 해요. 베개 커버에는 머리카락 먼지, 자면서 흘리는 땀과 침, 피지와 각질 등이 쌓이면서 세균이 번식하기 쉬운 환경이 됩니다. 그런 베개에 얼굴을 대고 자면 당연히 트러블의 원인이 될 수 있죠. 이를 예방하려면 **베개 커버를 일주일에 한두 번 정도는 세탁해주시는 게 좋고**, 귀찮으면 매일 세탁한 수건을 베개 위에 깔고 주무시는 것도 좋습니다.$AAA$, array['수면자세', '주름예방', '베개세균', '수면주름', '베개커버세탁']::text[], 2025, 'MsNRy2pW8AQ-4', 'https://youtu.be/MsNRy2pW8AQ?t=540s', null, '2025-03-14 00:00:00+00'::timestamptz, '2025-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴을 만지는 습관이 주름을 만드나요?$AAQ$, $AAA$손으로 얼굴을 자주 만지는 습관은 주름과 트러블을 동시에 유발합니다. 눈을 비빈다든가 턱을 괜다든가 하는 동작을 수년간 반복하면 그 부위에 주름이 생길 수 있어요. 특히 눈가는 피부가 아주 얇아서 자주 비비면 진짜 주름이 잘 생기는 부위입니다.

얼굴이 건조하거나 피부 컨디션이 안 좋을 때 이런 습관을 계속 반복하면 상태가 더 악화됩니다. 게다가 손에는 세균이 많기 때문에 **세안할 때, 화장할 때 말고는 손으로 얼굴을 아예 만지지 말아야 해요**. 마른 세수나 화면을 오래 본 뒤 눈을 비비는 행동도 모두 주름과 트러블을 동시에 키우는 원인이에요. 손과 얼굴은 붙으려야 붙을 수 없는 사이라고 생각하고, 의식적으로 손을 얼굴에서 떨어뜨리는 습관을 들이시는 게 좋습니다.$AAA$, array['얼굴만지기', '눈비비기', '주름원인', '손세균', '생활습관']::text[], 2025, 'MsNRy2pW8AQ-5', 'https://youtu.be/MsNRy2pW8AQ?t=492s', null, '2025-03-14 00:00:00+00'::timestamptz, '2025-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라, 써마지로도 안되는 처짐이 있나요?$AAQ$, $AAA$울쎄라와 써마지로는 얼굴 근육의 노화를 개선할 수 없습니다. 근육도 노화가 되는데, 이게 얼굴 처짐과 밀접한 연관이 있어요. 큰광대근에 힘이 떨어지면 입꼬리를 못 올려서 처지고, 이마 근육의 힘이 떨어지면 눈꺼풀이 덮이는 식으로 진행됩니다.

얼굴 근육들은 서로 밀접하게 연결되어 있어 한 쪽 근육이 약해지면 보상성으로 다른 쪽에 힘이 더 들어가게 돼요. 예를 들어 이마 근육의 힘이 빠지면 보상성으로 눈썹 주름근과 눈둘레근의 힘이 세지면서 **미간 주름이나 눈 주변 주름이** 두드러지게 생깁니다. 젊었을 때는 이런 움직임이 조화롭게 유지되지만 나이가 들면 한쪽 기능이 확 떨어지고 다른 쪽 기능이 확 올라가면서 **조화가 깨지는 거고 주름들이 많이 보이게 되는 거죠**. 그래서 얼굴 근육 운동이나 근육 자극 시술이 필요합니다.$AAA$, array['얼굴근육', '리프팅한계', '보상성근육', '근육노화', '주름원인']::text[], 2025, 'pgAA5ySxd68-1', 'https://youtu.be/pgAA5ySxd68?t=24s', null, '2025-03-19 00:00:00+00'::timestamptz, '2025-03-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$파오 같은 얼굴 운동 기구는 얼마나 자주 써야 하나요?$AAQ$, $AAA$파오 같은 얼굴 운동 기구는 하루 2번 30초씩, 8주간 사용한 논문 결과가 있습니다. 정확히는 **하루에 2번, 30초씩, 8주간 최소 일주일에 6일 이상 사용**했더니 광대근과 턱 밑 두힘살근이 두꺼워졌다고 합니다. 그래서 팔자주름과 턱 라인 개선 효과를 기대할 수 있어요.

사용할 때는 정확한 자세가 중요한데, 치아가 아닌 입술로 기구를 고정한 뒤 고개를 위아래로 리듬감 있게 움직이며 기구를 흔들어주세요. 운동 전에는 고개를 가볍게 스트레칭해 근육을 풀어주고, 귀·어깨·골반이 일직선이 되도록 자세에 신경 써야 합니다. 입을 다무는 힘이 떨어지면 얼굴이 처진다는 논문도 있어, **입을 다물고 고개를 위아래로 움직이면 광대와 턱 밑에 힘이 들어가** 정돈에 도움이 됩니다. 다만 꾸준한 실천이 어려운 경우도 많아요.$AAA$, array['파오', '얼굴운동', '팔자주름', '광대근', '턱라인']::text[], 2025, 'pgAA5ySxd68-2', 'https://youtu.be/pgAA5ySxd68?t=200s', null, '2025-03-19 00:00:00+00'::timestamptz, '2025-03-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$근육 노화 부위에 보톡스를 맞아도 되나요?$AAQ$, $AAA$힘이 약해진 부위에 보톡스를 맞는 것이 아니라, 보상성으로 힘이 세진 부위에 맞아야 합니다. 얼굴 근육들이 서로 연결되어 있어 한쪽이 약해지면 다른 쪽이 강해지는데, 약해진 쪽이 아니라 **보상성으로 세진 쪽 근육에 보톡스를 놔야** 주름이 펴집니다.

예를 들어 이마 근육의 힘이 빠지면 눈썹 주름근과 눈둘레근이 보상성으로 세져 미간 주름과 눈가 주름이 두드러지는데, 이때 보톡스는 약해진 이마가 아니라 세진 부위에 들어가야 효과가 나는 거예요. 의자에 앉아 있다가 의자를 빼면 허벅지에 힘이 빡 들어가는 것처럼, 평소엔 안 쓰던 근육이 갑자기 강해지는 원리와 같습니다. 그래서 얼굴 근육의 균형을 보고 어디에 힘이 빠지고 어디에 힘이 들어가 있는지 파악해야 **이게 되게 심해지는 거죠 그래서 조화가 깨지는** 상태를 바로잡을 수 있습니다.$AAA$, array['보톡스부위', '보상성근육', '미간주름', '눈가주름', '근육조화']::text[], 2025, 'pgAA5ySxd68-3', 'https://youtu.be/pgAA5ySxd68?t=82s', null, '2025-03-19 00:00:00+00'::timestamptz, '2025-03-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$엠페이스와 조비나 리프팅은 어떻게 다른가요?$AAQ$, $AAA$엠페이스는 한 부위를 집중 자극하고, 조비나는 얼굴 구석구석을 골고루 자극하는 EMS 시술입니다. 둘 다 EMS를 이용해 근육이 수축되면서 운동이 되도록 도와줍니다. 엠페이스는 이마와 양 볼에 부착해 시술하는데, **20분 동안 그 부분이 계속 집중적으로 운동되는** 방식이에요.

엠페이스는 추가로 그 부분에 계속 열을 주기 때문에 근육뿐 아니라 피부도 좋아지고, 콜라겐과 엘라스틴 생성도 도와요. 반면 조비나는 문질문질하면서 근육을 운동시키는 방식이라 얼굴 구석구석 골고루 자극할 수 있는 장점이 있습니다. 시술 횟수는 **일단 일주일 간격으로 5번 정도** 받는 것을 권하고, 이후엔 근육이 그 상태를 기억하기 때문에 자전거 타기처럼 몇 달 지나고 생각날 때마다 추가로 받으면 효과가 유지됩니다.$AAA$, array['엠페이스', '조비나', 'EMS리프팅', '근육수축시술', '콜라겐엘라스틴']::text[], 2025, 'pgAA5ySxd68-4', 'https://youtu.be/pgAA5ySxd68?t=300s', null, '2025-03-19 00:00:00+00'::timestamptz, '2025-03-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티날과 레티놀은 어떻게 다른가요?$AAQ$, $AAA$레티날은 레티놀보다 약 10배 강력한 효과를 내는 레티노이드 성분입니다. 레티노이드 계열은 결국 모두 레티노익산으로 바뀌어야 효과가 나오는데, 레티놀이 씨앗을 뿌린 단계라면 **레티날은 꽃이 핀 단계**예요. 그래서 한 단계만 변환되면 바로 효과를 볼 수 있어요.

사과나무에 비유하면 레티놀은 씨앗을 뿌리고 꽃이 피고 열매가 맺히는 나머지 단계를 거쳐야 효과를 보는 거고, 레티날은 꽃이 핀 거니까 한 단계만 더 변환되면 됩니다. 그래서 똑같은 농도로 똑같이 바른다면 **레티날이 훨씬 빠르게 더 강하게 작용할 수 있다는** 의미예요. 가장 강력한 첫째는 스티바A 크림의 주성분인 레티노익산인데 이건 의사 처방이 필요한 전문의약품이고, 레티날은 그보다 부작용이 덜한 둘째 단계라 일반인이 화장품으로 쓰기에 적합합니다.$AAA$, array['레티날', '레티놀', '레티노이드', '안티에이징', '성분비교']::text[], 2025, 'MrvJDn2FTxY-1', 'https://youtu.be/MrvJDn2FTxY?t=304s', null, '2025-03-20 00:00:00+00'::timestamptz, '2025-03-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티날 처음 쓸 때 농도는 어떻게 골라야 하나요?$AAQ$, $AAA$레티날을 처음 쓰시는 분이나 예민한 피부는 낮은 농도부터 시작해 점차 올리는 것이 안전합니다. 레티날은 무조건 높은 농도를 쓴다고 좋은 게 아니에요. **우리 피부가 적응할 수 있도록 천천히 강도를 높이는 게** 핵심입니다.

예를 들어 더마팩토리 레티날 크림은 0.03%와 0.1% 두 라인이 있는데, 처음에는 0.03% 제품을 먼저 써보고 적응된 다음에 0.1% 제품으로 넘어가는 것을 권해 드려요. 닥터디퍼런트 비타리프트 시리즈는 농도가 더 다양해서 0.025%, 0.05%, 0.1%, 0.12%, 0.15%, 0.2% **6가지 농도로 입문자부터 고수까지 단계적으로** 레벨업하며 이어 쓸 수 있어요. 디오디너리 0.2% 에멀전은 상급자용으로 강도가 강해 초보자에게는 권하지 않습니다. 자극이 있을 때는 일주일에 1~2번으로 시작해 피부가 적응할 시간을 주세요.$AAA$, array['레티날농도', '입문자가이드', '단계적사용', '피부적응', '제품선택']::text[], 2025, 'MrvJDn2FTxY-2', 'https://youtu.be/MrvJDn2FTxY?t=158s', null, '2025-03-20 00:00:00+00'::timestamptz, '2025-03-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티날은 왜 안정화 기술이 들어간 제품을 골라야 하나요?$AAQ$, $AAA$레티날이 굉장히 불안정하고 예민한 성분이라서 빛이나 공기에 닿으면 금방 변질되기 때문입니다. 변질되면 효과가 확 떨어지기 때문에 아무 제품이나 쓰면 제대로 된 효과를 못 볼 수 있어요. 그래서 **빛과 공기로부터 안정적으로 보호해주는 기술**이 적용된 제품을 골라야 합니다.

예를 들어 더마팩토리 제품과 닥터디퍼런트 비타리프트 시리즈는 레티날을 안정적으로 보호하는 리포좀 기술이 적용되어 있어요. 디오디너리 0.2% 에멀전과 닥터디퍼런트 시리즈는 추가로 **내용물이 공기에 닿지 않게 에어리스 펌프나 에어리스 튜브 용기로 제작되어** 변질을 방지합니다. 또 레티날은 성분 특성상 자체가 노란색이고 농도가 진할수록 더 진해지기 때문에 베개나 옷에 묻지 않게 조심하시는 게 좋고, 빛 분해를 막기 위해 밤에만 사용하시는 것이 좋습니다.$AAA$, array['레티날안정화', '리포좀기술', '에어리스용기', '변질방지', '성분보호']::text[], 2025, 'MrvJDn2FTxY-3', 'https://youtu.be/MrvJDn2FTxY?t=114s', null, '2025-03-20 00:00:00+00'::timestamptz, '2025-03-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티날 바를 때 함께 쓰면 안 되는 성분이 있나요?$AAQ$, $AAA$레티날은 비타민C, AHA, BHA 같은 각질 제거 성분과 함께 쓰지 않는 것이 좋습니다. 이런 성분들과 함께 쓰면 피부가 너무 민감해질 수 있기 때문이에요. 그리고 레티날 자체가 빛과 만나면 쉽게 분해될 수 있고, 낮에 바르면 자외선과 만나면서 자극이 심해질 수 있어 **레티날은 밤에만 사용하는 게** 좋습니다.

또 처음부터 매일 바르면 자극이 심할 수 있으니 **일주일에 1~2번 정도만 발라보는 게 좋고**, 또는 크림에 섞어 희석해서 쓰는 방법도 있어요. 자외선 차단제를 제대로 바르지 않으면 오히려 피부 자극 때문에 색소침착이 생길 수 있으므로, 다음날 아침엔 꼭 선크림을 발라야 합니다. 만약 바르다 피부가 뒤집어졌다면 사용을 중단하고 장벽 회복 크림으로 피부를 회복시킨 뒤 다시 시작하시면 됩니다.$AAA$, array['레티날사용법', '병용금기', '비타민C', 'AHA BHA', '야간사용']::text[], 2025, 'MrvJDn2FTxY-4', 'https://youtu.be/MrvJDn2FTxY?t=425s', null, '2025-03-20 00:00:00+00'::timestamptz, '2025-03-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$결혼식 일주일 전 보톡스 맞아도 되나요?$AAQ$, $AAA$결혼식 일주일 전에는 보톡스를 절대 맞으시면 안 됩니다. 일반적인 보톡스 효과는 나타나기까지 일주일 정도 걸리고, 사각턱 보톡스는 한 달 정도 생각해야 해요. 근육이 마비되어 줄어드는 시간이 필요하기 때문입니다.

특히 **사각턱 보톡스는 부작용이 생길 수 있는 부위**라서 입이 비뚤어질 위험까지 있어요. 평생 한 번뿐인 중요한 자리를 앞두고 효과가 채 안 나오거나 부작용이 생기면 돌이키기 어렵습니다. 모공이나 흉터 치료도 회복하는 데 꽤 오랜 시간이 걸려 몇 달 전부터 서서히 준비해야 하는 시술이고, 색소 레이저 시술 역시 메이크업으로 가려지므로 중요한 이벤트 직전에는 받지 마세요. **이런 중요한 이벤트 직전에는 색소 레이저 시술 받지 마세요**.$AAA$, array['보톡스시기', '결혼식준비', '시술금기', '사각턱보톡스', '부작용']::text[], 2025, 'a1erQIFKqtc-1', 'https://youtu.be/a1erQIFKqtc?t=43s', null, '2025-03-21 00:00:00+00'::timestamptz, '2025-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅 효과는 어떻게 나타나나요?$AAQ$, $AAA$티타늄은 시술 직후 바로 BTS(Brightening, Tightening, Slimming) 효과가 나타나는 즉각형 리프팅입니다. **세 가지 파장의 빛을 이용해 표피, 진피, 피하지방층에 동시에 열을 줘서** 즉각적인 효과를 만들어내요. 얼굴 한쪽만 시술 후 거울로 보면 짝짝이라고 놀랄 정도로 변화가 두드러집니다.

B는 Brightening으로 얼굴이 화사해지고, T는 Tightening으로 피부가 탄탄해지고, S는 Slimming으로 얼굴 라인이 갸름해지는 효과예요. 울쎄라, 써마지와 유사한 효과에 더해 얼굴이 환해지는 플러스 알파가 있고, 시술하면 바로 리프팅 효과가 보이며 며칠 지나면 피부톤도 점점 밝아져요. **다른 시술들은 중요한 약속 전날 받기 힘들지만 티타늄은 당일에도 가능하고** 붓기가 별로 없고 화장도 가능해 연예인들이 방송 전날에도 많이 받는 시술입니다.$AAA$, array['티타늄리프팅', 'BTS효과', '즉각효과', '광대리프팅', '당일시술']::text[], 2025, 'a1erQIFKqtc-2', 'https://youtu.be/a1erQIFKqtc?t=144s', null, '2025-03-21 00:00:00+00'::timestamptz, '2025-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타란 스킨부스터는 리쥬란과 어떻게 다른가요?$AAQ$, $AAA$비타란은 송어 DNA, 리쥬란은 연어 DNA를 이용한 폴리뉴클레오타이드 성분의 스킨부스터입니다. 둘 다 DNA 조각의 아주 긴 사슬이라는 점은 같지만 원료가 달라요. 폴리뉴클레오타이드는 재생 효과가 좋고 염증 감소 효과와 수분 충전 효과까지 있어서 **피부 컨디션이 아주 반짝 올라가죠**.

특히 비타란은 손주사로 일일이 찌르는 것이 아니라 **약간의 손기술을 섞어서 하이브리드 방식으로 피부 밑에 아주 얇게 쫙 깔아드리는** 시술법을 사용합니다. 이렇게 하면 리쥬란처럼 올록볼록한 엠보가 생기지 않고 다운타임이 1도 없으며 피가 1도 안 나요. 시술 직후에 바로 광이 쫙 돌고 홍조 개선과 피부톤 환해짐, 건조함 해소 효과를 볼 수 있어 결혼식 같은 중요한 이벤트 전에 적합합니다.$AAA$, array['비타란', '리쥬란', '폴리뉴클레오타이드', '스킨부스터', '송어DNA']::text[], 2025, 'a1erQIFKqtc-3', 'https://youtu.be/a1erQIFKqtc?t=240s', null, '2025-03-21 00:00:00+00'::timestamptz, '2025-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$결혼식 전 가성비 시술은 무엇이 있나요?$AAQ$, $AAA$코레지는 결혼식 전 가성비 좋은 고주파 시술로 추천드릴 만합니다. **16개의 고주파가 화음을 이뤄 피부 세포를 직접 자극하는** 시술이에요. 도, 미, 솔이 따로 들릴 때보다 화음이 됐을 때 더 아름답게 들리는 것과 같은 원리로 고주파를 동시에 쏴 콜라겐과 엘라스틴 생성을 촉진합니다.

도자로 피부를 부드럽게 문지르면서 에너지를 전달해 탄력이 좋아지고 염증도 줄어들어 전반적인 피부 컨디션을 끌어올립니다. 코레지의 장점은 **시술 직후부터 효과가 보이면서 시간이 갈수록 톤이 좋아지고 광이 나며** 약간의 리프팅 효과까지 있다는 점이에요. 비용 부담 때문에 티타늄이나 비타란이 어려운 분들에게 가성비 시술로 추천되며, 가끔 관리받고 싶을 때 받기 좋은 옵션입니다.$AAA$, array['코레지', '고주파시술', '가성비리프팅', '콜라겐자극', '결혼식준비']::text[], 2025, 'a1erQIFKqtc-4', 'https://youtu.be/a1erQIFKqtc?t=323s', null, '2025-03-21 00:00:00+00'::timestamptz, '2025-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미세먼지가 자외선보다 피부에 더 안좋나요?$AAQ$, $AAA$WHO 자료에 따르면 **하루 동안 미세먼지에 노출된 피부가 일주일 동안 햇빛을 쬐는 피부보다 더 손상이 심하다고** 합니다. 햇빛은 선크림으로 막을 수 있지만 미세먼지는 마스크 외에는 딱히 막을 방법이 없어 더 까다로워요.

특히 초미세먼지는 사람 머리카락 굵기의 1/30 정도로 굉장히 작아서 피부 모공 속으로 잘 들어가 침투합니다. 미국 한 연구팀이 상의를 벗고 피부로만 미세먼지를 닿게 했을 때와 호흡기로만 흡입했을 때를 비교했더니 **두 가지가 체내로 흡수된 양이 비슷했다고** 해요. 또 60대 고령 참가자의 피부 흡수율이 20대보다 5배나 높았는데, 이는 나이가 들수록 피부 장벽이 약해지기 때문입니다. 피부 속으로 들어간 미세먼지는 쇠가 녹스는 것처럼 피부를 산화시키고 염증을 일으키며 피부 장벽까지 망가뜨려요.$AAA$, array['미세먼지', '자외선비교', '피부노화', '초미세먼지', '피부장벽']::text[], 2025, 'rAa4jsDXbvE-1', 'https://youtu.be/rAa4jsDXbvE?t=53s', null, '2025-03-25 00:00:00+00'::timestamptz, '2025-03-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미세먼지로 인한 피부 노화는 어떻게 막나요?$AAQ$, $AAA$비타민C를 외출 전에 발라 미세먼지로 인한 피부 노화를 막는 것이 효과적입니다. 이탈리아 연구진이 밝혀낸 바에 따르면 비타민C는 **미세먼지가 공격하는 세 가지 지점들을 정확히 다 막아준다고** 합니다.

첫째는 미세먼지가 만드는 활성산소를 직접 제거하는 항산화 작용, 둘째는 염증 반응을 진정시키는 항염 효과, 셋째는 피부 장벽의 단백질 생성을 촉진해 장벽을 튼튼하게 만들어주는 작용이에요. 특히 흥미로운 점은 **자외선과 미세먼지가 만나서 생기는 시너지 효과도 막아준다는** 거예요. 이탈리아 연구진의 실험실 배양 세포 연구에서 비타민C로 전처리한 세포는 자외선과 미세먼지에 동시 노출됐을 때도 거의 손상이 없었습니다. 외출 전에 항산화 성분인 비타민C를 발라야 미세먼지를 만나기 전에 피부를 보호할 수 있어요.$AAA$, array['비타민C', '항산화', '미세먼지방어', '활성산소제거', '외출전관리']::text[], 2025, 'rAa4jsDXbvE-2', 'https://youtu.be/rAa4jsDXbvE?t=267s', null, '2025-03-25 00:00:00+00'::timestamptz, '2025-03-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$어떤 비타민C 제품을 골라야 효과가 좋나요?$AAQ$, $AAA$**순수 비타민C 함량이 15% 이상이면서 비타민E나 페룰릭산 같은 안정제가 들어 있는** 제품을 골라야 합니다. 연구 결과 아무 비타민C 제품이나 발라서는 안 되며, 일정 농도 이상과 안정제 조합이 필요해요. 비타민C는 불안정해서 쉽게 산화되기 때문에 안정화 성분이 중요합니다.

바르는 타이밍도 중요한데, 미세먼지를 만나기 전인 외출 전에 항산화 성분인 비타민C를 바르는 게 좋아요. 그리고 미세먼지는 자외선과 결합하면 피부 손상이 더 심해지기 때문에 **꼭 선크림을 같이 발라야 돼요**. 미세먼지가 심한 날에는 클렌징 오일이나 밀크 같은 1차 세안제로 노폐물을 녹여낸 후 폼클렌저로 한 번 더 씻어내는 이중세안을 통해 피지와 결합한 미세먼지까지 제거해주세요.$AAA$, array['비타민C제품', '안정제', '페룰릭산', '비타민E', '선크림']::text[], 2025, 'rAa4jsDXbvE-3', 'https://youtu.be/rAa4jsDXbvE?t=321s', null, '2025-03-25 00:00:00+00'::timestamptz, '2025-03-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미세먼지는 어떤 피부 타입에 가장 안좋은가요?$AAQ$, $AAA$미세먼지는 건성·지성·민감성 피부 모두에 안 좋지만 특히 건성과 민감성 피부가 더 취약합니다. 건성 피부는 원래 수분이 부족한데 **미세먼지가 닿으면 피부 장벽이 손상되면서 수분 손실이 더 빨라져요**. 그러면 피부가 더 민감해지고 가려움이나 따가움 같은 염증 반응도 심해집니다.

지성 피부는 미세먼지가 피지에 잘 들러붙기 때문에 피지와 뭉친 미세먼지가 모공 속으로 잘 들어가 염증을 일으켜 여드름이 심해질 수 있어요. 민감성 피부는 미세먼지가 피부 염증을 더 심하게 만들고 장벽을 손상시켜 예민함이 가중됩니다. 더 큰 문제는 악순환이 일어난다는 점인데, **피부 장벽이 무너지면 더 많은 미세먼지가 침투해서** 손상이 누적되며 결국 색소침착, 기미, 여드름이나 아토피 같은 피부 질환을 심하게 만듭니다.$AAA$, array['피부타입', '건성피부', '지성피부', '민감성피부', '악순환']::text[], 2025, 'rAa4jsDXbvE-4', 'https://youtu.be/rAa4jsDXbvE?t=181s', null, '2025-03-25 00:00:00+00'::timestamptz, '2025-03-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$주름을 만드는 생활 습관에는 어떤 것들이 있나요?$AAQ$, $AAA$빨대 사용, 스마트폰을 숙여서 보는 자세, 옆으로 자는 자세가 대표적인 주름 유발 습관입니다. 빨대를 사용할 때 입을 오므리는 동작이 반복되면 입 둘레 주름이 굉장히 쉽게 생기고, 한번 생기면 없어지지도 않아 나이 들어 보이게 만듭니다. 그래서 커피나 음료를 자주 빨대로 마시는 분들은 한번 체크해 보세요.

스마트폰을 보면서 고개를 숙이는 자세는 텍스트넥이라고 부르는데, **목이 구부러지면서 턱살이 처지고 목주름이 생기는** 자세가 됩니다. 스마트폰을 높여서 목이 구부러지지 않게 하면 턱과 목 주름을 크게 줄일 수 있어요. 또 옆으로 누우면 얼굴 한쪽에 압력이 가해져서 시간이 지나면 **한쪽 팔자주름이 더 심해질 수 있거든요**. 천장을 보고 똑바로 누워서 자고, 베개 높이도 너무 높지 않게 조절하면 목주름 예방에 도움이 됩니다.$AAA$, array['주름습관', '빨대주름', '텍스트넥', '수면자세', '팔자주름']::text[], 2025, 'QMCQ2sOAjXU-1', 'https://youtu.be/QMCQ2sOAjXU?t=43s', null, '2025-03-27 00:00:00+00'::timestamptz, '2025-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$주름 개선에 효과적인 화장품 성분은 무엇인가요?$AAQ$, $AAA$**레티놀, 레티날, 비타민C가 주름 개선에 가장 효과적인** 성분입니다. 레티놀은 이미 생긴 주름을 개선하는 데 가장 효과적인 안티에이징 대표 성분으로, 피부 세포가 턴오버를 빨리하게 하고 콜라겐 생성을 자극해요. 피부 미백 효과까지 있어 피부를 탱탱하게 해줍니다.

레티날은 레티놀보다 한 단계 더 강한 안티에이징 성분이에요. 처음 사용하시는 분들은 피부가 적응할 시간이 필요해서 낮은 농도로 일주일에 2~3회 정도로 시작해 점점 늘려가는 것이 좋습니다. 또 낮에는 자외선에 민감해질 수 있어 주로 저녁에 바르고 다음날 아침엔 꼭 선크림을 발라야 해요. 비타민C는 강력한 항산화제로 자외선으로부터 피부를 보호하고 콜라겐 합성을 도와줘요. **멜라닌 색소 생성도 억제해서 기미, 잡티도 함께 개선할 수 있어** 일석이조입니다. 다만 레티놀과 비타민C를 함께 바르면 자극이 될 수 있어 아침엔 비타민C, 저녁엔 레티놀로 시간을 나눠 쓰세요.$AAA$, array['레티놀', '레티날', '비타민C', '콜라겐생성', '안티에이징']::text[], 2025, 'QMCQ2sOAjXU-2', 'https://youtu.be/QMCQ2sOAjXU?t=146s', null, '2025-03-27 00:00:00+00'::timestamptz, '2025-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$30대부터 보톡스를 미리 맞는 게 좋나요?$AAQ$, $AAA$주름이 신경 쓰이기 시작하는 30대부터 미리미리 보톡스를 맞는 것이 권해 드릴 만합니다. 보톡스는 표정을 지을 때 생기는 주름, 특히 **이마, 눈가, 미간 이런 주름에는 정말 보톡스만한 게 없어요**. 깊어지기 전에 예방하듯 맞아두면 도움이 됩니다.

보톡스는 너무 간단하고 효과 좋고 가성비가 진짜 좋은 시술인데, **이미 주름이 깊게 자리를 잡아 버리면 그때는 보톡스 만으로는 해결되지 않아요**. 그래서 미리미리 관리하는 게 훨씬 경제적이고 효과적이라는 거죠. 보톡스가 부담스러우신 분들은 바르는 보톡스라고 불리는 펩타이드 성분이 들어간 화장품을 대안으로 쓸 수 있어요. 굵은 주름에는 효과가 덜할 수 있지만 꾸준히 쓰면 얇은 잔주름은 많이 개선됩니다. 다만 보톡스 주사만큼의 효과는 기대하기 어렵습니다.$AAA$, array['보톡스시기', '30대보톡스', '예방주름', '펩타이드', '표정주름']::text[], 2025, 'QMCQ2sOAjXU-3', 'https://youtu.be/QMCQ2sOAjXU?t=359s', null, '2025-03-27 00:00:00+00'::timestamptz, '2025-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스로 안 펴지는 주름은 어떻게 치료하나요?$AAQ$, $AAA$보톡스로 펴지지 않는 깊은 주름은 필러로 패인 부분을 채워 올리는 방법이 필요합니다. 이마에 패인 주름 같은 경우에는 보톡스로는 다 안 펴져요. 필러를 주름에 사용할 때는 **피부의 얕은 층에 아주 조금씩 주입을 하는 거라서** 조심스럽게 시술하면 부작용을 피하면서 효과적으로 주름을 없앨 수 있습니다.

그리고 보톡스와 필러로도 교정이 안 되는 미세한 잔주름이 또 있어요. 눈가, 눈 아래, 입가에 있는 자글자글한 잔주름들은 스킨부스터가 필요합니다. **스킨부스터는 히알루론산이나 여러 가지 다른 영양성분들을 피부 속에다가 미세하게 주입을 하거나** 기계로 침투시키는 시술이에요. 필러처럼 볼륨을 채우는 게 아니라 피부 속의 수분이나 탄력을 높여 잔주름을 개선합니다. 특히 눈가나 입가, 자글자글한 목주름에 효과적이며 리쥬란, 비타란, 스킨바이브, 쥬베룩, 리바이브, 레스틸렌 등 종류가 다양합니다.$AAA$, array['필러주름', '스킨부스터', '잔주름개선', '히알루론산', '깊은주름']::text[], 2025, 'QMCQ2sOAjXU-4', 'https://youtu.be/QMCQ2sOAjXU?t=420s', null, '2025-03-27 00:00:00+00'::timestamptz, '2025-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흐린 날에도 선크림을 발라야 하나요?$AAQ$, $AAA$흐린 날에도 선크림을 꼭 발라야 합니다. 흐린 날은 구름이 있어 햇빛이 없다고 생각하는데, 의외로 **자외선의 90% 이상은 구름을 통과를 다 하거든요**. 그래서 자외선이 피부 깊이 들어와 콜라겐을 파괴하고 주름과 색소침착을 만들기 때문에 흐린 날에도 발라야 합니다.

실내에서도 유리창을 통해 자외선이 들어올 수 있어요. 운전을 많이 하거나 자리가 주로 창가에 있어 햇빛이 잘 든다면 꼭 잘 발라줘야 합니다. **피부 노화의 80%는 자외선 때문에** 생기는데, 피부가 자외선에 노출되면 콜라겐과 엘라스틴이 파괴되면서 피부가 얇아지고 주름이 생겨요. 다만 햇빛이 거의 안 드는 실내에서는 굳이 바를 필요는 없고, 형광등이나 LED 등에서 나오는 자외선은 양이 정말 작아서 무시해도 될 수준이라 굳이 안 발라도 됩니다.$AAA$, array['선크림', '자외선차단', '흐린날', '실내자외선', '광노화']::text[], 2025, 'QMCQ2sOAjXU-5', 'https://youtu.be/QMCQ2sOAjXU?t=288s', null, '2025-03-27 00:00:00+00'::timestamptz, '2025-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부는 정말 노화가 덜 진행되나요?$AAQ$, $AAA$지성 피부는 다른 피부 타입에 비해 노화가 더디게 진행됩니다. 모공이 많고 크거나 기름기가 많아서 오후만 되면 개기름이 끼는 분들이 속상해하시지만, 사실 이런 피부가 제일 좋은 피부입니다.

그 이유는 얼굴에 유분막이 있으면 **피부가 덜 건조해지고 잔주름도 덜 생기기** 때문이에요. 그래서 지성 피부가 다른 피부 타입에 비해 훨씬 탱탱합니다. 다만 당장 피부가 더러워 보이고 모공에 화장이 껴서 매끈해 보이지 않으며 시간이 지나면 지저분해 보이기 때문에, 당사자들은 속상한 경우가 더 많죠. 그래서 지성 피부는 **클렌징, 비타민C 같은 항산화 케어, 가벼운 보습 제품 선택, 모공 메이크업 같은 관리 포인트**를 집중적으로 챙기면 장점을 살리면서 단점을 보완할 수 있습니다.$AAA$, array['지성피부', '노화더딤', '유분막', '탄력유지', '피부타입']::text[], 2025, 'RiLTNyvpQrc-1', 'https://youtu.be/RiLTNyvpQrc?t=34s', null, '2025-03-28 00:00:00+00'::timestamptz, '2025-03-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부의 클렌징은 어떻게 해야 하나요?$AAQ$, $AAA$지성 피부는 1차 세안과 2차 세안의 이중 세안이 핵심입니다. **1차 세안은 화장, 기름, 각질을 1차적으로 녹여내는 데** 사용해서 모공에 끼인 피지와 노폐물이 잘 씻겨 내려가게 합니다. 클렌징 밀크나 클렌징 오일을 사용하시되 제품 종류보다 노폐물과 피지를 녹여내는 단계 자체가 중요해요.

그다음 2차 세안은 1차 세안제로 녹인 노폐물들이 모공에 남지 않도록 끝까지 잘 헹구는 과정이에요. 세안 중에는 뜨거운 물 말고 따뜻한 물이나 미지근한 물로 하시고, 마무리는 너무 찬물 말고 시원한 물로 해주세요. **2차 세안까지 마치고 필링젤로 스크럽을 하는데** 보통은 피부 장벽이 망가질 수 있어 권하지 않지만 지성 피부는 피부 상태를 보고 겨울철엔 1~2주에 한 번, 여름엔 일주일에 두 번 정도 해주는 것이 좋습니다.$AAA$, array['이중세안', '1차세안', '2차세안', '필링젤', '지성피부클렌징']::text[], 2025, 'RiLTNyvpQrc-2', 'https://youtu.be/RiLTNyvpQrc?t=86s', null, '2025-03-28 00:00:00+00'::timestamptz, '2025-03-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부에 적합한 보습 크림이 따로 있나요?$AAQ$, $AAA$지성 피부엔 묵직하지 않고 가벼운 제형이면서 **세라마이드, 콜레스테롤, 지방산이 들어간 장벽 강화 크림**이 적합합니다. 지성 피부도 로션이나 크림을 잘못 바르면 트러블이 올라오는데, 가벼운 제형의 장벽 보습제를 고르면 트러블 없이 충분한 보습이 가능해요.

예를 들어 에스트라 아토베리어 AI크림은 피부 장벽을 튼튼하게 해주는 세라마이드, 콜레스테롤, 지방산이 들어가면서도 지성 피부용이라서 묵직하지 않고 가벼워요. 보통 세콜지가 들어간 제품들은 유분기가 많아서 지성에게 권하기 망설여졌지만 이 제품은 산뜻한 편입니다. 또한 팩은 잘못 쓰면 오히려 트러블이 올라올 수 있어요. 그래서 **팩 사는데 돈 낭비하지 말고 기초를 열심히 바르면** 그걸로 충분합니다. 묵직한 크림보다는 가볍고 산뜻한 제형을 우선 고려하시는 것이 좋습니다.$AAA$, array['지성보습', '세라마이드', '장벽크림', '가벼운제형', '팩사용법']::text[], 2025, 'RiLTNyvpQrc-3', 'https://youtu.be/RiLTNyvpQrc?t=246s', null, '2025-03-28 00:00:00+00'::timestamptz, '2025-03-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 초기 대응은 어떻게 해야 하나요?$AAQ$, $AAA$여드름은 초기 대응이 가장 중요하며, 진통소염제 성분의 애크논 크림으로 덮어주는 것이 효과적입니다. **여드름이 막 올라오기 시작해서 붉어지고 만지면 아프다 싶을 때** 약국에서 살 수 있는 애크논 크림을 사용하세요.

여기서 중요한 팁은 그냥 바르는 게 아니라 덮어준다는 거예요. 말 그대로 **트러블 부위를 애크논 크림으로 도톰하게 덮어주는 게** 중요합니다. 또 항노화 효과까지 함께 노린다면 처방받아야 구매 가능한 갈더마코리아 아크리프 크림이 대안인데, 스티바A 크림이 단종된 뒤 대체제로 좋은 전문의약품입니다. 다른 레티놀이나 레티날 같은 항노화 화장품에 비해 효과가 뛰어나고 원래 여드름에 쓰는 약이라 여드름이나 피지 조절에도 탁월해요. 다만 자극감이 있을 수 있어 처음엔 다른 보습 크림과 섞어서 발라보고 괜찮으면 단독으로 사용하시는 게 좋습니다.$AAA$, array['여드름초기', '애크논크림', '아크리프크림', '트러블관리', '도톰하게덮기']::text[], 2025, 'RiLTNyvpQrc-4', 'https://youtu.be/RiLTNyvpQrc?t=347s', null, '2025-03-28 00:00:00+00'::timestamptz, '2025-03-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부 모공 커버 메이크업은 어떻게 하나요?$AAQ$, $AAA$지성 피부의 모공 커버는 프라이머와 파운데이션을 얇게 펴 바르고 스펀지로 톡톡 두드리는 방식이 효과적입니다. 베네피트 더 포어페셔널 같은 **실리콘 베이스 프라이머는 모공을 착 메꿔주는 역할을** 하는데, 슥슥 바르지 마시고 모공이 있는 부위에 열감을 이용해 여러 번 문지른 뒤 톡톡 두드려 주세요.

파운데이션은 스파츌라에 얹어 얇게 펴 바른 다음 **스펀지로 톡톡 엄청 오래 두들겨주면** 모공 부분이 덜 보이고 매끈한 표현이 됩니다. 그리고 파우더도 진짜 중요해요. 가루 타입이든 팩트 타입이든 적당량을 완전 밀착해 힘 있게 두드려 주세요. 화장이 두꺼워 보이지 않게 하는 것이 포인트입니다. 오후에 유분기가 올라오면 픽서 대신 파우더가 발린 기름종이로 피부를 눌러주세요. 이 방법이 픽서보다 오래가고 화장이 뭉치지 않아 지성 피부에 가장 좋습니다.$AAA$, array['모공커버', '프라이머', '파운데이션기법', '파우더기름종이', '지성메이크업']::text[], 2025, 'RiLTNyvpQrc-5', 'https://youtu.be/RiLTNyvpQrc?t=447s', null, '2025-03-28 00:00:00+00'::timestamptz, '2025-03-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라와 필러는 어떻게 다른가요?$AAQ$, $AAA$스컬트라는 피부 스스로 콜라겐을 만들게 자극하는 시술이고, 필러는 히알루론산을 직접 채우는 시술입니다. 필러는 쫀득한 히알루론산을 넣어 그 자체가 볼륨을 만들기 때문에 시술 즉시 효과가 나타나지만, 1년 정도 지나면 몸에 흡수돼 사라져요. 반면 스컬트라는 섬유아세포를 자극해 새로운 콜라겐을 만들어내고, 그 콜라겐이 차오르면서 볼륨이 생깁니다.

그래서 **효과가 천천히 나타나는 대신**, 필러보다 더 오래 유지돼요. 또 시술 횟수도 다른데, 필러는 한 번에 원하는 만큼 채우면 끝이지만, 스컬트라는 콜라겐 생성에 시간이 걸려 2~3회까지 시술이 필요합니다. 다만 **원하는 부위를 원하는 만큼 정확히 채우는 건 필러로 해야 하고**, 스컬트라는 사람마다 콜라겐 생성 능력이 달라 만들어지는 양도 달라요. 자연스러움을 원할 때 스컬트라가 잘 맞습니다.$AAA$, array['스컬트라', '필러비교', '콜라겐생성', '히알루론산', '볼륨시술']::text[], 2025, 'KUygxZviqWw-1', 'https://youtu.be/KUygxZviqWw?t=177s', '{"pmid": "39719485", "doi": "10.1007/s00266-024-04627-5", "title": "A Systematic Review on the Effectiveness and Safety of Combining Biostimulators with Botulinum Toxin, Dermal Fillers, and Energy-Based Devices.", "journal": "Aesthetic Plast Surg", "year": "2024", "authors_short": "Tam E, Choo JPS, Rao P et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39719485/", "doi_url": "https://doi.org/10.1007/s00266-024-04627-5"}'::jsonb, '2025-04-01 00:00:00+00'::timestamptz, '2025-04-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라 효과는 얼마나 오래 가나요?$AAQ$, $AAA$스컬트라 효과는 개인차가 있지만 대부분 **2년 정도 유지됩니다**. 필러가 부위에 따라 보통 1년 이상 지속되는 것에 비하면 오래 유지되는 편이에요. 즉시 볼륨이 채워지는 게 아니라, 피부가 스스로 콜라겐을 만들어내고 그 콜라겐이 피부의 일부가 되기 때문에 몸에서 빨리 분해되지 않아 효과가 길게 가는 것입니다.

다만 시술 직후 바로 효과가 나타나진 않아요. 스컬트라는 가루를 주사용수에 섞어 주입하는데, 그 주사용수가 1~2일 내로 흡수되고 그 다음부터 가루가 천천히 녹으며 콜라겐이 생성되기 시작합니다. 보통 **3~4주 정도부터 효과가 보이기 시작해 3~6개월에 걸쳐 점점 좋아져요**. 그래서 결혼식 같은 중요한 일정 직전에 맞는 시술은 아니고, 여유를 두고 계획하시는 게 좋아요.$AAA$, array['스컬트라지속기간', '효과기간', '콜라겐', '시술효과', '재시술']::text[], 2025, 'KUygxZviqWw-2', 'https://youtu.be/KUygxZviqWw?t=458s', '{"pmid": "40897963", "doi": "10.1007/s00266-025-05190-3", "title": "Final Report on the Safety and Efficacy of Poly-L-Lactic Acid Filler (Gana V) Injection for the Correction of Nasolabial Fold: A Double-Blind, Non-Inferiority, Randomized, Split-Face Controlled Trial.", "journal": "Aesthetic Plast Surg", "year": "2025", "authors_short": "Kim H, Kim HJ, Han WY et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/40897963/", "doi_url": "https://doi.org/10.1007/s00266-025-05190-3"}'::jsonb, '2025-04-01 00:00:00+00'::timestamptz, '2025-04-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라는 누구에게 잘 맞는 시술인가요?$AAQ$, $AAA$스컬트라는 **노화로 피부 꺼짐이 있는 분에게 잘 맞는 시술입니다**. 30대 중후반부터 60대까지 다 해당될 수 있는데, 특히 얼굴이 전체적으로 살이 없어 마르고 군데군데 꺼진 분들에게 좋아요. 본인 얼굴에 볼륨이 필요하지만 자연스러움이 중요한 분, 그리고 꺼진 부위에 잔주름이 많고 탄력이 떨어진 분에게도 권합니다.

주로 시술하는 부위는 관자놀이가 꺼진 부위, 광대뼈 아래 볼이 꺼진 부위 등인데, 이 부위들이 나이 들면서 가장 많이 볼륨이 줄어드는 곳이에요. 관자놀이가 꺼지면 얼굴이 해골 같아 보이고, 광대와 볼이 꺼지면 뼈가 튀어나와 보이며 얼굴이 울퉁불퉁해집니다. 다만 **눈 주변·이마·입가는 움직임이 많고 피부가 얇아 결절이 잘 보일 수 있어** 시술을 안 하도록 되어 있어요.$AAA$, array['스컬트라적응증', '관자놀이꺼짐', '볼륨감소', '노화', '시술부위']::text[], 2025, 'KUygxZviqWw-3', 'https://youtu.be/KUygxZviqWw?t=347s', '{"pmid": "41493260", "doi": "10.36849/JDD.9501", "title": "Prospective Single-Site Open-label Study Assessing Safety and Efficacy of Poly-L-Lactic Acid for Temple Volume Loss.", "journal": "J Drugs Dermatol", "year": "2026", "authors_short": "Arruda S, Swearingen A, Elmadany Z et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/41493260/", "doi_url": "https://doi.org/10.36849/JDD.9501"}'::jsonb, '2025-04-01 00:00:00+00'::timestamptz, '2025-04-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라 결절 부작용은 위험하지 않나요?$AAQ$, $AAA$스컬트라는 피부에 딱딱한 결절이 만져질 수 있는 부작용이 있지만, **최근에는 결절 발생 확률이 굉장히 낮아졌습니다**. 스컬트라는 20년이 넘은 오래된 시술이라 전 세계적으로 많은 시술이 이루어졌고, 그만큼 검증된 시술이에요. 예전 처음 쓰이던 때에는 결절이 꽤 많이 발생했지만, 오랜 세월을 거치며 시술 방법이 많이 개선됐습니다.

그래도 위험이 아예 없는 건 아니어서 **결절이 안 생기도록 하는 여러 가지 방법이 필요해요**. 모든 시술에는 부작용 가능성이 있다는 점도 염두에 두셔야 합니다. 또 부작용은 아니지만 단점도 있어요. 맞은 즉시 효과가 나타나지 않고, 시술 직후 보이는 약간의 볼륨은 실제 효과가 아니라 가루를 섞은 주사용수 때문이에요. 주사용수는 1~2일 내 흡수되고 콜라겐 생성은 3~4주 후부터 시작됩니다.$AAA$, array['스컬트라결절', '부작용', '안전성', '시술이력', '검증']::text[], 2025, 'KUygxZviqWw-4', 'https://youtu.be/KUygxZviqWw?t=412s', '{"pmid": "21239677", "doi": "10.1177/1090820X10391213", "title": "Nonsurgical rejuvenation of the aging face with injectable poly-L-lactic acid for restoration of soft tissue volume.", "journal": "Aesthet Surg J", "year": "2011", "authors_short": "Schierle CF, Casas LA", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/21239677/", "doi_url": "https://doi.org/10.1177/1090820X10391213"}'::jsonb, '2025-04-01 00:00:00+00'::timestamptz, '2025-04-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$안면거상술과 울쎄라·써마지는 어떻게 다른가요?$AAQ$, $AAA$안면거상술은 피부를 절개해 SMAS를 직접 잘라 당겨 고정하는 수술이고, 울쎄라·써마지는 외부에서 열을 줘 SMAS층을 수축시키는 비수술적 리프팅 시술입니다. 울쎄라는 초음파 열을 조사해 근막층을 수축시키는데, 더 이상 효과가 부족할 때 성형외과에서 피부를 절개하고 늘어난 SMAS를 육안으로 보면서 잘라내고 당겨 고정해요.

접근하는 원리는 비슷하지만 **수술은 근막을 자르고 당기는 적극적인 방식이에요**. 그래서 안면거상술은 효과가 드라마틱하지만 회복 기간이 필요합니다. 한 가지 흥미로운 점은 울쎄라·써마지를 아무리 많이 받아도 **안면거상술에 거의 영향을 미치지 않는다는 점**입니다. 성형외과 의사들도 처음엔 우려해서 수술 전 병력을 체크하지만, 실제로는 영향이 없어 아무리 많이 하셔도 괜찮다고 합니다.$AAA$, array['안면거상술', '울쎄라', '써마지', 'SMAS', '리프팅비교']::text[], 2025, 'noid-1-2', 'https://youtu.be/_4yPUUMNrqA', null, '2025-04-07 00:00:00+00'::timestamptz, '2025-04-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$안면거상술 효과는 평생 유지되나요?$AAQ$, $AAA$안면거상술 효과는 평생 가지 않고, **수술 후 5~10년 정도 지속됩니다**. 그러면 좋겠지만 모든 조직은 당기는 그 순간부터 다시 처지기 시작하기 때문이에요. 시간이 지나면 다시 처지는 것이 눈에 드러나는 순간이 오고, 한 번 수술 받는 걸로는 만족 못하는 분들도 종종 계세요.

실제로 재수술을 받고 또 재수술을 받는 분들도 간혹 계신데, **수술을 받을수록 조직 상태가 좋아지지 않아 부작용 가능성이 올라가고 결과도 처음만큼 자연스럽지 못할 수 있습니다**. 그래서 초반에는 리프팅으로 관리하다가 50대 이후에 안면거상술을 받는 게 좋아요. 또 수술 후 초반 6개월은 회복에 신경 써야 해서 리프팅을 받지 못하지만, 6개월 정도 지나 회복이 되면 울쎄라·써마지 같은 시술을 적극적으로 받아 효과를 오래 유지하는 게 권장됩니다.$AAA$, array['안면거상술지속', '재수술', '효과기간', '리프팅조합', '노화관리']::text[], 2025, 'noid-2-2', 'https://youtu.be/_4yPUUMNrqA', null, '2025-04-07 00:00:00+00'::timestamptz, '2025-04-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$안면거상술을 받으면 얼굴형이 변하나요?$AAQ$, $AAA$안면거상술을 받으면 **원래 갖고 있던 얼굴 윤곽이 변하는 경우가 있어요**. 얼굴이 팽팽해져 만족감이 높지만, 달라진 얼굴형 때문에 어색하다는 얘기를 듣기도 합니다. 수술할 때 조직을 위쪽으로 당기다 보니 사각턱 부위가 자연스럽게 눌리게 돼요.

대표적인 예가 브래드 피트인데, 원래 사각턱이 발달했지만 수술 후 사각턱이 없어졌습니다. **여성분들은 V라인·U라인이 됐다고 좋아하는 경우가 많지만**, 남성분들은 얼굴이 여성스러워진 것 같다며 부자연스럽다고 하는 경우가 종종 있어요. 또 한 가지, 얼굴 형태가 네모에 가까울수록 안면거상술 효과가 좋습니다. 나이 들면 피부 안 연부조직과 심부지방층이 처져 얼굴이 불독처럼 네모로 되는데, 수술 후 다시 V라인으로 돌아오니 만족도가 매우 높아요.$AAA$, array['안면거상술얼굴형', '사각턱', 'V라인', '윤곽변화', '수술결과']::text[], 2025, 'noid-3-2', 'https://youtu.be/_4yPUUMNrqA', null, '2025-04-07 00:00:00+00'::timestamptz, '2025-04-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅 시술과 안면거상술 중 어느 시점에 무엇을 받는 게 좋나요?$AAQ$, $AAA$젊고 처짐이 적을 때는 울쎄라·써마지로 관리하다가, 효과가 미진해지는 시기에 안면거상술로 접근하는 게 권장됩니다. 안면거상술은 50살에 받아도 60살 넘어 또 해야 할 가능성이 있고 효과가 평생 가지 않기 때문이에요. 그래서 **처짐이 많지 않을 때는 리프팅으로 평생 관리**하는 게 좋습니다.

실제로 꾸준히 울쎄라 시술을 받으면 **적어도 7~10년 정도 젊어보일 수 있어요**. 어떤 분은 작년 가을 울쎄라를 받은 후로 얼굴이 덜 처지기 시작했다고 합니다. 다만 네모형 얼굴은 울쎄라 효과가 확실히 떨어져 안면거상술이 더 잘 맞아요. 성형외과 원장님조차 둘 중 하나만 고르라면 울쎄라·써마지를 받겠다고 할 정도로, 리프팅 시술을 꾸준히 받으면 안면거상술을 안 받아도 괜찮다고 합니다.$AAA$, array['리프팅타이밍', '울쎄라관리', '안면거상술시기', '노화예방', '시술순서']::text[], 2025, 'noid-4-2', 'https://youtu.be/_4yPUUMNrqA', null, '2025-04-07 00:00:00+00'::timestamptz, '2025-04-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터 치료는 정말 효과가 있나요?$AAQ$, $AAA$여드름 흉터 치료는 됩니다. 다만 **100% 원래 피부처럼 돌아가지는 않아요**. 그러나 치료한 흉터와 하지 않은 흉터를 비교하면 확실히 차이가 보입니다. 패인 정도를 완화시켜 더 매끄러워 보이고 남들이 봤을 때 흉터가 덜 보이도록 할 수 있지만, 완전히 없었던 피부로 돌아가는 걸 기대하고 치료받으시면 안 돼요.

중요한 건 시기인데, **흉터가 생긴 지 얼마 안 됐을 때 빨리 치료해야** 결과가 좋습니다. 떠도는 소문만 듣고 무서워서 못 오시다가 한참 후에 와서 치료 기간이 길어지는 분들이 많아요. 패인 흉터는 새살을 채워야 하는데 깊을수록 시간이 오래 걸려, 한두 번 시술로 판단하지 마시고 마라톤 한다고 생각하며 천천히 완주하시는 게 중요합니다. 꾸준히 치료하면 분명 치료 전보다 훨씬 좋아져요.$AAA$, array['여드름흉터치료', '흉터효과', '치료기간', '조기치료', '꾸준한관리']::text[], 2025, 'Sqb-UwUTHIE-1', 'https://youtu.be/Sqb-UwUTHIE?t=70s', null, '2025-04-08 00:00:00+00'::timestamptz, '2025-04-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터 치료는 어떤 방식으로 진행되나요?$AAQ$, $AAA$여드름 흉터 치료는 흉터의 모양·부위·깊이에 따라 여러 방법을 적절히 섞어 진행됩니다. 패인 흉터가 주변 정상 조직과 경계가 뚜렷할 때는 어븀 레이저로 가장자리를 깎아내 단차를 부드럽게 만들어요. 특히 깊고 뾰족한 아이스픽 스카는 **TCA를 이용한 크로스 치료를 주로 사용해요**. 이쑤시개 같은 도구로 함몰 부위에 고농도 TCA를 직접 도포해 국소 염증 반응을 일으켜 새 콜라겐 형성을 촉진합니다.

또 패인 흉터 부위는 염증으로 피부 조직이 엉겨붙어 있어, 바늘이나 CO2 가스로 끊어내는 서브시전도 많이 시행해요. **CO2 프락셀이나 피코 프락셀처럼 미세한 상처를 만들어 진피 재생을 촉진하는 레이저**도 사용하고, 미세 바늘이 스탬프처럼 들어가 고주파로 콜라겐을 만드는 니들 RF도 많이 씁니다. 미라젯·큐어젯으로 바늘 없이 압력을 이용해 쥬베룩 같은 콜라겐 부스터를 주입하는 방식도 활용돼요.$AAA$, array['프락셀', 'TCA크로스', '서브시전', '니들RF', '쥬베룩']::text[], 2025, 'Sqb-UwUTHIE-2', 'https://youtu.be/Sqb-UwUTHIE?t=370s', null, '2025-04-08 00:00:00+00'::timestamptz, '2025-04-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터 치료는 정말 많이 아픈가요?$AAQ$, $AAA$여드름 흉터 치료는 아픈 편에 속하지만, **모든 치료 과정이 아픈 건 아니에요**. CO2 프락셀 레이저처럼 꽤 아픈 레이저가 있는 반면, 마취크림만 발라도 받을 만한 레이저들도 분명 있습니다. 쥬베룩이나 쥬베룩 볼륨 같은 주사 시술은 주사 통증이 당연히 있지만, 통증에 취약한 분이라면 비수면 호흡마취 방식으로 진행할 수 있어요.

비수면 호흡마취는 어린이가 치과 치료할 때 사용하는 웃음가스와 비슷한데, **통증을 못 느끼는 건 아니지만 훨씬 덜 느껴 통증에 예민하신 분도 충분히 치료받을 수 있어요**. 여드름 흉터 치료는 문신제거, 수염 제모와 함께 꽤 아픈 치료에 들어가기 때문에 통증에 취약하신 분은 잘 생각해 보셔야 합니다. 다만 모든 레이저가 아픈 것은 아니니 너무 겁먹을 필요는 없고, 마취크림만으로 부족하다면 비수면 호흡마취가 있는 병원을 찾는 것도 대안이 됩니다.$AAA$, array['흉터통증', 'CO2프락셀', '비수면호흡마취', '웃음가스', '통증완화']::text[], 2025, 'Sqb-UwUTHIE-3', 'https://youtu.be/Sqb-UwUTHIE?t=150s', null, '2025-04-08 00:00:00+00'::timestamptz, '2025-04-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터 치료 전 알아야 할 점은 무엇인가요?$AAQ$, $AAA$여드름 흉터 치료 전 **진물·딱지·붓기 등 회복 과정이 길 수 있다는 점**을 꼭 알아야 합니다. 치료 방법에 따라 진물이 나고 딱지가 생기거나, 치료 부위에 물이 닿으면 안 돼 하루 이틀 정도 못 씻고 재생 테이프를 붙이는 경우도 있어요. 치료 후 얼굴이 붓고 붉은 기가 1~2주 정도 지속될 수도 있습니다.

대부분의 경우 시간이 지나면 점점 좋아지지만, **일부 환자에서는 치료 기간 동안 피부색이 더 붉고 어두워지기도 해요**. 이런 점 때문에 운동하시는 분이나 서비스업 종사자처럼 사람을 상대하는 직업이신 분들은 굉장히 불편할 수 있어요. 주말에 치료받고 하루 이틀 쉬면 티 안 나겠지 생각하셨다가, 이런 과정을 듣고 다시 생각해보겠다며 돌아가시는 분들도 있습니다. 흉터 상태에 따라 이런 과정이 꼭 필요한 경우들이 있으니 알고 내원하시는 게 좋아요.$AAA$, array['흉터회복기간', '진물딱지', '재생테이프', '다운타임', '치료주의사항']::text[], 2025, 'Sqb-UwUTHIE-4', 'https://youtu.be/Sqb-UwUTHIE?t=284s', null, '2025-04-08 00:00:00+00'::timestamptz, '2025-04-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$딸기우유나 가슴 커지는 운동이 정말 효과 있나요?$AAQ$, $AAA$딸기우유는 사춘기 발육기에 먹으면 영향이 있고, 가슴 커지는 운동은 사이즈는 늘지만 모양은 예쁘지 않습니다. 정확히는 딸기가 효과 있는데, **에스트로겐과 유사한 분자식의 물질이 자연 상태에서 존재**해 베리류를 성장기에 먹으면 가슴 발육에 긍정적 영향을 줘요. 다만 성인은 효과를 기대하기 어렵습니다.

가슴 커지는 운동도 효과는 있지만, **여성성을 상징하는 유선조직이나 지방이 커지는 게 아니라 남성성을 상징하는 대흉근이 커지는 거예요**. 대흉근이 커지면 흉곽 사이즈가 늘어 브라 사이즈는 늘어나지만, 헬스로 만든 가슴이라 모양이 예쁘지 않아요. A컵에서 꽉 찬 A컵 정도가 되는 것이지, 여자들이 생각하는 예쁜 가슴으로 커지는 건 아닙니다. 가슴 커지는 크림도 마사지로 인한 일시적 붓기일 뿐 실제 효과는 없어요.$AAA$, array['딸기우유', '가슴운동', '대흉근', '에스트로겐', '속설']::text[], 2025, 'i3IbyFQnb1Q-1', 'https://youtu.be/i3IbyFQnb1Q?t=88s', null, '2025-04-09 00:00:00+00'::timestamptz, '2025-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$가슴 보형물은 평생 사용할 수 있나요?$AAQ$, $AAA$현재 사용하는 가슴 보형물은 **반영구적으로 사용 가능합니다**. 실리콘 보형물은 60년 넘게 사용되어 왔는데, 초기에는 액상 실리콘, 그다음 식염수가 들어갔고, 5세대·6세대로 발전하면서 현재 사용하는 보형물은 사용기간 제한이 없어졌어요. 제조사들의 기술이 좋아져 파손·파열이 많이 낮아진 결과입니다.

그래서 **이제는 10년마다 교체해야 한다는 기준이 없어졌고**, 한 번 넣으면 평생 쓸 수 있어요. 보형물 사이즈는 다양한데, 295cc는 꽉 찬 B컵, 325cc는 남는 C컵이고, D컵을 원한다면 이보다 100cc 정도 더 큰 걸 넣어야 합니다. 트렌드도 변했는데, 과거에는 거거익선이라고 크면 클수록 좋다는 분위기였지만, 요즘에는 자연스러움을 선호하는 쪽으로 바뀌었어요. 보형물마다 촉감이 다른데 더 말랑말랑하고 부드러운 것도 있습니다.$AAA$, array['가슴보형물', '실리콘', '사용기간', '사이즈', '트렌드']::text[], 2025, 'i3IbyFQnb1Q-2', 'https://youtu.be/i3IbyFQnb1Q?t=341s', null, '2025-04-09 00:00:00+00'::timestamptz, '2025-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$가슴 수술 후 모유수유나 유방암 검진에 영향이 있나요?$AAQ$, $AAA$가슴 수술 후 모유수유와 유방암 검진 영향은 **수술 방법에 따라 다릅니다**. 보형물이 들어가는 위치가 핵심인데, 대흉근 위에 올리면 유선 조직이 바로 맞닿아 있어 모유수유에 영향을 줄 수 있고, 맘모그램 검진 시에도 같이 눌리면서 봐야 할 부분을 못 보는 경우가 있어요.

반면 **근육 안쪽에 보형물을 넣으면 모유수유 때 장벽이 돼서 전혀 영향이 없고**, 검진할 때도 영향을 주지 않습니다. 그래서 대한민국 여성들은 90% 이상 근육 안쪽으로 수술하는 편이에요. 다만 단점도 있는데, 근육 밑에 넣어 수술 후 근육에 영향을 받고 통증도 조금 더 있는 편입니다. 한국 여성분들은 근육 위 조직이 별로 없어 근육 위에 넣으면 보형물 티가 나고 밥그릇 엎어놓은 모양이 되기 쉬워, 안전성과 모양 면에서 근육 안쪽 삽입이 좋습니다.$AAA$, array['모유수유', '유방암검진', '대흉근', '보형물위치', '맘모그램']::text[], 2025, 'i3IbyFQnb1Q-3', 'https://youtu.be/i3IbyFQnb1Q?t=413s', null, '2025-04-09 00:00:00+00'::timestamptz, '2025-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$가슴 수술은 보통 몇 살에 받나요?$AAQ$, $AAA$가슴 수술 연령대는 점점 어려지고 있고, 동시에 더 많은 연령대로도 확장되고 있어요. 예전에는 주 연령대가 30세 초반이었지만, **요즘에는 수능 끝나고 오는 학생들도 있을 정도로 어려졌습니다**. 예전엔 수능 끝나면 쌍커풀이나 코 수술을 하러 왔다면, 이제는 가슴 수술을 하러 오는 친구들이 늘어났어요.

반대편 끝에서도 변화가 있는데, **예전에는 50대 중반 이후 환자분을 보기 어려웠지만 이제 60대 중반까지 자연스럽게 연령대가 늘어났어요**. 양극단이 동시에 확장되고 있는 셈입니다. 70대 환자분도 가끔 계시지만, 70대는 보형물을 넣으려는 분보다 빼려고 오시는 분의 비중이 조금 더 높아요. 또한 한 달에 100~150건 정도 수술을 진행하는 전문의도 있을 만큼 가슴 수술 수요는 꾸준한 편입니다.$AAA$, array['가슴수술연령', '수능후수술', '60대수술', '수술트렌드', '양극화']::text[], 2025, 'i3IbyFQnb1Q-4', 'https://youtu.be/i3IbyFQnb1Q?t=355s', null, '2025-04-09 00:00:00+00'::timestamptz, '2025-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$윤곽 보톡스는 어떻게 얼굴 사이즈를 줄이나요?$AAQ$, $AAA$윤곽 보톡스는 **부피가 커진 근육의 사이즈를 줄여 얼굴 윤곽을 잡아주는 시술입니다**. 음식을 씹거나 표정을 지을 때 많이 쓰이는 관자놀이와 턱 근육이 발달해 부피가 커지면 얼굴이 넙데데하고 커 보이는데, 이 근육을 줄여주면 큰 변화를 볼 수 있어요. 거울을 보고 이를 앙 물어보면 움직이는 근육들이 윤곽을 좌우합니다.

이마가 굴곡지고 살짝 꺼져 보이는 분은 안에서 잡아당기는 근육 때문인데, **그 부분에 보톡스를 놓으면 잡아당기는 힘이 풀어지면서 마치 필러 맞은 것처럼 이마가 둥글게 볼륨이 살아나요**. 또 스킨 보톡스라고 해서 전체 피부층에 보톡스를 얇게·고르게·넓게 주사하는 방식도 있는데, 모공을 작아지게 하고 모공 처짐을 개선해 피부결을 좋아 보이게 해요. 측두근 보톡스를 함께 맞으면 얼굴 부피가 더 줄어드는 효과가 있습니다.$AAA$, array['윤곽보톡스', '측두근', '교근', '이마볼륨', '스킨보톡스']::text[], 2025, 'Y3eMje8kgCQ-1', 'https://youtu.be/Y3eMje8kgCQ?t=120s', null, '2025-04-11 00:00:00+00'::timestamptz, '2025-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$윤곽 보톡스 효과는 얼마나 지속되나요?$AAQ$, $AAA$윤곽 보톡스는 **시술 후 2주차부터 효과가 나타나기 시작해 3~4개월 정도 지속됩니다**. 보톡스 자체가 급격하게 얼굴 부피를 줄이는 게 아니라 서서히 자연스럽게 변화를 일으키는 시술이기 때문이에요. 그래서 시술 직후 바로 드라마틱한 변화를 기대하기보다 자연스러운 변화를 원하는 분에게 잘 맞습니다.

흥미로운 점은 꾸준히 맞을수록 효과가 더 오래간다는 것입니다. **꾸준히 맞다 보면 얼굴 면적이 줄어들면서 점점 입체적인 얼굴로 변하고 근육이 작아져 효과가 더 오래 지속되기도 해요**. 그래서 주기적으로 시술받는 게 좋습니다. 또 윤곽 보톡스는 사람의 얼굴형에 맞게 디자인할 수 있다는 게 큰 장점이에요. 둥근형·긴형·땅콩형 등 얼굴 형태와 어느 근육이 발달했는지·어디에 볼륨이 필요한지를 고려해 꼼꼼하게 커스터마이징할 수 있고, 울쎄라보다 훨씬 저렴합니다.$AAA$, array['보톡스지속기간', '효과기간', '재시술', '윤곽디자인', '맞춤시술']::text[], 2025, 'Y3eMje8kgCQ-2', 'https://youtu.be/Y3eMje8kgCQ?t=300s', null, '2025-04-11 00:00:00+00'::timestamptz, '2025-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$윤곽 보톡스 부작용은 어떤 게 있나요?$AAQ$, $AAA$윤곽 보톡스는 주사 시술이라 시술 후 **멍이나 붓기가 생길 수 있는데 대부분 일주일 이내로 사라져요**. 아주 드물게 눈이 처지거나 씹는 힘이 약해지는 경우가 있고, 보톡스가 확산되면서 입술 모양이 약간 비대칭으로 보이는 경우도 있어요. 다만 이런 증상도 시간이 지나면 원래대로 돌아오니 너무 걱정하지 않으셔도 됩니다.

중요한 주의사항으로 **시술 후 4~6시간 동안은 해당 부위를 누르거나 마사지하면 안 돼요**. 보톡스가 다른 곳으로 퍼질 수 있기 때문입니다. 또 **24시간 동안은 과격한 운동·사우나·뜨거운 목욕을 피해야 하는데** 열에 의해 효과가 빨리 떨어질 수 있어서예요. 처음 맞는 분 중에는 이마 보톡스 후 무거워서 눈을 뜨기 힘들다는 분이 있는데, 이는 평소 이마로 눈을 뜨는 습관 때문이며 눈을 부릅뜨는 연습으로 눈 근육을 키워주면 좋아요.$AAA$, array['보톡스부작용', '보톡스주의사항', '확산', '운동제한', '사우나']::text[], 2025, 'Y3eMje8kgCQ-3', 'https://youtu.be/Y3eMje8kgCQ?t=330s', null, '2025-04-11 00:00:00+00'::timestamptz, '2025-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$윤곽 보톡스는 통증이 심한가요?$AAQ$, $AAA$윤곽 보톡스는 주사 바늘로 찌르는 통증은 있지만 **마취 연고를 잘 바르면 생각보다 많이 아프지 않습니다**. 통증에 약한 분도 마취크림을 10분 정도 바르고 받으면 그렇게 아픈 건 많이 못 느낀다고 해요. 눈가가 원래 좀 아픈 부위인데도 견딜 만한 정도예요.

또 일반 보톡스와 윤곽 보톡스의 주사 방식이 달라 통증 양상도 다릅니다. 일반 보톡스는 근육에 주사하지만, 윤곽 보톡스 중 스킨 보톡스 방식은 **제일 바깥층인 피부에 얇게·고르게·넓게 주사**해요. 또 이를 앙 물어도 음식을 못 씹게 되는 건 아닌데, 보톡스로 근육을 줄여놨지만 아예 못 쓰게 하는 게 아니라 과하게 수축·긴장된 근육을 풀어주는 정도이기 때문입니다. 오히려 관자놀이 근육에 보톡스를 맞으면 편두통이 정말 많이 좋아져 미국 FDA에서 승인받기도 했어요.$AAA$, array['보톡스통증', '마취연고', '편두통', 'FDA승인', '스킨보톡스']::text[], 2025, 'Y3eMje8kgCQ-4', 'https://youtu.be/Y3eMje8kgCQ?t=216s', null, '2025-04-11 00:00:00+00'::timestamptz, '2025-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목 주름은 집에서 어떻게 관리하나요?$AAQ$, $AAA$목 주름은 집에서 **목 운동·기초 제품 바르기·선크림 사용 세 가지가 기본이에요**. 첫째, 아침에 침대에 앉아 2~3분 정도 목 스트레칭을 하는데, 고개를 천천히 뒤로 젖혀 10초씩 10번 하고 좌우로 천천히 돌리고 어깨를 으쓱 올렸다 내리는 동작을 합니다. 목 근육이 위축되면 주름이 생기기 때문에 근육을 강화해 피부를 지지하는 것이 중요해요.

둘째, **얼굴에 바르는 기초 제품을 목에도 똑같이 발라야 해요**. 만약 한 가지만 골라야 한다면 레티날·레티놀 같은 레티노이드 계열이 피부 노화에 확실한 효과를 냅니다. 다만 목 피부는 얼굴보다 얇고 민감해 자극감 있는 성분은 천천히 늘려야 해요. 셋째, 선크림은 턱 밑부터 시작해 목 전체와 쇄골까지 발라야 합니다. 자외선A는 창문도 통과하기 때문에 실내에서도 노화를 일으키므로 꼭 꼼꼼하게 발라야 해요.$AAA$, array['목주름홈케어', '목스트레칭', '레티놀', '목선크림', '예방']::text[], 2025, 'vnl-6pf7HJY-1', 'https://youtu.be/vnl-6pf7HJY?t=46s', null, '2025-04-15 00:00:00+00'::timestamptz, '2025-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목 가로 주름과 세로 주름은 어떤 시술이 효과적인가요?$AAQ$, $AAA$목 가로 주름에는 히알루론산 필러, 세로 주름에는 보톡스가 효과적입니다. **가로 주름은 패인 진피층에 필러를 직접 주입해** 빈 공간을 메워주는 방식인데, 시술 직후 바로 패여있던 주름이 개선되는 즉각적인 효과가 있어요. 깊이 패인 가로 주름에 필러가 정답인 이유입니다.

반면 세로 주름은 목을 빼고 '으' 자세를 했을 때 서는 근육으로 인해 생기는데, **이 근육에 보톡스를 놓으면 근육이 이완되면서 주름이 펴지는 효과가 있어요**. 나이가 들수록 피부 탄력이 떨어져 잘 보이는 주름이에요. 또 울쎄라·써마지 같은 리프팅도 목에 받을 수 있는데, 리프팅만 하는 것보다 스킨부스터와 함께 하는 게 효과나 유지력이 좋아요. 40대 이상이라면 리프팅과 함께 스킨부스터·필러를 복합 시행하면 더 좋은 효과를 볼 수 있습니다.$AAA$, array['가로주름', '세로주름', '히알루론산필러', '목보톡스', '복합시술']::text[], 2025, 'vnl-6pf7HJY-2', 'https://youtu.be/vnl-6pf7HJY?t=472s', null, '2025-04-15 00:00:00+00'::timestamptz, '2025-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목 스킨부스터는 어떤 효과가 있나요?$AAQ$, $AAA$목 스킨부스터는 **히알루론산이나 다양한 영양 성분을 피부 속에 주입해 탄력을 높이고 잔주름을 개선하는 시술입니다**. 피부 자체에 영양분을 직접 공급해 자글거리는 주름을 줄여줘요. 비타란이라는 스킨부스터가 효과가 좋은데, 시술 후 목을 움직일 때 보이던 자글거리는 주름이 많이 없어지고 피부가 탱탱해진다고 합니다.

특히 목은 한 땀 한 땀 손주사로 하는 것보다 기계를 이용하는 게 더 좋아요. **목 피부가 워낙 얇아 손주사로 하면 멍이 잘 들기 때문에**, 여러 기계를 사용하면 멍도 덜 들고 덜 아프며 넓은 부위에 고르게 주사할 수 있습니다. 미세한 바늘이 여러 개 달린 기계를 이용하면 자글자글한 주름에 골고루 주입돼 효과가 더 좋아요. 피부 탄력이 떨어져 근본적 개선이 필요하다면 콜라겐·엘라스틴·프로테오글리칸 생성을 촉진하는 레디어스도 권합니다.$AAA$, array['목스킨부스터', '비타란', '레디어스', '기계주입', '히알루론산']::text[], 2025, 'vnl-6pf7HJY-3', 'https://youtu.be/vnl-6pf7HJY?t=389s', null, '2025-04-15 00:00:00+00'::timestamptz, '2025-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목 주름은 베개와 자세에 영향을 받나요?$AAQ$, $AAA$베개와 자세는 목 주름 형성에 매우 큰 영향을 줍니다. **하루에 적어도 6시간 이상을 잠을 자면서 보내기 때문에**, 높은 베개를 베고 자거나 잘못된 자세로 자서 그 시간 동안 목에 주름이 가 있으면 당연히 주름이 깊어져요. 그래서 베개는 너무 높지 않고 낮은 걸 사용하고, 천장을 똑바로 보고 누워서 자는 게 좋아요.

평소 자세도 마찬가지로 중요합니다. **요즘 핸드폰이나 컴퓨터 사용으로 고개를 거북목처럼 숙이게 되는데**, 컴퓨터·핸드폰 높이를 맞춰 목이 앞으로 숙여지지 않게 들고 있을 수 있도록 해야 해요. 일하면서 중간중간 목 스트레칭을 해주는 것도 도움이 됩니다. 또 음식도 영향을 주는데, 당이 콜라겐을 파괴하는 당화 반응을 일으키기 때문에 주름을 악화시킬 수 있어요. 시럽이 든 달달한 음료를 줄이는 노력도 필요합니다.$AAA$, array['베개높이', '수면자세', '거북목', '당화반응', '생활습관']::text[], 2025, 'vnl-6pf7HJY-4', 'https://youtu.be/vnl-6pf7HJY?t=298s', null, '2025-04-15 00:00:00+00'::timestamptz, '2025-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈밑지방은 피부과와 성형외과 중 어디로 가야 하나요?$AAQ$, $AAA$눈밑지방의 근본적 해결은 수술이고, 수술을 원치 않는다면 피부과 필러로 해결할 수 있습니다. 피부과에서는 수술을 하지 않기 때문에 **밑에 그늘진 부위를 필러로 채워주는 방식**을 주로 쓰는데, 수술을 원하지 않거나 심하지 않은 분들은 필러로도 만족하시는 경우가 많아요.

반면 성형외과에서는 옵션이 더 다양합니다. **뼈 있는 데까지 들어가 눈밑고랑인대 아래 부위의 여러 연부조직을 한 번에 해결**해 줄 수 있어요. 안에 지방이 많다면 물리적으로 빼거나 재배치해주는 방법이 있고, 환자가 수술해서라도 해결하고 싶은지 또는 회복 기간 없이 빠르게 가고 싶은지에 따라 여러 방법으로 수술을 진행해요. 그래서 눈밑지방이 심하고 근본적 해결을 원한다면 성형외과, 가벼운 정도라면 피부과 필러가 적합합니다.$AAA$, array['눈밑지방', '눈밑필러', '피부과성형외과', '지방재배치', '다크서클']::text[], 2025, 'rxTU-9N3OCE-1', 'https://youtu.be/rxTU-9N3OCE?t=37s', null, '2025-04-16 00:00:00+00'::timestamptz, '2025-04-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$처진 눈은 어떤 시술로 해결하나요?$AAQ$, $AAA$처진 눈은 원인에 따라 시술이 달라집니다. 피부과에서는 주로 **아이써마지나 프락셀 레이저로 피부에 열을 줘 콜라겐을 재생시켜 탄력을 좋아지게** 해요. 30~40대에게는 매우 좋지만, 연세가 많아 피부가 많이 처졌거나 눈꺼풀이 두꺼우면 효과가 한정적입니다.

성형외과에서는 **눈썹과 이마를 하나의 유닛으로 보고 원인에 맞게 다른 수술을 진행해요**. 눈썹과 눈 사이 거리가 가까우면 상안검 수술, 거리가 멀면 눈썹 밑 절개로 거리를 줄여줍니다. 눈썹이 내려와 처진 거라면 눈썹을 끌어올리는 이마 거상술을 같이 하기도 해요. 눈 위 구조는 눈 밑과 거울처럼 같아 피부·지방·인대 조직이 같이 있어, 피부가 많이 처지면 절제하지만 안쪽 지방이 꺼지면 채워주고 인대가 늘어나 있으면 다시 복원시켜 주는 수술을 합니다.$AAA$, array['처진눈', '아이써마지', '상안검수술', '이마거상술', '눈썹']::text[], 2025, 'rxTU-9N3OCE-2', 'https://youtu.be/rxTU-9N3OCE?t=124s', null, '2025-04-16 00:00:00+00'::timestamptz, '2025-04-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름은 어떻게 치료하나요?$AAQ$, $AAA$팔자주름 치료는 채우는 방법과 당기는 방법 두 가지로 접근합니다. 피부과에서는 **필러나 스컬트라로 채우거나 처진 살을 울쎄라로 올려주고 팔자 부위를 녹여주는 주사**를 사용해요. 살이 처져서 팔자주름이 되는 경우가 있어 그럴 때는 위로 올려주는 방식이 필요합니다.

성형외과에서는 채우는 거랑 당기는 걸 같이 접근하는데, **귀 앞이나 눈 밑을 절개해 밑으로 내려간 조직을 위로 끌어올려 고정하는 중안면 거상술**을 많이 합니다. 또 채워주는 경우에는 수술대에 누워 필러 맞는 걸 좋아하지 않는 분이 많아 허벅지나 배에서 지방을 뽑아 같이 넣어줘요. 팔자주름을 만들고 있는 내려간 조직을 끌어올려 보존해주기 때문에 근본을 해결하는 느낌이지만, 근본을 건드리는 만큼 회복 기간이 비교적 길다는 단점이 있습니다.$AAA$, array['팔자주름', '중안면거상술', '스컬트라', '지방이식', '필러']::text[], 2025, 'rxTU-9N3OCE-3', 'https://youtu.be/rxTU-9N3OCE?t=327s', null, '2025-04-16 00:00:00+00'::timestamptz, '2025-04-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이마 깊은 주름은 어떻게 펴나요?$AAQ$, $AAA$이마 깊은 주름은 보톡스로 안 펴지기 때문에 **필러나 쥬브젠 같은 기계를 함께 활용합니다**. 보톡스는 표정으로 생기는 주름에는 효과적이지만, 이미 깊이 패인 주름에는 한계가 있어요. 그래서 일단 보톡스를 하고 깊은 주름에는 필러를 많이 사용합니다.

요즘에는 **필러랑 이산화탄소 가스를 조금씩 미세하게 분사해주는 쥬브젠** 같은 기계도 활용해요. 그냥 필러로 하는 것보다 훨씬 더 잘 차오른다고 합니다. 목 가로 주름도 비슷한 원리로 접근하는데, 성형외과에서 아무리 당겨도 가로 주름이 해결되지 않을 때 피부과에서는 주름 안에 직접 히알루론산 필러를 채워 간단하게 좋아지게 해요. 어렸을 때부터 유전적으로 목 주름이 깊은 분들은 나이가 들면 더 깊어지므로 필러로 채워주면 많이 개선될 수 있습니다.$AAA$, array['이마주름', '쥬브젠', '이산화탄소', '필러', '깊은주름']::text[], 2025, 'rxTU-9N3OCE-4', 'https://youtu.be/rxTU-9N3OCE?t=478s', null, '2025-04-16 00:00:00+00'::timestamptz, '2025-04-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름은 왜 생기고 홈케어로 어떻게 줄일 수 있나요?$AAQ$, $AAA$여드름은 모공 안에 기름 덩어리가 끼면서 생기기 때문에, 이중 세안과 제형 선택만 잘해도 호전될 수 있습니다. 밑에서 만들어진 피지든, 위에서 발라 낀 유분이든 결국 모공이 막혀 발생하는 구조예요. 그래서 기름은 기름으로 씻는 1차 클렌징이 핵심입니다.

클렌징 오일·밀크·크림으로 먼저 유분을 녹여 분해한 뒤 물로 헹구고, 마지막에 폼클렌징으로 2차 세안을 마무리합니다. 클렌징 워터만으로는 **기름이 잘 안 날아가** 모공 속까지 비우기 어려워요. 바르는 단계에서도 지성 피부는 안에서 기름을 만들어내므로 **오일리한 제품을 덧바르면 모공을 이중으로 막게 되어** 산뜻한 제형을 선택해야 합니다. 건성처럼 유분이 적은 피부는 꾸덕한 제형도 큰 트러블 없이 쓸 수 있다는 차이가 있습니다.$AAA$, array['여드름원인', '이중세안', '클렌징오일', '지성피부제형', '홈케어']::text[], 2025, 'vmI7WO35EeM-1', 'https://youtu.be/vmI7WO35EeM?t=75s', null, '2025-04-22 00:00:00+00'::timestamptz, '2025-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름은 홈케어로 펴질 수 있나요?$AAQ$, $AAA$팔자주름은 홈케어만으로는 펴기 어렵고, 잔주름 위주의 개선이 현실적인 목표입니다. 팔자주름·불독살·마리오네트 주름처럼 깊은 주름은 피부뿐 아니라 그 밑의 지방·근육·뼈가 한꺼번에 줄고 처지면서 만들어지기 때문이에요. 뼈의 부피까지 줄어드는 구조적 변화라 표면 케어로는 한계가 있습니다.

다만 광대 근육을 단련하는 '은' 발음 운동처럼 **얼굴 근육을 꾸준히 사용하면 처짐을 어느 정도 끌어올릴 수** 있습니다. 힙업처럼 시간이 오래 걸리는 변화이지만, 잔주름은 홈케어로 충분히 다룰 수 있어요. 깊은 주름에 좌절하기보다 **잔주름 개선과 얼굴 근육 운동을 병행하는 접근**이 현실적입니다. 깊은 주름까지 펴고 싶다면 시술적 접근이 필요하다는 점은 자연스럽게 받아들이는 게 좋습니다.$AAA$, array['팔자주름', '홈케어한계', '얼굴근육운동', '잔주름', '노화구조']::text[], 2025, 'vmI7WO35EeM-2', 'https://youtu.be/vmI7WO35EeM?t=218s', null, '2025-04-22 00:00:00+00'::timestamptz, '2025-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀은 어떤 원리로 잔주름을 개선하나요?$AAQ$, $AAA$레티놀은 느려진 각질 턴오버 주기를 다시 끌어올려 잔주름과 탄력을 개선합니다. 피부는 원래 한 달 주기로 죽은 각질을 벗기고 새살을 만들지만, 나이가 들면 이 주기가 점차 느려져요. 그 결과 죽은 각질과 노화 세포가 쌓여 잔주름과 재생 지연이 생깁니다.

레티놀을 바르면 **턴오버 속도를 다시 돌려주어** 잔주름이 개선되고 탄력도 회복돼요. 다만 농도 선택이 중요해서, 처음 쓰는 분은 0.2% 같은 저용량부터 시작해 다음 날 붉어짐이 없는지 확인하며 단계적으로 올려야 합니다. 1%처럼 고농도를 처음부터 쓰면 자극이 클 수 있어 권하지 않아요. 만약 각질이 심하게 일어나면 **농도를 더 낮추거나 다른 보습크림과 섞어서 발라주셔야 되기 때문에** 사용감을 살피며 조절합니다.$AAA$, array['레티놀원리', '각질턴오버', '잔주름개선', '저용량시작', '콜라겐재생']::text[], 2025, 'vmI7WO35EeM-3', 'https://youtu.be/vmI7WO35EeM?t=332s', null, '2025-04-22 00:00:00+00'::timestamptz, '2025-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$각질 제거는 모든 피부에 해도 괜찮나요?$AAQ$, $AAA$각질 제거는 지성·여드름성 피부에만 도움이 되고, 건성·민감성 피부에서는 오히려 피부 장벽을 무너뜨립니다. 우리 피부는 만리장성처럼 외부 자극을 막고 안의 수분이 빠져나가지 않게 해주는데, 인위적 각질 제거는 이 장벽을 계속 깨뜨리는 행위거든요. 장벽이 무너지면 시뻘게지고 트러블이 잡히지 않게 됩니다.

지성 피부는 각질과 피지가 많아 이중 세안만으로는 모공 속이 다 비워지지 않는데, 그럴 때 **각질 제거를 한 번씩 해주면 훨씬 피부가 좋아지지**라고 표현될 만큼 효과가 분명합니다. 다만 빈도는 하루 한 번이 아니라 **일주일에 1-2회 그렇게 해주시면 돼요**처럼 절제가 필요해요. 닦토나 패드도 마찬가지로 건성·민감 피부에서는 굳이 할 필요가 없고, 지성 피부도 살살 닦아주는 정도가 적절합니다.$AAA$, array['각질제거', '피부장벽', '지성피부', '닦토', '주1-2회']::text[], 2025, 'vmI7WO35EeM-4', 'https://youtu.be/vmI7WO35EeM?t=448s', null, '2025-04-22 00:00:00+00'::timestamptz, '2025-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$성형수술이 정말 인생을 바꿀 수 있나요?$AAQ$, $AAA$성형수술 후 환자분들이 외적·내적으로 자신감을 회복하며 변화하는 경우가 분명히 있습니다. 가슴 성형을 받은 임직원분들의 경우 수술 전에는 움츠러들어 있는 경향이 있다가, 수술 후에는 본인을 드러내고 과감해져 MBTI가 I에서 E로 바뀌었나 싶을 정도로 캐릭터가 변하는 모습이 관찰된다고 합니다.

변화는 마음속에만 머무르지 않고 외적으로도 드러나, **눈빛과 말투, 옷차림까지 달라지는 변화**가 따라옵니다. 외적 콤플렉스 때문에 집에만 틀어박혀 있던 분이 사람 만나는 걸 즐기게 되는 식이에요. 피부과 시술에서도 자신감이 없던 부분을 해결해드리면 객관적인 차이는 크지 않더라도 **자신감이나 사람을 대면하는 태도에서 달라지는 모습**이 보입니다. 시술을 받고 해외 방송에 나갔을 때 "왜 이렇게 젊어 보여?"라는 반응을 받은 경험이 대표적인 예시입니다.$AAA$, array['성형효과', '자존감변화', '콤플렉스개선', '가슴성형사례', '울쎄라']::text[], 2025, 'gn10PBM_WjY-1', 'https://youtu.be/gn10PBM_WjY?t=192s', null, '2025-04-23 00:00:00+00'::timestamptz, '2025-04-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$성형수술 받을 때 가장 중요한 기준은 무엇인가요?$AAQ$, $AAA$성형수술에서 가장 중요한 기준은 '남들처럼 되려고 하지 않는 것'입니다. 진료실에서 많은 환자분들이 연예인 사진을 가져와 누구처럼 되게 해달라고 요청하는데, 그 모습이 본인에게 어울리지 않거나 골격상 불가능할 수도 있어 결과적으로 만족이 어렵습니다. 화려한 느낌이 안 나오면 굉장히 실망하는 분들이 많거든요.

원장님 본인도 40대 중반에 **매몰법으로 찝어달라고 했거든요**라며 자기 주문대로 수술을 받았다가 겹쌍커풀이 생긴 경험을 공유합니다. 매몰법이 맞지 않는 눈이었지만 전문가 의견을 무시한 결과 위가 꺼지면서 라인이 하나 더 생겼습니다. 그래서 **사람들마다 맞는 수술 방법과 적합한 라인이 있는데** 그걸 무시하면 결과가 어그러질 수 있어요. 결국 외모 콤플렉스를 본인 기준으로 개선하는 건 좋지만, 타인을 따라하려는 마음은 수술 결과와 본인 만족도를 모두 해칠 수 있다는 점이 핵심입니다.$AAA$, array['성형수술기준', '전문가의견', '매몰법실패', '겹쌍커풀', '남처럼되지말기']::text[], 2025, 'gn10PBM_WjY-2', 'https://youtu.be/gn10PBM_WjY?t=300s', null, '2025-04-23 00:00:00+00'::timestamptz, '2025-04-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$예전 강남미인도는 왜 생겼고 지금은 어떻게 달라졌나요?$AAQ$, $AAA$예전에는 '눈·코·지방이식'을 묶은 세트 메뉴식 수술이 흔해 결과가 비슷비슷한 강남미인도가 만들어졌습니다. 그때는 환자분이 어떤 눈매를 원하는지 상담하기보다, 눈 8mm·코에 실리콘 3mm·지방이식 15cc 같은 식으로 정형화된 수치를 적용했기 때문이에요. 메뉴판처럼 정해진 조합이 그대로 시술된 셈입니다.

그러다 보니 강남역이나 압구정에 가면 **비슷비슷하게 생긴 분들이 많이 보였던** 시기가 실제로 있었습니다. 지금은 이런 트렌드에서 벗어나, 눈은 중·고등학교 때, 코는 수능 끝나고, 지방이식은 다이어트 후 볼륨 보강이 필요할 때처럼 **그때그때 필요한 수술을 따로따로 진행하는 방향**으로 바뀌었어요. 한 번에 묶지 않고 시기와 목적에 맞춰 분리해 받는 흐름이 자리잡으면서 개별 얼굴 특징을 살리는 방향으로 변화했다는 설명입니다.$AAA$, array['강남미인도', '세트수술', '성형트렌드변화', '단계별성형', '개인맞춤']::text[], 2025, 'gn10PBM_WjY-3', 'https://youtu.be/gn10PBM_WjY?t=70s', null, '2025-04-23 00:00:00+00'::timestamptz, '2025-04-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$성공한 사람들의 얼굴에는 공통된 특징이 있나요?$AAQ$, $AAA$성형외과 전문의가 진료실에서 관찰한 바로는 성공한 분들의 얼굴에는 두 가지 표정이 공존합니다. 가만히 계실 때는 화가 나 보이고, 사람을 만나 얘기를 나눌 때는 굉장히 웃는 상태로 바뀌는 식이에요. 두 표정이 한 얼굴에서 공존하는 경우가 일반적으로는 흔치 않습니다.

그런데 **두 개가 한 얼굴에서 공존하기가 굉장히 어려운데** 그게 정말로 같은 사람에게 동시에 보인다는 점이 인상적입니다. 평소 기본 표정과 대화 시 표정이 뚜렷이 분리되어 있다는 의미로, 진지함과 따뜻함을 함께 가진 인상이라 할 수 있어요. 다만 자막에서 이 관찰은 외모적 정의가 아니라 표정 패턴에 대한 임상적 인상에 가깝습니다. 그래서 본인의 표정이 어떻게 보이는지를 점검해보는 가벼운 관전 포인트로 받아들이면 좋습니다.$AAA$, array['성공얼굴특징', '표정공존', '성형외과관찰', '기본표정', '대화표정']::text[], 2025, 'gn10PBM_WjY-4', 'https://youtu.be/gn10PBM_WjY?t=52s', null, '2025-04-23 00:00:00+00'::timestamptz, '2025-04-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림은 모든 사람이 매일 발라야 하나요?$AAQ$, $AAA$선크림은 자외선 노출이 거의 없는 분이라면 매일 바르지 않아도 됩니다. 출퇴근이 왕복 20분 정도이고 운전으로 이동하며 하루 대부분을 실내에서 보내는 루틴이라면, 해를 볼 일이 거의 없어 매일 도포가 필수적이지 않아요. 오히려 이런 분들은 햇빛을 적절히 받는 것이 도움이 됩니다.

우리나라 사람들은 대부분 비타민D 결핍이라는 보고가 있고, 비타민D가 부족하면 **뼈가 삭고 근육이 약해지며 면역력도 떨어져요**. 그래서 선크림 안 바르고 **일주일에 3번 30분 정도 햇빛 쬐는 것을 권장**합니다. 다만 일하거나 공부하는 자리에 햇빛이 들어오는 창문이 있다면 얘기가 달라져요. UVA는 창문을 뚫고 들어와 피부 깊숙이 침투해 주름·기미·주근깨를 만들기 때문에, 창가에 계시는 분은 꼭 선크림을 발라주셔야 합니다.$AAA$, array['선크림필요성', '실내근무', '비타민D결핍', 'UVA창문투과', '주3회햇빛']::text[], 2025, '3nLgtbXkAfo-1', 'https://youtu.be/3nLgtbXkAfo?t=89s', null, '2025-04-25 00:00:00+00'::timestamptz, '2025-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 바르기 부담스러울 때 비타민C 세럼이 도움이 되나요?$AAQ$, $AAA$매일 바르기 어려운 분에게는 항산화제인 비타민C 세럼이 보완적인 선택이 됩니다. 비타민C는 자외선으로부터 피부를 보호해 노화를 예방하고, 멜라닌 색소 생성을 억제해 기미·잡티·주근깨 개선에 도움을 줍니다. 손상된 피부의 회복 속도를 빠르게 하는 역할도 합니다.

다만 비타민C는 공기·빛·열에 닿으면 금방 산화돼 효과가 떨어지고 자극이 생길 수 있어요. 그래서 비타민C 15%에 비타민E와 페룰릭애씨드가 조합된 스킨수티컬스 C E 페룰릭이 나왔고, **페룰릭애씨드는 광보호 효과를 2배 증가시키는 역할을 했다는 연구 결과**도 있습니다. 가격이 부담스럽다면 닥터디퍼런트의 CEQ 안티옥시던트 세럼이 대안인데, **비타민C와 비타민E, 페룰릭애씨드에 코엔자임 Q10까지 추가된 조합**이라 가격 부담을 덜면서 항산화 효과를 챙길 수 있어요. 자극이 없다면 동일한 조합의 다른 제품을 써도 무방합니다.$AAA$, array['비타민C세럼', '항산화', '페룰릭애씨드', 'CE페룰릭', '광보호효과']::text[], 2025, '3nLgtbXkAfo-2', 'https://youtu.be/3nLgtbXkAfo?t=222s', null, '2025-04-25 00:00:00+00'::timestamptz, '2025-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$유기자차와 무기자차 선크림은 어떻게 다른가요?$AAQ$, $AAA$유기자차는 자외선을 흡수해 열로 바꾸고, 무기자차는 피부 표면에서 자외선을 물리적으로 차단한다는 점에서 다릅니다. 유기자차 선크림은 자외선을 흡수해 열 에너지로 바꿔 공기 중으로 날려보내는 방식으로 작동하는데, 옥시벤존이나 아보벤존 같은 일부 성분이 피부염이나 알러지 반응을 일으킬 수 있어 예민한 분에게는 권하지 않습니다.

반면 무기자차 선크림은 **피부 표면에 아주 얇은 막을 만들어서 자외선을 물리적으로 차단을 시키는 방식**입니다. 자극이 적고 비교적 안정적이라 예민한 피부에도 잘 맞는 경우가 많아요. 대표 성분은 징크옥사이드와 티타늄디옥사이드이고, 단점은 바르면 굉장히 하얘지는 **백탁현상이 생기고 사용감이 좀 뻑뻑한** 점입니다. 피부염이 있어 무언가를 바르면 따갑고 붉어지는 분은 야외 활동 시에만 발라도 무방하고, 평소 실내 위주라면 굳이 매일 바를 필요가 없습니다.$AAA$, array['유기자차', '무기자차', '옥시벤존', '백탁현상', '징크옥사이드']::text[], 2025, '3nLgtbXkAfo-3', 'https://youtu.be/3nLgtbXkAfo?t=329s', null, '2025-04-25 00:00:00+00'::timestamptz, '2025-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림은 어느 정도 양을 어떻게 발라야 효과를 보나요?$AAQ$, $AAA$선크림은 500원 동전 크기인 1.2~1.5g을 두 번에 나눠 바르는 것이 효과적인 도포법입니다. 정석대로 바르면 100% 차단 효과를 위해 500원 동전 크기만큼이 필요한데 현실적으로 한 번에 바르기 부담스럽기 때문이에요. 그래서 적당량을 발라 흡수시키고 그 위에 한 번 더 바르는 레이어링 방식을 권합니다.

도포 범위도 중요한데 **얼굴뿐만 아니라 귀, 목, 눈가, 헤어라인까지 꼼꼼하게** 발라야 합니다. 얼굴은 탱탱한데 목에 주름이 자글자글하면 부자연스럽고, 귀와 목도 똑같은 피부이기 때문이에요. 시간 측면에서는 자외선 차단 성분이 자리잡도록 **외출 15-30분 전에 미리 바르고 2-3시간마다 덧바르는 것이 좋습니다**. 한 번 더 챙겨야 할 부분은 지우는 과정으로, 선크림은 한 번에 안 닦여 이중 세안이 부담스럽다면 클렌징 한 종류만으로도 잘 지워지는 이지워시 타입을 선택하면 도움이 됩니다.$AAA$, array['선크림도포량', '레이어링', '목귀헤어라인', '덧바르기', '이지워시']::text[], 2025, '3nLgtbXkAfo-4', 'https://youtu.be/3nLgtbXkAfo?t=441s', null, '2025-04-25 00:00:00+00'::timestamptz, '2025-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스는 일반 주름 보톡스와 어떻게 다른가요?$AAQ$, $AAA$스킨보톡스는 근육이 아닌 피부 얕은 층에 고르게 깔아주는 방식이라, 일반 주름 보톡스와 작용 위치와 결과가 다릅니다. 이마·미간 보톡스는 근육에 직접 주사해 근육의 힘을 10에서 0으로 떨어뜨려 강하게 작용하지만, 부모님 세대는 이미 근육이 무겁고 눈꺼풀이 처지기 시작해 어색해 보이거나 화난 인상을 줄 수 있어요.

반면 스킨보톡스는 **피부의 근육층이 아니라 얕은 층에 고르게 깔아주다 보니** 자글자글한 잔주름이 전체적으로 펴지면서 자연스러우며 광까지 나는 결과가 만들어집니다. 효과는 **3-4일 내에 바로 나타나고 3-4개월 유지되어**, 같은 간격으로 재시술하면 좋습니다. 가격은 눈가·미간·이마 같은 부위 기준으로 보통 2-30만 원대에서 끊겨 가성비 입문용으로 적합합니다. 다만 시술 직후 2-3일은 약간 울룩불룩하게 보일 수 있고, 한두 군데 멍이 들어 일주일 정도 티가 날 수 있다는 점을 감안하세요.$AAA$, array['스킨보톡스', '주름보톡스비교', '피부얕은층', '3-4개월유지', '어머님시술']::text[], 2025, 'mTr0u2XmxWo-1', 'https://youtu.be/mTr0u2XmxWo?t=68s', null, '2025-04-30 00:00:00+00'::timestamptz, '2025-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지와 울쎄라는 부모님 첫 시술로 권하지 않는 이유가 뭔가요?$AAQ$, $AAA$써마지와 울쎄라는 한 번 받는다고 즉각적인 변화가 보이지 않아 부모님 첫 시술로는 권하지 않습니다. 부모님들이 피부과를 처음 오시면 비용 걱정이 크고, 처음 받은 시술에서 티가 나줘야 만족도가 생기는데, 이 두 시술은 첫 회 효과 체감이 크지 않기 때문이에요.

써마지는 가격이 비싼 데 비해 **축적되어야지 효과가 보이는** 구조라 첫 시술에서는 만족도가 떨어집니다. 울쎄라 역시 부모님 세대의 처짐을 한 번에 잡아주기 어려워, 처음 받았을 때 변화가 확 보이지 않아요. 그래서 "피부과 한번 가봤는데 비싸고 효과 없더라"는 인상으로 이어질 수 있습니다. 첫 시술은 즉각적인 변화가 보여야 입소문도 나고 재방문 동기도 생기므로, **자연스럽게 바로 티가 나는 시술이 입문용으로 더 적합**합니다. 처진 부위는 채워주는 접근이 단번에 리프팅 효과를 보여줄 수 있는 대안이 됩니다.$AAA$, array['써마지단점', '울쎄라첫시술', '축적효과', '부모님입문', '즉각효과']::text[], 2025, 'mTr0u2XmxWo-2', 'https://youtu.be/mTr0u2XmxWo?t=197s', null, '2025-04-30 00:00:00+00'::timestamptz, '2025-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스 시술은 어떤 원리로 즉각 효과와 재생 효과를 함께 만들어내나요?$AAQ$, $AAA$레디어스는 CaHA 입자가 즉각 볼륨을 만들면서 동시에 피부 세포가 콜라겐과 엘라스틴을 만들도록 자극합니다. CaHA는 머리카락보다 훨씬 더 작은 입자로 겔에 골고루 퍼져 있어, 처지고 자글자글하게 패인 부위에 주입되면 즉각적인 볼륨 효과가 단번에 나타나요.

시간이 지나 **겔은 1-2개월이면 싹 빠지지만 CaHA 입자가 남아** 피부 세포에게 콜라겐·엘라스틴·프로테오글리칸 같은 중요한 구조물을 계속 만들라고 신호를 보냅니다. 그래서 일종의 바이오 스티뮬레이터 역할을 하며 재생까지 함께 일어나요. 일반 필러는 재생 능력이 떨어지고 스컬트라나 쥬베룩 볼륨은 재생은 좋지만 즉각 효과가 약한데, **레디어스는 즉각적인 볼륨 효과가 있으면서도 재생을 계속 해 주니까** 권하기 좋은 시술입니다. 시술 후 부분적으로 멍이 들어 길게는 2주까지 갈 수 있어 중요한 행사와는 1-2주 간격을 둬야 합니다.$AAA$, array['레디어스', 'CaHA입자', '콜라겐재생', '바이오스티뮬레이터', '즉각볼륨']::text[], 2025, 'mTr0u2XmxWo-3', 'https://youtu.be/mTr0u2XmxWo?t=325s', null, '2025-04-30 00:00:00+00'::timestamptz, '2025-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$부모님 얼굴의 검버섯과 흑자는 어떻게 다르게 치료하나요?$AAQ$, $AAA$검버섯은 만져지는 형태라 물리적으로 깎아내고, 흑자는 납작하므로 딱지가 생기게 한 뒤 재생 테이프를 붙이는 방식으로 치료합니다. 검버섯은 점 제거하는 레이저로 한 번에 깎아 날려버리는 식으로 진행해 한두 번만 해도 쏙 빠지는 편이에요.

반면 **흑자는 이렇게 만져지진 않고 그냥 납작하게 갈색인** 색소로, 딱지가 생기게 만든 후 **2주 동안 재생 테이프를 붙이게** 합니다. 흑자는 시간이 지나서 한 번 더 시술이 필요한 경우도 있지만, 그 전보다는 꽤 깔끔하게 지워지는 시술이에요. 가격은 개수가 적으면 10만 원도 안 할 수 있고, 많아도 얼굴 전체 시술 패키지로 50만 원 선에서 끊깁니다. 얼굴이 지저분하게 보이는 검버섯·흑자를 정리만 해도 환하고 깨끗해 보이는 효과가 커서, 가성비가 좋은 선택지입니다. 다만 재생 테이프를 붙이는 동안 2주까지 티가 날 수 있다는 점은 고려하세요.$AAA$, array['검버섯흑자비교', '점제거레이저', '재생테이프2주', '색소시술가격', '가성비시술']::text[], 2025, 'mTr0u2XmxWo-4', 'https://youtu.be/mTr0u2XmxWo?t=242s', null, '2025-04-30 00:00:00+00'::timestamptz, '2025-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 세럼은 아침과 저녁 중 언제 발라야 하나요?$AAQ$, $AAA$비타민C는 아침에 바르고 저녁에는 레티놀을 바르는 조합이 권장됩니다. 예전에는 비타민C가 자외선과 접촉하면 산화돼 효과가 떨어지니 밤에 바르라는 얘기가 많았지만, 요즘은 아침에 바르는 쪽으로 가이드가 바뀌었어요.

이유는 비타민C가 **자외선으로 인한 피부 손상을 막아주고** 미세먼지나 환경오염 물질로부터 피부를 보호하는 역할을 하기 때문입니다. 그래서 아침에 비타민C를 바르고 그 위에 자외선 차단제까지 발라주면 가장 이상적이에요. 자외선 차단제를 같이 안 바른다고 피부가 난리 나지는 않지만 비타민C의 효과는 떨어질 수 있습니다. 둘 다 자극적일 수 있어, 매일 부담스러우면 **격일로 어느 한 날은 비타민C를 발라주시고 어느 한 날은 레티놀을 발라주시고** 퐁당퐁당으로 쓰는 것도 좋은 방법입니다. 제품은 농도와 제형을 보고 고르되, 지성은 물 같은 제형, 보습이 필요하면 꾸덕한 제형을 선택하면 됩니다.$AAA$, array['비타민C아침', '레티놀저녁', '자외선차단병행', '격일사용', '제형선택']::text[], 2025, 'kX5CCiLIxdg-1', 'https://youtu.be/kX5CCiLIxdg?t=119s', null, '2025-05-01 00:00:00+00'::timestamptz, '2025-05-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$먹는 콜라겐과 콜라겐 주사는 효과 차이가 큰가요?$AAQ$, $AAA$먹는 콜라겐보다 콜라겐 주사가 피부에 도달하는 양 면에서 가성비가 좋습니다. 먹는 콜라겐은 소화 과정을 거치며 일부는 배설로 빠지고 나머지가 여러 장기에 퍼지기 때문에, 정작 피부에 가는 양은 매우 제한적이에요. 꾸준히 오래 먹으면 도움은 되지만 드라마틱한 변화를 기대하기는 어렵습니다.

반면 **콜라겐 주사는 콜라겐이 바로 피부로 들어가** 효율이 높습니다. 비싼 먹는 제품을 오래 먹는 비용과 한 번 주사로 넣는 비용을 비교하면 주사 쪽이 가성비가 더 낫다는 설명입니다. 즉시 탱글탱글해진다고 표현하긴 어렵지만 효과 자체는 분명하다고 합니다. 다만 자막에서는 비용·횟수·종류에 대한 구체 수치를 다루지 않으므로, 본인 피부 상태와 예산에 맞춰 시술 상담 시 세부를 확인하는 것이 좋습니다. **건강식품으로의 먹는 콜라겐과 피부 직접 작용을 노리는 콜라겐 주사**는 목적이 다른 선택지로 이해하면 됩니다.$AAA$, array['먹는콜라겐', '콜라겐주사', '흡수율비교', '이너뷰티', '가성비']::text[], 2025, 'kX5CCiLIxdg-2', 'https://youtu.be/kX5CCiLIxdg?t=223s', null, '2025-05-01 00:00:00+00'::timestamptz, '2025-05-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살 크림은 예방과 치료 중 어디에 효과적인가요?$AAQ$, $AAA$튼살 크림은 튼살 예방에는 도움이 되지만 이미 생긴 튼살을 없애기는 어렵습니다. 튼살은 살이 늘어나는 속도를 피부가 따라가지 못해 갈라지면서 생기는 흔적이라, 보습과 마사지로 피부 장력을 미리 끌어올리는 예방적 접근이 가능한 거예요. 임신 중 꾸준히 발라 튼살이 거의 생기지 않은 사례도 비슷한 맥락에서 설명됩니다.

튼살 크림은 **굉장히 성분이 좋은 보습제에다가 피부 재생되는 어떠한 물질들을 각 브랜드별로 넣어놓은 거예요**라는 구성이라, 보습을 충분히 해주고 마사지를 병행하면 피부 장력 개선 효과를 기대할 수 있어요. 다만 **이미 생겨버린 튼살에는 튼살 크림 만으로 어떻게 효과를 보기에는 조금 어려울 수 있다**는 점이 분명합니다. 이런 경우 시술 영역으로 넘어가야 하는데, 예전에는 치료가 어려웠지만 요즘에는 좋은 시술이 많이 나와 튼살 치료가 가능한 상황입니다.$AAA$, array['튼살크림예방', '보습마사지', '피부장력', '임신튼살', '시술필요']::text[], 2025, 'kX5CCiLIxdg-3', 'https://youtu.be/kX5CCiLIxdg?t=327s', null, '2025-05-01 00:00:00+00'::timestamptz, '2025-05-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 타입별로 어떤 성분이 가장 잘 맞나요?$AAQ$, $AAA$피부 타입별로 권장 성분이 달라, 본인 피부에 맞춰 골라 쓰면 만족도가 높아집니다. 건성 피부는 피부 장벽을 구성하는 세라마이드를 바르면 장벽이 튼튼해지고, 지성 피부는 피지 조절에 도움을 주는 나이아신아마이드가 적합합니다.

복합성 피부는 T존이 지성이고 U존이 건성인 타입이라, **T존에는 나이아신아마이드, U존에는 세라마이드** 식으로 섞어 발라주시면 됩니다. 민감성 피부에는 판테놀이나 마데카소사이드 같은 재생 성분이 권장돼요. 여드름성 피부는 살리실산 성분이 좋은데, 이 성분이 모공에 낀 피지를 날려주는 역할을 하기 때문입니다. **살리실산이 있는 폼클렌저와 토너를 함께 써도 화장품 농도이기 때문에 큰 부담은 없습니다**. 추가로 약산성 클렌징폼이 피부 산도에 맞아 피부 건강에 더 좋으며, 약알칼리성은 세정력이 강해 극 지성이나 여드름 피부에서만 선택적으로 쓰는 편이 적절합니다.$AAA$, array['세라마이드', '나이아신아마이드', '살리실산', '복합성피부', '약산성클렌징']::text[], 2025, 'kX5CCiLIxdg-4', 'https://youtu.be/kX5CCiLIxdg?t=497s', null, '2025-05-01 00:00:00+00'::timestamptz, '2025-05-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$옷에서 나는 쩐내는 땀 때문이 아닌 건가요?$AAQ$, $AAA$옷에서 나는 쩐내의 대부분은 땀이 아니라 피지에서 비롯된 냄새입니다. 하루 종일 입었던 옷을 벗어두고 냄새를 맡으면 특히 등 부분에서 쩐내가 강하게 느껴지는데, 등에는 겨드랑이 땀이 날 일이 없기 때문에 그 냄새의 주범은 피지로 볼 수 있어요.

등은 다른 부위보다 피지 분비가 많아 냄새가 두드러집니다. 여성에게도 같은 원리로 냄새가 나는데, 과학적으로 **남성은 남성 호르몬 때문에 피지 분비가 여성보다 2배 정도 많아** 더 강한 쩐내가 나타나는 차이가 있어요. 생활습관도 큰 영향을 미치는데, 환기를 자주 안 하거나 이불·베개커버 세탁을 거의 안 하면 **피지가 묻어 있는데 그게 씻겨 나가지 않으니까 계속 냄새가 쌓이는** 구조가 됩니다. 그래서 하루 두 번 정도 창문을 열어 환기하고, 잘 씻고 빨래를 자주 하는 것이 피지 냄새 관리의 기본입니다.$AAA$, array['옷쩐내', '피지냄새', '등분비', '남성호르몬', '환기빨래']::text[], 2025, 'HFvW2-RVelc-1', 'https://youtu.be/HFvW2-RVelc?t=49s', null, '2025-05-02 00:00:00+00'::timestamptz, '2025-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$노인 특유의 냄새는 왜 생기나요?$AAQ$, $AAA$노인 냄새는 40대 중반부터 피지 성분이 바뀌면서 만들어지는 노넨알데하이드라는 물질 때문에 생깁니다. 영어로 Old Person Smell이라 부르며 과학적으로 정의된 냄새인데, 단순히 집이 오래되거나 환기를 안 해서 나는 꿉꿉한 냄새와는 근본적으로 다릅니다.

나이가 들면 **피부에서 나오는 피지의 성분이 바뀌어** 팔미톨레산이 증가하고, 이것이 몸에 쌓인 활성산소와 반응하며 노넨알데하이드를 만들어요. 젊을 때는 피부의 항산화 시스템이 활성산소를 바로바로 처리하지만, 나이가 들면 그 청소부가 일을 잘 못해 활성산소가 쌓이고 피지와 반응이 일어납니다. 다만 **75세 이상 노인들의 등에서 채취한 노넨알 농도가 개인별로 10배까지 차이가 났다는** 일본 연구가 있어, 개인 차이가 크다는 점도 함께 봐야 해요. 스트레스·흡연·당뇨가 있거나 항산화 음식을 적게 먹으면 노넨알이 더 많이 생성됩니다.$AAA$, array['노인냄새', '노넨알데하이드', '팔미톨레산', '활성산소', '40대중반']::text[], 2025, 'HFvW2-RVelc-2', 'https://youtu.be/HFvW2-RVelc?t=241s', null, '2025-05-02 00:00:00+00'::timestamptz, '2025-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$내가 나중에 노인 냄새가 날 체질인지 미리 알 수 있나요?$AAQ$, $AAA$씻은 뒤 3시간 후 팔 안쪽 오금부위를 문질러 30분 뒤 냄새를 맡는 간단한 테스트로 미리 체크해볼 수 있습니다. 일단 몸을 깨끗하게 씻고, 3시간 뒤에 팔이 접히는 오금 부위를 손가락 두 개로 10초 정도 문지른 다음 30분을 그대로 둡니다.

그리고 30분이 지난 뒤 냄새를 맡아 **마른 건초 냄새 혹은 오래된 책 냄새가 난다면** 나중에 노인 냄새가 나는 체질일 가능성이 있어요. 노넨알은 유전적 요인도 있지만 생활 습관이 굉장히 중요한데, **스트레스·흡연·항산화 음식 섭취 부족·당뇨병** 같은 요인이 있으면 노넨알이 더 많이 만들어지기 때문입니다. 즉 체질 점검은 미래 대비의 출발점일 뿐, 결과는 생활 습관에 따라 조정될 수 있어요. 테스트 결과에 너무 무겁게 반응하기보다 식습관·환기·세정 습관을 정비하는 계기로 활용하는 게 좋습니다.$AAA$, array['노넨알자가진단', '오금부위테스트', '마른건초냄새', '체질확인', '생활습관']::text[], 2025, 'HFvW2-RVelc-3', 'https://youtu.be/HFvW2-RVelc?t=365s', null, '2025-05-02 00:00:00+00'::timestamptz, '2025-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$노인 냄새를 줄이려면 평소에 어떻게 관리해야 하나요?$AAQ$, $AAA$노인 냄새 관리는 잘 씻기, 항산화 식품 섭취, 환기와 보습이라는 네 가지 축으로 정리됩니다. 가장 기본은 피지가 산화되면서 나는 냄새이므로 피지를 잘 씻어내는 것인데, 특히 귀 뒤·등·앞가슴처럼 피지가 많이 분비되는 곳을 바디클렌저로 꼼꼼히 세정하는 것이 중요해요.

식습관 측면에서는 항산화 식품을 많이 먹는 것이 핵심으로, **베리류·녹차·토마토·브로콜리** 같은 음식이 항산화 성분이 풍부합니다. 오메가3 영양제 복용도 도움이 된다고 알려져 있어요. 환기도 빠질 수 없는데, **아무리 내 몸 관리를 잘해도 냄새는 조금씩 날 수 있기 때문에** 자주 식혀줘야 합니다. 추가로 보습도 중요한데, 피부가 건조하면 피지가 더 많이 분비돼 냄새가 심해지므로 바디로션이나 바디크림을 잘 발라주세요. 일본에서는 노넨알을 중화시키는 비누나 바디워시가 발달했지만, 어떤 특정 제품보다도 피지 분비 부위를 깨끗이 씻는 것이 가장 중요합니다.$AAA$, array['노인냄새관리', '항산화식품', '오메가3', '환기보습', '피지부위세정']::text[], 2025, 'HFvW2-RVelc-4', 'https://youtu.be/HFvW2-RVelc?t=436s', null, '2025-05-02 00:00:00+00'::timestamptz, '2025-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$오래된 하얀 튼살은 홈케어로 없앨 수 있나요?$AAQ$, $AAA$하얗게 변한 오래된 튼살은 홈케어 크림이나 디바이스로는 거의 개선되지 않습니다. 튼살이 하얘졌다는 것은 이미 흉터처럼 자리를 잡은 상태라, 좋다는 크림이나 연고를 발라도, 문지르는 디바이스나 커피가루로 세게 문질러도 변화가 만들어지지 않아요.

이런 단계의 튼살은 **피부 속을 자극하거나 미세하게 찢어주는 시술적 접근**이 있어야 치료가 됩니다. 듣기에는 무서워도 효과는 굉장히 좋은 편이라, 누가 봐도 튼살이 있던 피부였더라도 멀리서 언뜻 보면 잘 보이지 않는 정도까지는 옅어질 수 있어요. 완전히 처음 피부로 돌아간다고 단정할 수는 없지만, 시술 영역에서는 분명한 개선이 가능합니다. 부위가 좁을수록 한두 번 치료로 확 없어지고, 손바닥 넓이만큼 넓은 부위는 오래 걸리고 완전히 사라지긴 어렵다는 점이 차이입니다. 본인 튼살이 신경 쓰인다면 피부과 진료로 단계를 점검하는 게 가장 빠른 길입니다.$AAA$, array['하얀튼살', '튼살홈케어한계', '흉터화', '시술필요', '튼살크기']::text[], 2025, '7Igx2xG-2Qw-1', 'https://youtu.be/7Igx2xG-2Qw?t=119s', null, '2025-05-07 00:00:00+00'::timestamptz, '2025-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯 시술은 어떤 원리로 튼살을 개선하나요?$AAQ$, $AAA$미라젯은 강한 압력으로 피부를 뚫으면서 동시에 쥬베룩 같은 약물을 정밀하게 주입해 튼살을 개선합니다. 손으로 주사하려면 얇은 튼살 부위에 일정한 깊이로 균일하게 약물을 넣기 어려운데, 미라젯은 엄청 센 압력으로 피부를 뚫고 들어가면서 미세하게 찢어주는 작용을 함께 만들어내요.

튼살은 일종의 흉터로 자세히 보면 피부가 약간 패여 있는데, 이 패인 부위를 **미세하게 밑에서 찢어주면 살이 차오르는 반응이 생기면서** 개선됩니다. 약물로는 쥬베룩을 넣어 사용하는데, **쥬베룩은 피부에서 콜라겐을 만들도록 자극을 해주는 역할**을 합니다. 살이 뜯어지며 꺼져 있던 튼살 부위에 콜라겐이 차오르며 피부가 채워지는 방식이에요. 통증은 비교적 적은 편이면서 효과는 빠르고, 회복 기간도 짧아 시술 다음 날부터 일상생활이 가능합니다. 시술 후 7-10일 정도 작은 딱지가 점처럼 생겼다 떨어지는 회복 과정을 거칩니다.$AAA$, array['미라젯', '쥬베룩', '콜라겐자극', '압력주입', '튼살시술']::text[], 2025, '7Igx2xG-2Qw-2', 'https://youtu.be/7Igx2xG-2Qw?t=263s', null, '2025-05-07 00:00:00+00'::timestamptz, '2025-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살 시술은 몇 번 받아야 변화가 보이나요?$AAQ$, $AAA$튼살 상태에 따라 다르지만 미라젯은 약 세 번 정도 치료하면 눈에 띄는 변화를 확인할 수 있습니다. 튼살이 얼마나 심한지, 넓이는 어느 정도인지, 부위가 어디인지에 따라 횟수는 달라지지만 일반적인 기준점이 세 번 정도예요.

좁은 부위 튼살은 한두 번만 해도 확 없어지는 반면, 손바닥 넓이만큼 넓은 부위는 오래 걸리고 완전히 사라지긴 어렵습니다. **미라젯은 통증이 적은 편이면서도 효과는 빠르다는 거** 그리고 회복 기간이 굉장히 짧다는 장점이 있어요. **시술하고 나서 하루만 지나도 일상생활이 가능하다는** 점이 부담을 낮추고, 회복 과정에서 7-10일 동안 점처럼 생긴 작은 딱지가 떨어지는 변화를 거칩니다. 즉 한 번의 시술로 끝나지 않는 누적적 접근이지만, 회차당 부담이 크지 않아 일상과 병행하기 쉬운 흐름입니다.$AAA$, array['미라젯횟수', '튼살3회', '회복하루', '딱지7-10일', '튼살넓이']::text[], 2025, '7Igx2xG-2Qw-3', 'https://youtu.be/7Igx2xG-2Qw?t=355s', null, '2025-05-07 00:00:00+00'::timestamptz, '2025-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$붉은 튼살은 어떻게 관리해야 하나요?$AAQ$, $AAA$붉은 튼살은 최대한 빨리 치료하는 것이 좋고, 트레티노인 성분의 투앤티 크림이 도움이 됩니다. 트레티노인은 피부 세포의 턴오버를 촉진하고 콜라겐 생성을 자극해 새로운 피부로 재생되도록 돕는 성분이에요. 다만 효과를 보려면 **적어도 3개월에서 6개월 정도는 발라야** 합니다.

바르는 방법은 자기 전에 한 번, 완두콩 절반 크기 정도를 손등에 덜어 얇게 펴 바르는 정도로 충분해요. 자극이 있을 수 있어 본인 보습제와 반반 섞어 희석해 쓰는 것도 방법이고, **처음에는 일주일에 2-3번 정도만 발랐다가 피부가 적응되면 매일 바르는 방식으로** 늘려갑니다. 중요한 주의점은 **트레티노인 성분은 임신 중에는 쓰면 안 되기 때문에** 임신 중 발견된 튼살은 출산 후에 바르기 시작해야 한다는 점이에요. 또한 붉은 튼살이라 해서 100% 완전히 사라지는 것은 아니므로, 흔적이 보이면 가까운 피부과에 가서 진료를 받는 것이 가장 좋습니다.$AAA$, array['붉은튼살', '트레티노인', '투앤티크림', '임신금기', '주2-3회시작']::text[], 2025, '7Igx2xG-2Qw-4', 'https://youtu.be/7Igx2xG-2Qw?t=384s', null, '2025-05-07 00:00:00+00'::timestamptz, '2025-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 보톡스 효과는 얼마나 지속되나요?$AAQ$, $AAA$겨드랑이 보톡스 시술은 한 번에 **4-6개월 정도** 땀 분비 억제 효과가 유지됩니다. 시술 후 일주일 정도만 지나도 땀 분비가 확실하게 억제되고, 6-8월의 한여름 시즌에 맞춰 4-5월 정도에 받으면 가장 뽀송한 컨디션으로 여름을 보낼 수 있어요.

시술 자체는 마취크림을 바르고 겨드랑이 전체에 골고루 보톡스를 주사하는 방식이며 약 1분 정도면 끝납니다. 주기적으로 받다 보면 **시간이 지날수록 땀 분비 자체가 서서히 줄어드는 효과**가 있어, 다음 시술까지의 간격이 점점 길어지기도 합니다. 심하지 않은 분들은 몇 년 맞고 나면 더 이상 시술이 필요 없어지는 경우도 있어요. 효과에는 개인차가 있을 수 있습니다.$AAA$, array['겨드랑이보톡스', '다한증시술', '땀억제', '효과지속', '재시술주기']::text[], 2025, 'OUeJq_4dlYs-1', 'https://youtu.be/OUeJq_4dlYs?t=247s', null, '2025-05-08 00:00:00+00'::timestamptz, '2025-05-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$데오드란트와 드리클로는 어떻게 다른가요?$AAQ$, $AAA$데오드란트는 땀 자체를 줄여주지 않고 땀 냄새만 줄여주는 제품인 반면, 드리클로는 **땀 분비 자체를 억제하는** 제품이라는 점에서 본질적으로 다릅니다. 데오드란트는 땀 주변 세균 번식을 억제해 냄새만 잡아주는 역할이에요.

드리클로는 알루미늄클로로하이드레이트 성분이 포함된 약국 제품으로 노스엣과 함께 약국에서 쉽게 구할 수 있어요. 사용 방법도 다른데, 그냥 바르면 안 되고 **저녁에 샤워 후 물기를 완전히 말리고 발라 자고 다음날 아침에 씻어주는 방식**으로 사용해야 합니다. 면도를 한 직후에는 자극이 될 수 있으므로 최소 하루 이상 전에 면도하고 발라야 해요. 이렇게 사용하면 하루 동안 땀이 거의 나지 않아 의상에 땀이 묻지 않는 효과를 볼 수 있습니다.$AAA$, array['데오드란트', '드리클로', '노스엣', '땀억제제', '약국템']::text[], 2025, 'OUeJq_4dlYs-2', 'https://youtu.be/OUeJq_4dlYs?t=109s', null, '2025-05-08 00:00:00+00'::timestamptz, '2025-05-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 보톡스 시술 후 주의사항이 있나요?$AAQ$, $AAA$겨드랑이 보톡스 시술 당일에는 무리한 운동이나 카페인 섭취, 사우나·찜질방은 피하시는 것이 좋고 **일상생활은 당일부터 바로 가능**합니다. 면도는 시술 하루 전날까지만 가능해요.

시술 부위에 멍이 들거나 주사 바늘 자국 같은 가벼운 부작용이 생길 수 있는데 대부분 며칠 이내에 사라집니다. 통증은 마취크림을 바르고 시술하면 거의 대부분 못 느낄 정도로 약하며, **시술시간 1분에 마취크림 바르는 시간 30분만 투자하면** 끝나요. 또한 레이저 제모와 같은 날 동시에 받는 것은 권하지 않습니다. 레이저 제모도 자극적인 시술이라서 같은 날 받기보다는 시점을 나눠 진행하는 게 좋아요. 두 시술을 병행하는 것 자체는 전혀 문제가 없습니다.$AAA$, array['보톡스주의사항', '다운타임', '시술후관리', '운동제한', '레이저제모']::text[], 2025, 'OUeJq_4dlYs-3', 'https://youtu.be/OUeJq_4dlYs?t=338s', null, '2025-05-08 00:00:00+00'::timestamptz, '2025-05-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 털은 미는 것이 땀에 더 좋은가요?$AAQ$, $AAA$겨드랑이 털은 미는 편이 더 좋습니다. **털이 많을수록 땀이 털에 묻어 있는 시간이 길어져** 세균 번식과 냄새가 심해지기 때문이에요.

털이 길면 땀이 옷에도 더 많이 묻어나기 때문에 위생적으로도 깔끔하지 않습니다. 그래서 제모나 면도를 통해 털을 제거하면 **냄새가 덜 나고 땀 자국 관리도 훨씬 깔끔해져요**. 옷의 소재도 함께 신경 쓰면 좋은데, 폴리에스터나 레이온 같은 합성 소재는 촉감은 좋지만 통풍이 안 돼서 체온이 올라가 땀이 더 나기 쉬워요. 너무 달라붙는 옷보다 약간 여유 있는 핏이 겨드랑이 땀 관리에는 더 도움이 됩니다. 면도, 옷 소재, 약국 제품을 함께 활용해 보시고 그래도 부족하면 보톡스 시술을 고려해 보세요.$AAA$, array['겨드랑이제모', '면도', '옷소재', '땀관리', '냄새']::text[], 2025, 'OUeJq_4dlYs-4', 'https://youtu.be/OUeJq_4dlYs?t=381s', null, '2025-05-08 00:00:00+00'::timestamptz, '2025-05-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 신약 옵젤루라는 어떤 효과가 있나요?$AAQ$, $AAA$옵젤루라 크림은 **JAK 억제제 계열의** 백반증 신약으로, 면역 반응을 차단해 색소를 회복시키는 약물입니다. 미국과 유럽에서 백반증 치료제로 승인되어 판매되고 있어요.

임상 연구에 따르면 12주 동안 옵젤루라만 도포해 25% 이상 개선된 반응군은 48주 시점에 **몸 전체는 평균 70%, 얼굴은 평균 91%까지 개선되었습니다**. 반면 초기 반응이 미흡했던 군에 주 3회 자외선 치료를 추가하자 48주에 몸 전체 평균 50%, 얼굴 평균 86%까지 개선됐어요. 모든 환자에게서 심각한 부작용은 관찰되지 않았습니다. 다만 옵젤루라는 아직 국내에 도입되지 않았는데요, 소규모 연구에서 프로토픽의 효과가 옵젤루라와 비슷한 수준이라는 결과가 있어 자외선 치료와 함께 연고를 꾸준히 바르는 방식이 권장됩니다.$AAA$, array['옵젤루라', '백반증신약', 'JAK억제제', '자외선치료', '프로토픽']::text[], 2025, 'X3lT-AxxxYM-1', 'https://youtu.be/X3lT-AxxxYM?t=36s', null, '2025-05-09 00:00:00+00'::timestamptz, '2025-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증은 조기 치료가 왜 중요한가요?$AAQ$, $AAA$백반증은 **발생 초기에 적극적으로 치료할수록 결과가 더 좋습니다**. 파세론 교수의 ERASE Vitiligo 연구에서 초기 환자들은 자외선 치료와 경구 스테로이드 병합에 매우 좋은 반응을 보였고, 오래된 환자들은 효과가 상대적으로 낮았어요.

조기 치료의 핵심은 **조직 상주 기억 T세포의 수와 활성도가 현저히 감소한다는** 점입니다. 이 세포는 오랫동안 피부에 남아 백반증 재발에 관여하는 면역세포로, 초기에 강력한 스테로이드 치료로 줄이면 재발도 줄일 수 있어요. 실제 진료에서도 발생 한두 달 이내에 치료를 시작한 환자 중에는 10년이 지나도 재발하지 않는 경우가 있습니다. 모든 환자들은 주 3회 자외선 치료와 함께 경구 스테로이드를 6개월간 주 2회 주말요법으로 복용했어요. 치료 결정은 환자 개인 상황과 주치의 상담을 통해 이뤄져야 합니다.$AAA$, array['백반증조기치료', '스테로이드주말요법', '자외선치료', '기억T세포', '재발예방']::text[], 2025, 'X3lT-AxxxYM-2', 'https://youtu.be/X3lT-AxxxYM?t=191s', null, '2025-05-09 00:00:00+00'::timestamptz, '2025-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 백반증의 유형은 어떻게 나뉘나요?$AAQ$, $AAA$얼굴 백반증은 발생 양상에 따라 **얼굴 중앙형, 얼굴 전체형, 이마선국한형**의 3가지 타입으로 분류됩니다. 473명의 환자 분포를 분석해 도출한 새로운 분류 체계예요.

가장 흔한 얼굴 중앙형은 **10명 중 7명에 해당하며** 이마, 눈, 코, 입 주변에 발생하고 반복적인 마찰이 원인으로 추정되어 손으로 얼굴을 만지는 습관에 주의가 필요합니다. 엑시머 레이저 반응은 비교적 좋은 편이에요. 얼굴 전체형은 양 광대 주변으로 넓게 발생하며 평균 발생 연령이 약 48세로 다소 높고, 햇빛 노출이 원인으로 보여 자외선 차단제를 열심히 바르는 것이 재발 방지에 도움이 됩니다. 이마선국한형은 이마선과 두피 경계에 집중적으로 발생하며 주로 고령층에 나타나고, 발병 초기에는 치료에 호전되지만 시간이 지난 뒤에는 반응이 좋지 않은 편이에요.$AAA$, array['얼굴백반증', '백반증분류', '얼굴중앙형', '이마선국한형', '엑시머레이저']::text[], 2025, 'X3lT-AxxxYM-3', 'https://youtu.be/X3lT-AxxxYM?t=337s', null, '2025-05-09 00:00:00+00'::timestamptz, '2025-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스 효과는 얼마나 지속되나요?$AAQ$, $AAA$스킨보톡스는 한 번 시술로 **3-4개월까지** 피지 분비 감소 효과가 지속됩니다. 보톡스가 피지샘에서 피지를 분비하는 신경전달을 차단해 피부에 고르게 깔리면 전체적으로 피지샘 분비가 확 줄어들어요.

실제 논문에서는 피지 분비가 **80%까지 감소한다는** 결과가 보고되어 있습니다. 가격은 1회 20-30만 원대로 부담이 크지 않고, 시술 즉시 효과를 체감할 수 있어 가성비가 좋은 편이에요. 7-8월의 한여름에 피지가 가장 많이 분비되므로 4-5월 정도에 한 번 받아두면 한 시즌을 뽀송하게 보낼 수 있습니다. 다만 주사로 한 땀 한 땀 놓는 방식이라 콧구멍처럼 좁은 부위까지 빠짐없이 시술하긴 어려워, T존 집중 피지 관리는 다른 시술과 병행하는 편이 좋습니다.$AAA$, array['스킨보톡스', '피지억제', '효과지속', '가성비시술', '여름대비']::text[], 2025, 'oOJeEFCMnPI-1', 'https://youtu.be/oOJeEFCMnPI?t=244s', null, '2025-05-13 00:00:00+00'::timestamptz, '2025-05-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스와 미세바늘 고주파는 어떻게 다른가요?$AAQ$, $AAA$스킨보톡스는 신경전달 차단으로 **피지 분비를 즉각적으로 줄여주는** 시술이고, 미세바늘 고주파는 피지선 자체를 파괴하면서 콜라겐 재생까지 유도하는 시술이라는 점이 다릅니다.

스킨보톡스는 한 번만 받아도 효과가 있어 가성비가 좋은 반면, 미세바늘 고주파는 한 번으로는 약하고 **세 번까지 꾸준히 받아줘야** 효과가 충분히 나옵니다. 포텐자, 버츄RF, 실펌 같은 장비가 대표적이며 논문상 피지 분비 감소 효과는 약 80%로 비슷한 수준이에요. 미세바늘 고주파는 콧구멍과 콧볼 같은 T존 깊숙한 곳까지 집중적으로 시술할 수 있다는 장점이 있어요. 그래서 한 번만 받는다면 스킨보톡스를, T존 집중 관리가 필요하면 아쿠아필로 피지를 빼낸 뒤 미세바늘 고주파로 조여주는 조합이 권장됩니다. 다만 시술 시 통증이 강해 마취크림을 45분 정도 발라야 해요.$AAA$, array['스킨보톡스비교', '미세바늘고주파', '포텐자', '버츄RF', '아쿠아필']::text[], 2025, 'oOJeEFCMnPI-2', 'https://youtu.be/oOJeEFCMnPI?t=358s', null, '2025-05-13 00:00:00+00'::timestamptz, '2025-05-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피지를 줄이려면 어떤 클렌징을 해야 하나요?$AAQ$, $AAA$피부 타입에 따라 클렌징 제품을 다르게 선택해야 합니다. 건조한 피부는 **T존에만 클렌징 오일이나 밀크로 천천히 롤링**하는 방식이 좋고, 지성 피부는 클렌징 젤이나 밀크를 추천드려요.

건성 피부가 과하게 피지를 제거하려고 하면 기존 건조 부위가 더 건조해질 수 있어요. T존 부위에만 집중해 피지를 제거하고 건조한 부위는 로션을 듬뿍 발라주는 것이 좋습니다. 지성 피부는 오일 제품이 피부에 잘 끼어 덜 씻길 수 있으니 **얼굴 전체를 클렌징 젤이나 밀크로 1차 세안한 뒤 거품이 충분한 세안제로 2차 세안**하는 방식이 권장됩니다. 봄·여름에는 모공이 잘 막히기 때문에 보습제도 겨울보다는 좀 더 산뜻한 제품으로 사용하는 게 좋아요. 다만 홈케어로 피지를 근본적으로 줄이는 데는 한계가 있어 시술 병행을 고려할 수 있습니다.$AAA$, array['클렌징방법', '피부타입별', '지성피부', '건성피부', '이중세안']::text[], 2025, 'oOJeEFCMnPI-3', 'https://youtu.be/oOJeEFCMnPI?t=100s', null, '2025-05-13 00:00:00+00'::timestamptz, '2025-05-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$골드 PTT는 피지 감소에 효과적인가요?$AAQ$, $AAA$골드 PTT는 단기적인 피지 감소 목적으로는 **권장되지 않습니다**. 다른 병원에서 3회를 받았는데도 효과가 없어 오시는 환자분이 있을 만큼 단독 시술로는 약한 편이에요.

골드 PTT는 금 성분을 액체에 흡수시켜 피부에 도포하고 충분히 침투시킨 뒤 레이저로 열 에너지를 가해 금이 피지선에만 흡수되어 파괴되는 원리입니다. 여드름 프로그램의 일부로 사용하는 데는 효용이 있지만, **단 1-2회의 시술로는 추천드리지 않아요**. 7-8월의 뽀송함을 단기에 만들고 싶다면 한계가 있다는 뜻이에요. 이번 여름을 위해 기름기를 빠르게 줄이고 싶은 분이라면 한 번에 효과가 나타나는 스킨보톡스, 또는 T존 집중 관리를 위한 미세바늘 고주파 조합이 더 적합합니다. 골드 PTT는 종합적 여드름 치료 프로그램 안에서 활용하시는 게 좋아요.$AAA$, array['골드PTT', '여드름치료', '피지선파괴', '시술효과한계', '단기효과']::text[], 2025, 'oOJeEFCMnPI-4', 'https://youtu.be/oOJeEFCMnPI?t=534s', null, '2025-05-13 00:00:00+00'::timestamptz, '2025-05-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화장품은 단계별로 다 발라야 하나요?$AAQ$, $AAA$스킨, 앰플, 세럼, 로션, 크림, 나이트 크림을 모두 바를 필요는 없습니다. 같은 라인의 제품을 다 발라도 **결국 비슷한 성분을 7번 바르는 셈**이라 큰 의미가 없어요.

추천드리는 방법은 피부 장벽을 보호하고 보습을 주는 **좋은 보습제 하나를 선택하고, 미백이 필요하면 비타민C 같은 기능성 제품을 먼저 발라주는** 두 단계예요. 세안 후 미백에 도움이 되는 비타민C를 바르고 보습제를 바르면 충분합니다. 보습을 조금 더 추가하고 싶다면 히알루론산 같은 다른 성분의 제품을 추가하는 정도는 의미가 있어요. 비싸다고 다 좋은 제품은 아니며 화장품의 성분이 본인 피부에 잘 맞는지가 가장 중요합니다. 너무 많이 바르면 다 스며들지도 못하고 얼굴에 쌓이는 느낌만 들어요.$AAA$, array['화장품단계', '보습제', '비타민C', '기능성화장품', '스킨케어루틴']::text[], 2025, 'TlOzDryC6Ck-1', 'https://youtu.be/TlOzDryC6Ck?t=183s', null, '2025-05-16 00:00:00+00'::timestamptz, '2025-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 시술을 자주 하면 피부가 얇아지나요?$AAQ$, $AAA$피부과 시술을 자주 한다고 피부가 얇아지지는 않습니다. **피부가 얇아진다기보다는 민감해진다**고 표현하는 것이 맞아요. 프락셀 같은 박피 시술은 피부를 한 꺼풀씩 벗겨내는 방식이라 이런 오해가 생긴 것 같습니다.

바닥에 굴러서 피부가 긁혀도 다시 재생되는 것처럼, **시술을 받더라도 충분한 재생 기간을 거쳐 의사의 판단에 따라 주기적으로 받으면** 피부가 얇아지는 일은 없어요. 너무 자주 하거나 과하게 할 때 민감해지는 현상이 생기는 것입니다. 오히려 고주파 시술 같은 것들은 피부가 더 건강해질 수 있어요. 레이저 시술도 어느 순간 못 받게 된다는 얘기가 있지만 사실이 아닙니다. 전문의와 상담해 본인에게 맞는 주기로 받으면 안전하게 오래 받을 수 있어요.$AAA$, array['피부과시술', '피부두께', '프락셀', '박피시술', '민감해짐']::text[], 2025, 'TlOzDryC6Ck-2', 'https://youtu.be/TlOzDryC6Ck?t=420s', null, '2025-05-16 00:00:00+00'::timestamptz, '2025-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$알로에는 보습에 정말 좋은가요?$AAQ$, $AAA$알로에는 **보습의 끝판왕은 아니며**, 일광 화상 후 진정 효과가 주된 장점입니다. 동남아 여행에서 햇볕에 피부가 상했을 때 진정 효과를 보기에는 매우 좋아요.

알로에 겔에는 알코올 성분이 들어가 있어서 처음 바르면 진정되고 보습되는 느낌이 들지만 **시간이 지나면 알코올이 날아가면서 피부가 오히려 더 건조해지는 느낌**이 납니다. 그래서 알로에로 진정을 하신 뒤에는 반드시 그 위에 보습제를 따로 발라줘야 해요. 보습 목적이라면 알로에만 사용하는 것은 적합하지 않고, 진정 효과를 위해 사용하시는 게 맞습니다. 1일 1팩도 무조건 좋은 것은 아닌데, 팩 안에 방부제나 향료 등 화학적 성분이 들어가 있어 매일 사용하면 피부에 자극이 될 수 있어요. 피부 컨디션이 안 좋을 때 오히려 자극이 될 수 있다는 점을 알고 사용하세요.$AAA$, array['알로에', '보습효과', '일광화상진정', '1일1팩', '피부진정']::text[], 2025, 'TlOzDryC6Ck-3', 'https://youtu.be/TlOzDryC6Ck?t=113s', null, '2025-05-16 00:00:00+00'::timestamptz, '2025-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 약은 정말 독한가요?$AAQ$, $AAA$피부과 약이 특별히 독한 것은 아닙니다. 스테로이드, 무좀약, 여드름약이 흔히 거론되는데, 모두 **다른 과에서도 사용하는 동일한 약**이며 피부과만 쓰는 게 아니에요.

스테로이드는 적정 용량으로 짧게 쓰고 끊으면 **부작용 없이 질환이 치료되는** 매우 유용한 약입니다. 옛날에 일부 사람들이 끊지 못하고 계속 복용해 부작용이 생긴 사례 때문에 인식이 나빠진 것입니다. 손·발톱 무좀약은 6개월 정도 장기 복용해야 하지만 간으로 대사되기 때문에 중간중간 간 수치를 검사하면서 복용하므로 위험하지 않아요. 다만 피지 조절제는 임신 중 복용 시 기형아 출산 위험이 있어 임산부에게는 금기입니다. 보습제나 비판텐으로 해결되지 않는 피부 질환에는 스테로이드가 필요한 경우가 있고, 병이 작을 때 짧게 치료하는 편이 오히려 부작용이 적어요.$AAA$, array['피부과약', '스테로이드', '무좀약', '여드름약', '약독성']::text[], 2025, 'TlOzDryC6Ck-4', 'https://youtu.be/TlOzDryC6Ck?t=518s', null, '2025-05-16 00:00:00+00'::timestamptz, '2025-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름은 부위별로 원인이 다른가요?$AAQ$, $AAA$여드름이 같은 부위에 반복적으로 나는 이유는 **사람마다 피지샘이 발달한 부위가 다르기 때문**입니다. 어떤 사람은 턱에, 어떤 사람은 볼에 피지샘이 많이 발달해 있어요.

여드름은 결국 피지샘에서 만들어진 피지가 배출되지 못해 염증이 생기는 질환이에요. **피지가 많이 만들어지는 부위에 배출이 잘 안 되면 그 부위에서 계속 여드름이 생기는** 경우가 많습니다. 대부분 T존이 흔하지만 사람마다 달라 볼이나 턱에 집중되는 분도 있어요. 피부 타입별로 보면 지성 피부는 기름을 줄이는 것이 우선이고, 악건성인데 여드름이 나는 분은 피부가 물을 만들지 못해 기름을 더 많이 만들어내므로 수분을 채워주는 것이 해결법이 됩니다. 복합성 피부는 건조한 부위는 수분을 채우고 기름기 많은 부위는 라이트한 제품을 쓰는 방식으로 부위별 케어가 필요해요.$AAA$, array['여드름부위', '피지샘', 'T존여드름', '건성여드름', '복합성피부']::text[], 2025, 'GAwFS2SaeKM-1', 'https://youtu.be/GAwFS2SaeKM?t=652s', null, '2025-05-22 00:00:00+00'::timestamptz, '2025-05-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 개선에 가장 중요한 생활 습관은?$AAQ$, $AAA$여드름 개선을 위해 가장 추천드리는 생활 습관은 **충분한 수면**입니다. 여드름으로 병원에 오시는 분들 중 잠을 잘 주무시는 분은 거의 없을 정도예요.

늦게 자거나, 조금 자거나, 잠이 불규칙하면 **잠을 못 자면 피부가 뒤집어지는 것처럼 여드름도 똑같이 영향을 받습니다**. 인생에서 여드름이 심하게 났던 시기 중 한 번은 새벽에 일을 하며 밤낮이 바뀐 시기로, 조금씩 안 좋아지다가 미친 듯이 번지는 경험을 했어요. 잠을 제대로 못 자면 여드름에 직접적인 영향이 있다는 뜻입니다. 진료 현장에서도 약물 치료가 가장 강력하지만, 약을 끊고 나서도 잘 유지하려면 집에서 케어와 함께 수면 관리가 필수예요. 결국 클래식이 가장 중요한 셈입니다.$AAA$, array['여드름수면', '생활습관', '야간근무', '여드름악화', '라이프스타일']::text[], 2025, 'GAwFS2SaeKM-2', 'https://youtu.be/GAwFS2SaeKM?t=1280s', null, '2025-05-22 00:00:00+00'::timestamptz, '2025-05-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$애크논 크림과 노스카나겔은 어떻게 다른가요?$AAQ$, $AAA$애크논 크림은 **진행 중인 여드름** 치료용 연고이고, 노스카나겔은 **여드름 흉터** 개선용 연고로 적용 시점이 다릅니다. 진행 중인 여드름에 흉터 연고를 바르면 오히려 악화될 수 있어요.

애크논 크림의 메인 성분은 이부프로펜 30mg(다른 제품은 20mg)으로 함량이 높아 항염 효과가 강합니다. **두 번째 성분인 이소프로필메틸페놀은 향균 작용**이 있어 여드름 균을 줄여줘요. 이 두 작용 덕분에 막 올라오기 시작하는 빨간 염증성 여드름에 효과가 좋습니다. 고름이 비치는 화농성 여드름에는 티트리 100% 오일이 효과적인데 사용감이 화한 편이라 면봉으로 여드름 부위에만 톡 발라야 해요. 노스카나겔은 광고가 많이 나와 여드름 연고로 오해받는 경우가 많지만 흉터 케어용입니다. 병변에 맞게 구분해 사용해야 효과가 빠르게 나타납니다.$AAA$, array['애크논크림', '노스카나겔', '이부프로펜', '여드름연고', '티트리오일']::text[], 2025, 'GAwFS2SaeKM-3', 'https://youtu.be/GAwFS2SaeKM?t=361s', null, '2025-05-22 00:00:00+00'::timestamptz, '2025-05-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$오래된 여드름은 어떤 치료가 가장 효과적인가요?$AAQ$, $AAA$오랫동안 지속되는 여드름의 경우 **먹는 약이 가장 강력하고 확실한** 치료법으로 추천됩니다. 진료 현장에서도 가장 많이 처방되는 치료 중 하나예요.

여드름이 잠깐 나는 게 아니라 오래된 만성 여드름이라면 **약 만큼 효과가 강력하고 확실한 건 없기 때문에** 무조건 먹는 약을 권유하는 편입니다. 약 종류는 환자의 상태에 따라 달라질 수 있어요. 다만 약을 끊고 나서도 좋은 상태를 유지하려면 집에서의 케어가 함께 중요한데, 클렌징과 진정 케어, 적절한 보습제 사용이 받쳐줘야 합니다. 화농성·염증성 여드름이 심한 분들은 잘못된 압출로 더 번지는 경험을 할 수 있으니, 신뢰할 수 있는 의료진을 만나는 것이 중요해요. 약물 치료와 홈케어가 시너지를 낼 때 가장 좋은 결과를 얻을 수 있습니다.$AAA$, array['만성여드름', '여드름약', '경구치료', '압출주의', '홈케어유지']::text[], 2025, 'GAwFS2SaeKM-4', 'https://youtu.be/GAwFS2SaeKM?t=789s', null, '2025-05-22 00:00:00+00'::timestamptz, '2025-05-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실리마린은 피부에 어떤 효과가 있나요?$AAQ$, $AAA$실리마린은 **밀크씨슬(엉겅퀴)에서 추출한 성분**으로, 피부에 진정·항산화·피지 조절 세 가지 효과를 가지고 있습니다. 더운 계절에 사용하기 좋은 성분이에요.

첫 번째로 피부 진정 효과가 있어 날이 덥거나 자극을 받아 얼굴이 붉어질 때 도움이 됩니다. 두 번째 항산화 효과는 **놀랍게도 비타민 E보다 항산화 효과가 뛰어나다고** 알려져 있어 활성산소 제거에 효과적이에요. 세 번째로는 피지 분비를 줄여줘 모공이 좁아지는 효과가 있고, 피지가 산화되어 블랙헤드가 되는 것도 막아줍니다. 피지가 산화되면 염증이 생기는데 실리마린이 이를 막아 트러블과 염증을 줄여줘요. 엉겅퀴에서 추출한 성분이라 자극이 적고 임상 연구에서도 특별한 부작용은 보고되지 않았습니다. 단 국화과 식물 알레르기가 있는 분은 주의해야 해요.$AAA$, array['실리마린', '밀크씨슬', '항산화', '피지조절', '엉겅퀴']::text[], 2025, 'jppKl6_0z9g-1', 'https://youtu.be/jppKl6_0z9g?t=86s', null, '2025-05-23 00:00:00+00'::timestamptz, '2025-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨수티컬즈 실리마린 CF와 C E 페룰릭은 어떻게 다른가요?$AAQ$, $AAA$실리마린 CF 세럼은 **C E 페룰릭의 지성·여드름성 피부용 버전**입니다. 비타민C 15%와 페룰릭애씨드는 동일하게 들어가 있지만, 실리마린 CF에는 실리마린과 살리실산이 추가로 들어가 있어요.

실리마린은 피부의 염증과 트러블을 가라앉혀 여드름에 도움이 되고, **살리실산은 BHA로서 피지를 잡아주고 모공을 깨끗하게 해주는** 성분입니다. 그래서 실제로 사용해 보면 C E 페룰릭보다 제형이 훨씬 더 산뜻해요. 지성 피부라면 실리마린 CF를 그대로 사용하시면 되고, 평소 비타민C 세럼을 쓰던 분이 여름에 피지가 많아져 답답함을 느낄 때 전환하는 용도로 좋습니다. 여드름 후 색소침착이 생긴 분에게도 비타민C 성분이 색소침착 개선에 도움이 돼요. 항산화 효과와 미백 효과를 동시에 얻을 수 있는 세럼입니다.$AAA$, array['스킨수티컬즈', '실리마린CF', 'CE페룰릭', '비타민C세럼', '지성용세럼']::text[], 2025, 'jppKl6_0z9g-2', 'https://youtu.be/jppKl6_0z9g?t=188s', null, '2025-05-23 00:00:00+00'::timestamptz, '2025-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실리마린 화장품의 부작용은 없나요?$AAQ$, $AAA$실리마린은 엉겅퀴라는 식물에서 추출한 성분으로 **자극이 굉장히 적은 안전한 성분**입니다. 임상 연구에서도 특별한 부작용은 보고되지 않았어요.

다만 한 가지 주의할 점이 있는데, **밀크씨슬은 국화과 식물이므로 국화과 알레르기가 있는 분은 사용 전 주의가 필요합니다**. 그 외에는 부작용이라 할 만한 것은 없어요. 화장품을 구매할 때 한 가지 체크해야 할 부분이 있는데, 실리마린이나 밀크씨슬 추출물이 전성분표에서 너무 하위에 표기되어 있으면 함량이 적어 실리마린의 효과를 보기 어려울 수 있습니다. 그래서 실리마린 함유 화장품을 살 때는 전성분표의 어느 위치에 표기되어 있는지 꼭 확인하세요. 임상 연구에서는 실리마린 복용 시에도 여드름과 유분 개선 효과가 있다는 결과가 있어, 발라도 먹어도 효과가 있는 성분이에요.$AAA$, array['실리마린부작용', '국화과알레르기', '전성분확인', '화장품안전성', '함량']::text[], 2025, 'jppKl6_0z9g-3', 'https://youtu.be/jppKl6_0z9g?t=469s', null, '2025-05-23 00:00:00+00'::timestamptz, '2025-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아벤느 클리낭스 파워 컨트롤 세럼은 누구에게 추천하나요?$AAQ$, $AAA$아벤느 클리낭스 파워 컨트롤 세럼은 **여드름이 지속적으로 나서 여드름 케어가 필요한 분**에게 추천드립니다. 특히 T존 부위는 유분과 트러블이 많고 볼은 건조한 복합성 피부에 잘 맞아요.

흰무니 엉겅퀴 열매 추출물이라는 특허 성분이 들어 있는데 **밀크씨슬에서 추출한 활성 성분으로 트러블 진정과 피지 케어 효과**가 있어요. 임상시험에서 7일 만에 여드름이 감소했다는 결과를 가지고 있습니다. 제형은 약간 점성이 있지만 빠르게 흡수되고 마무리감이 뽀송해요. 다만 발라보면 알코올 냄새가 꽤 나는데, 전성분표에서 알코올이 두 번째에 표기될 만큼 함량이 높습니다. 따라서 피부가 민감하거나 알코올에 예민한 분은 조심해서 사용해야 해요. T존에만 부분적으로 발라 사용하는 방법도 권장됩니다.$AAA$, array['아벤느클리낭스', '여드름세럼', '흰무니엉겅퀴', '알코올민감', 'T존케어']::text[], 2025, 'jppKl6_0z9g-4', 'https://youtu.be/jppKl6_0z9g?t=344s', null, '2025-05-23 00:00:00+00'::timestamptz, '2025-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$내 모공 타입은 어떻게 셀프 진단하나요?$AAQ$, $AAA$모공 타입은 두 가지 간단한 테스트로 셀프 진단할 수 있습니다. **세수 후 두 시간이 지나 얼굴이 번들거리면 피지 과다 모공형**이고, 거울 앞에서 볼살을 위로 밀었을 때 모공이 동그랗게 줄어들면 탄력 저하 모공형이에요.

피지 과다형은 사춘기 때 여드름이 많았던 지성 피부인 경우가 많고 흉터도 동반되는 편이며, 성인이 돼서도 오후가 되면 화장이 다 떠 날아가는 경향이 있습니다. 탄력 저하형은 **콜라겐이 줄고 피부가 아래로 처지면서 모공이 세로로 늘어나는** 형태로 주로 30대 이후부터 나타나요. 본인이 어떤 타입에 해당하는지 알아야 효과적인 시술을 선택할 수 있고, 호구를 당하지 않으려면 셀프 진단으로 원인부터 파악하고 가는 것이 중요합니다. 두 가지 특징을 모두 가진 혼합형은 복합적 프로그램이 필요해요.$AAA$, array['모공타입', '셀프진단', '피지과다모공', '탄력저하모공', '모공원인']::text[], 2025, 'iL-N8_oBHPE-1', 'https://youtu.be/iL-N8_oBHPE?t=68s', null, '2025-05-27 00:00:00+00'::timestamptz, '2025-05-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피지 과다 모공에는 어떤 시술이 가장 효과적인가요?$AAQ$, $AAA$피지 과다 모공에는 **스킨보톡스가 가장 효과적**입니다. 보톡스가 피지샘에서 피지를 나오게 하는 신경전달 경로를 차단해 피지 분비 자체를 줄여줘요.

논문에 따르면 스킨보톡스로 **최대 80%까지 피지 분비가 감소합니다**. 시술 후 자국이 조금 있어도 화장이 바로 가능하고 일상생활도 지장이 없으며, 한 번만 해도 효과가 있어 가성비가 좋아요. 다만 코의 모공, 미간, 이마처럼 근육 움직임이 중요한 부위에는 보톡스를 많이 놓기 어렵습니다. 이 부위까지 시술하면 표정이 부자연스러워질 수 있기 때문이에요. 그래서 이런 부위에는 미세바늘 고주파(포텐자, 버츄RF)를 추천드리는데 피지 분비 감소와 콜라겐 자극을 동시에 줘 모공 주변을 조여줍니다. 한 번 시술 효과는 스킨보톡스가 강하므로 2주 간격으로 3번 이상 받는 것이 권장돼요.$AAA$, array['스킨보톡스', '미세바늘고주파', '피지모공', '포텐자', 'T존모공']::text[], 2025, 'iL-N8_oBHPE-2', 'https://youtu.be/iL-N8_oBHPE?t=134s', null, '2025-05-27 00:00:00+00'::timestamptz, '2025-05-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탄력 저하 모공에는 어떤 시술이 좋은가요?$AAQ$, $AAA$탄력 저하로 늘어진 모공에는 **울쎄라가 가장 추천되는 시술**입니다. 울쎄라는 에너지를 집중시켜 피부를 조여주는 원리로 모공도 함께 좁아지게 만들어요.

특히 울쎄라 중에서도 **얕게 들어가는 모드는 모공 주변에만 에너지가 집중되어** 조여주는 효과가 있습니다. 다만 가격이 부담될 수 있는데, 가성비 있는 대안으로 쥬베룩과 피코프락셀의 조합이 있어요. 쥬베룩은 콜라겐 씨앗 역할을 하고 피코프락셀은 피부에 미세한 구멍을 만들어줘 그곳에 콜라겐 씨앗을 심으면 더 잘 자라납니다. 이 조합으로 콜라겐을 많이 만들어 피부가 부드럽게 차오르며 세안 시 매끈매끈해지는 변화를 느낄 수 있어요. 보통 4주 간격으로 3회 정도 치료를 받으면 됩니다. 환자분들이 다 만족해 재시술을 이어가는 경우가 많고 주변 사람들도 변화를 알아본다고 해요.$AAA$, array['울쎄라', '탄력모공', '쥬베룩', '피코프락셀', '콜라겐재생']::text[], 2025, 'iL-N8_oBHPE-3', 'https://youtu.be/iL-N8_oBHPE?t=263s', null, '2025-05-27 00:00:00+00'::timestamptz, '2025-05-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$홈케어로 모공 크기를 줄일 수 있나요?$AAQ$, $AAA$홈케어만으로는 **모공 크기를 절대 작게 만들 수 없습니다**. 모공은 겉이 아니라 속의 문제이며, 화장품은 피부 속까지 들어가지 못해 모공 문제를 해결하지 못해요.

홈케어는 **당장 돌고 있는 기름이나 피부 진정 정도의 효과만** 줄 뿐 속에서 채워야 하는 모공 문제에는 미치지 못합니다. 화장품이 피부에 흡수되어도 표면에 머무르기 때문에 피지 분비량 자체를 줄이거나 콜라겐을 재생시키는 것은 어려워요. 그래서 정말 모공을 개선하려면 본인의 모공 타입에 맞는 시술이 필요합니다. 피지 과다형은 스킨보톡스나 미세바늘 고주파로 피지 분비를 줄이고, 탄력 저하형은 울쎄라나 쥬베룩·피코프락셀로 콜라겐을 채워주는 방식이에요. 두 가지 문제가 모두 있는 분은 첫 회차에 울쎄라와 스킨보톡스를 받고 이후 미세바늘 고주파와 쥬베룩·피코프락셀을 교대로 진행하는 프로그램이 필요합니다.$AAA$, array['홈케어한계', '모공시술필요', '화장품흡수', '복합형모공', '프로그램시술']::text[], 2025, 'iL-N8_oBHPE-4', 'https://youtu.be/iL-N8_oBHPE?t=22s', null, '2025-05-27 00:00:00+00'::timestamptz, '2025-05-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$괄사 마사지는 어떤 효과가 있나요?$AAQ$, $AAA$괄사 마사지는 얼굴 붓기를 빼고 림프 순환을 도와 얼굴이 작아 보이게 만드는 효과가 있습니다. 자기 전에 얼굴과 목 라인을 따라 마사지해주면 다음 날 붓기가 빠지고 턱 라인이 달라진 느낌이 들어요. **논문에서도 증명된** 효과가 있어서 피부과 전문의로서 권해 드립니다.

다만 주름이 펴지거나 피부가 밝아진다는 주장은 비약이 있습니다. 괄사는 붓기 제거와 순환 개선으로 혈색이 좋아지는 정도이고, **주름·탄력 개선이나 노화 방지를 직접적으로 한다고 보기는 어렵습니다**. 림프절을 따라 귀 앞뒤에서 목 아래로 밀어내듯 해주는 게 핵심 방법이에요. 가볍게 얼굴 라인 정리와 뭉친 근육 풀기 정도로 생각하시면 좋습니다.$AAA$, array['괄사마사지', '얼굴붓기', '림프순환', '효과한계']::text[], 2025, 'RXvGzvWVmYM-1', 'https://youtu.be/RXvGzvWVmYM?t=189s', null, '2025-05-28 00:00:00+00'::timestamptz, '2025-05-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$괄사 사용 시 부작용이 있을 수 있나요?$AAQ$, $AAA$괄사를 잘못 사용하면 멍, 접촉성 피부염, 여드름 악화 같은 부작용이 생길 수 있습니다. 처음에는 압력을 어느 정도 줘야 할지 감을 못 잡아 시원하다고 계속 하다 보면 **멍이 들 수 있어요**. 마찰을 반복적으로 주기 때문에 접촉성 피부염이 생길 가능성도 있습니다.

특히 기름이 많고 트러블이 잘 생기는 피부라면 **괄사 때문에 트러블이 더 심해질 수 있어 주의가 필요합니다**. 처음에는 가벼운 힘으로 시작해 조금씩 적응하면서 압력을 조절하는 연습이 필요해요. 여드름이 많은 분들이 괄사를 한 뒤 여드름이 늘었다면 괄사를 의심해 보세요. 마냥 좋은 것이 아니라 이런 점들도 함께 생각하면서 사용해야 합니다.$AAA$, array['괄사부작용', '접촉성피부염', '멍', '트러블']::text[], 2025, 'RXvGzvWVmYM-2', 'https://youtu.be/RXvGzvWVmYM?t=228s', null, '2025-05-28 00:00:00+00'::timestamptz, '2025-05-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$고주파 괄사는 일반 괄사와 어떻게 다른가요?$AAQ$, $AAA$고주파 괄사는 물리적 자극에 열 에너지를 더해 심부 근막까지 작용하는 점에서 일반 괄사와 다릅니다. 일반 괄사는 그냥 물리적으로 누르는 마사지이지만, 고주파가 흐르면 **열 에너지가 심부 근막까지 깊게 들어가서** 근막 유착과 셀룰라이트를 녹여주는 원리예요. 그래서 효과가 더 빠르고 강력하며 오래 지속됩니다.

실제로 한쪽 승모근에만 10분을 시술해 보았을 때 좌우 차이가 눈에 띌 정도로 달라졌어요. **식품의약품안전처 승인을 받은 의료기기**여서 가정용으로는 쓸 수 없고 피부과에서만 받을 수 있어요. 받을 때는 통증이 거의 없고 따뜻한 느낌이라 잠들 정도로 편안합니다. 웨딩 전 승모근 관리, 울쎄라·써마지 후 얼굴 라인 관리, 종아리 마사지 등 활용 범위도 넓어요.$AAA$, array['고주파괄사', '파셀라', '근막유착', '심부열에너지']::text[], 2025, 'RXvGzvWVmYM-3', 'https://youtu.be/RXvGzvWVmYM?t=264s', null, '2025-05-28 00:00:00+00'::timestamptz, '2025-05-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$괄사 도구는 어떤 걸 골라야 하나요?$AAQ$, $AAA$괄사 도구는 무게감과 소재를 기준으로 자신에게 맞는 것을 고르는 것이 좋습니다. 괄사는 무게, 그립, 모양, 돌기 형태가 모두 다르기 때문에 부위마다 본인에게 맞는 도구가 따로 있어요. 여러 종류를 써보며 비교해 보면 자연스럽게 본인 취향에 맞는 것을 찾게 됩니다.

소재에 따라서도 사용감이 다릅니다. **플라스틱은 가볍기 때문에 힘을 많이 주게 되는 경향이 있어요**. 반면 세라믹은 묵직한 무게감이 있어 힘을 덜 들이고도 마사지가 잘 되는 느낌이 확실히 있습니다. 머리 마사지에는 돌기가 있는 형태가 좋고, 얼굴 라인은 림프 흐름을 따라 위에서 아래로 밀어 내려주는 동작이 핵심이에요. 겨드랑이 림프 부위도 함께 풀어주면 효과적입니다.$AAA$, array['괄사선택', '괄사소재', '세라믹', '사용법']::text[], 2025, 'RXvGzvWVmYM-4', 'https://youtu.be/RXvGzvWVmYM?t=120s', null, '2025-05-28 00:00:00+00'::timestamptz, '2025-05-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피지가 피부에 어떤 역할을 하나요?$AAQ$, $AAA$피지는 수분 증발을 막아 피부 노화를 늦추고 피부를 보호하는 중요한 역할을 합니다. 피지가 만든 보호막이 수분이 증발하는 것을 막아 **피부에 수분감을 유지**시켜 줘요. 피부가 건조해지면 주름이 더 많이 생기고 쉽게 늙기 때문에, 적당한 양의 피지가 있으면 노화 방지 효과가 자연스럽게 따라옵니다.

그뿐 아니라 피지는 항산화 작용과 항균 작용도 하기 때문에 **피부를 보호하는 기능을 생각보다 많이 가지고 있어요**. 일명 개기름이라 불리는 그것이 사실 피부 건강에 꼭 필요한 성분인 셈이죠. 피지는 피지샘에서 분비되어 피부를 건강하게 하는 윤활제 같은 역할을 합니다. 다만 굳고 산화되어 모공에 노랗게 보이는 것은 관리가 안 된 노폐물 상태로 구분해서 봐야 해요.$AAA$, array['피지역할', '수분유지', '항산화', '노화방지']::text[], 2025, '2eIHf-AGh-1', 'https://youtu.be/2eIHf-AGh?t=89s', null, '2025-05-30 00:00:00+00'::timestamptz, '2025-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스쿠알란 성분은 어떤 분에게 좋나요?$AAQ$, $AAA$스쿠알란 성분은 피부 속건조가 있거나 악건성인 분들에게 잘 맞는 성분입니다. 스쿠알란은 피지의 핵심 성분인 스쿠알렌에서 안정화시킨 형태로, **스쿠알렌보다 덜 끈적이고 더 안정적**이에요. 원래 피지에서 추출한 성분이기 때문에 피부 흡수력이 굉장히 좋습니다.

보습 효과뿐 아니라 **자외선으로부터 피부를 보호하고 항산화 효과도 갖춘 성분으로 알려져 있어요**. 보습크림이나 장벽크림을 고를 때 전성분표에서 스쿠알란이라고 적힌 제품을 찾으시면 됩니다. 대표적으로는 에스네이처 아쿠아 스쿠알란 수분크림이 함유량이 높아 악건성에 잘 맞고, 지성 피부에는 끈적여서 권하지 않아요. 일리윤 아토 집중크림에도 스쿠알란이 들어가 있어 촉촉하게 수분감을 채워줍니다.$AAA$, array['스쿠알란', '악건성', '보습성분', '흡수력']::text[], 2025, '2eIHf-AGh-2', 'https://youtu.be/2eIHf-AGh?t=180s', null, '2025-05-30 00:00:00+00'::timestamptz, '2025-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피지가 많은지 적은지 어떻게 알 수 있나요?$AAQ$, $AAA$피지가 많은지 적은지는 5가지 체크리스트 중 **3개 이상 해당되는지**로 간편하게 확인할 수 있습니다. 첫 번째는 오후가 되면 얼굴이 번들번들해진다, 두 번째는 코 옆에 블랙헤드가 잘 보인다, 세 번째는 기름종이를 하루에 두 번 이상 사용해야 한다입니다.

네 번째는 화장이 자주 무너진다, 다섯 번째는 화장을 안 했을 때도 핸드폰 통화 후 얼굴 자국이 잘 묻어난다예요. 이 중 **3개 이상 해당되면 피지가 많은 편이라고 보시면 됩니다**. 절대적인 기준은 아니지만 본인 피부 상태를 간단히 파악하는 데 도움이 되는 방법이에요. 피지가 많은 분들은 안색이 칙칙해지고 화장이 무너지며 트러블이 생기는 특징이 나타납니다.$AAA$, array['피지량체크', '유분측정', '피부타입진단', '체크리스트']::text[], 2025, '2eIHf-AGh-3', 'https://youtu.be/2eIHf-AGh?t=252s', null, '2025-05-30 00:00:00+00'::timestamptz, '2025-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피지 관리는 피부 타입별로 어떻게 다른가요?$AAQ$, $AAA$피지 관리의 핵심은 균형이며, 피부 타입에 따라 **클렌저 선택부터 달라져야 합니다**. 피지가 많아 안색이 칙칙해지고 트러블이 잘 나는 피부라면 약알칼리성 클렌저나 계면활성제가 비교적 강한 폼클렌저로 기름 성분을 잘 씻어내는 게 중요해요. 메이크업이나 선크림을 발랐다면 클렌징 오일·밤으로 1차 세안 후 폼클렌저로 2차 세안을 해줍니다.

반대로 **피지가 적고 건조하며 예민한 피부는 약산성 클렌저로 살살 세안해야 해요**. 너무 센 세정제로 오래 세안하면 피부장벽이 무너질 수 있습니다. 피지가 많든 적든 보습은 꼭 필요해요. 피부가 건조하다고 느끼면 오히려 기름을 더 만들어내기 때문에, 유분감은 적고 수분을 채워주는 가벼운 보습제를 쓰시는 게 좋습니다.$AAA$, array['피지관리', '클렌저선택', '약알칼리성', '약산성']::text[], 2025, '2eIHf-AGh-4', 'https://youtu.be/2eIHf-AGh?t=313s', null, '2025-05-30 00:00:00+00'::timestamptz, '2025-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$좁쌀 여드름에 어떤 클렌저를 써야 하나요?$AAQ$, $AAA$좁쌀 여드름 클렌저는 **피부 타입에 따라 다르게 선택**해야 합니다. 유명한 1등 제품을 따라 사는 것이 오히려 여드름을 악화시키는 흔한 실수예요. 지성이고 기름이 많이 도는 분들은 유분기를 잘 씻어주는 약알칼리성 클렌저가 좋고, BHA·AHA·LHA 같은 산 성분이 함유된 제품이 적합합니다.

반면 건성이나 민감성 피부는 피부 장벽이 약하기 때문에 **벗겨내지 않고 보호해 주는 부드러운 약산성 클렌저를 사용하는 게 좋아요**. 닥터지 약산성 레드 블레미쉬 클리어 수딩 폼, 아비브 어성초 폼, 라로슈포제 에빠끌라 퓨리파잉 포밍 젤 등이 약산성에 BHA 각질 케어와 병풀 추출물·판테놀 같은 진정 성분을 함께 갖춘 제품입니다. 좁쌀 여드름은 모공을 막은 묵은 각질을 풀어주는 것이 핵심이에요.$AAA$, array['좁쌀여드름', '클렌저선택', '약산성', '약알칼리성']::text[], 2025, 'R8nd2qBscLA-1', 'https://youtu.be/R8nd2qBscLA?t=178s', null, '2025-06-04 00:00:00+00'::timestamptz, '2025-06-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$좁쌀 여드름에 효과적인 성분은 무엇인가요?$AAQ$, $AAA$좁쌀 여드름에 과학적으로 입증된 핵심 성분은 **나이아신아마이드**입니다. 비타민 B3로도 불리는 나이아신아마이드는 피부 장벽을 강화하고 피지를 줄이며 염증을 완화하는 다양한 작용을 합니다. 이 모든 기능이 여드름 관리에 도움이 되기 때문에 가장 대표적으로 권해 드리는 성분이에요.

그 외에 **징크는 피부 장벽 강화와 피지 조절에 좋은 성분이고**, 판테놀은 진정과 장벽 회복을 도와요. 석류에서 추출한 필로바이오마는 피부 장벽 강화와 미생물 균형에 도움을 줍니다. 여러 가지를 한꺼번에 바르지 말고 피부 장벽을 보강하는 한두 가지만 골라 단계적으로 바꾸는 것이 좋아요. 에스트라 테라크네365, 라로슈포제 에빠끌라 듀오+ M에센스, 닥터지 레드 블레미쉬 클리어 수딩 크림 같은 제품에 이 성분들이 함께 들어 있습니다.$AAA$, array['나이아신아마이드', '징크', '판테놀', '필로바이오마']::text[], 2025, 'R8nd2qBscLA-2', 'https://youtu.be/R8nd2qBscLA?t=341s', null, '2025-06-04 00:00:00+00'::timestamptz, '2025-06-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티노이드가 좁쌀 여드름에도 효과가 있나요?$AAQ$, $AAA$레티노이드는 **각질 탈락 주기를 촉진해 막힌 모공을 열어주는** 효과로 좁쌀 여드름에도 도움이 됩니다. 레티놀, 레티날 같은 레티노이드 계열 성분이 피부 결과 주름, 항노화에만 좋다고 알려져 있지만, 사실 여드름 약으로 처음 출시된 스티바 A크림이 대표적인 레티노이드 성분 약이에요.

좁쌀 여드름이나 여드름이 꾸준히 나는데 **피부 장벽이 괜찮고 건조하거나 따갑지 않은 분들은 스킨케어 루틴에 넣어 꾸준히 발라주시면 정말 도움이 됩니다**. 모공 입구를 계속 열어주는 역할을 가장 잘하는 성분이기 때문이에요. 좁쌀 양이 적고 군데군데 생기는 편이라면 BHA 살리실산 2%와 티트리오일이 든 애크린 겔 같은 스팟 제품도 활용할 수 있습니다. 일반의약품이라 약국에서 살 수 있어요.$AAA$, array['레티노이드', '레티놀', '각질탈락', '모공관리']::text[], 2025, 'R8nd2qBscLA-3', 'https://youtu.be/R8nd2qBscLA?t=495s', null, '2025-06-04 00:00:00+00'::timestamptz, '2025-06-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$좁쌀이라고 생각했는데 비립종일 수도 있나요?$AAQ$, $AAA$좁쌀처럼 보이는 것이 사실 **편평사마귀나 비립종인 경우가 진료 현장에서 진짜 많습니다**. 이 두 가지는 좁쌀 여드름과 달리 홈케어로는 없어지지 않기 때문에 정확한 구분이 중요해요. 진료를 보면 좁쌀이 안 없어지고 계속 번진다고 오시는 분들 중 좁쌀이 아닌 경우가 흔합니다.

좁쌀 여드름은 주로 피지가 많은 **T존, 이마, 코, 볼, 턱 부위에 잘 생겨요**. 비립종은 주로 눈 주변에 생기고 자세히 보면 피부 속에 동그란 하얀 알갱이가 보입니다. 편평사마귀는 바이러스성이라 내버려 두면 번지는 특징이 있어요. 피부가 하얀 분들은 편평사마귀가 본인 피부색과 비슷해 잘 안 보이므로 빛을 비춰 음영을 주면 잘 보입니다. 헷갈리면 피부과에서 진료받는 것이 가장 정확해요.$AAA$, array['편평사마귀', '비립종', '좁쌀구분', '감별진단']::text[], 2025, 'R8nd2qBscLA-4', 'https://youtu.be/R8nd2qBscLA?t=629s', null, '2025-06-04 00:00:00+00'::timestamptz, '2025-06-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$촉촉한 사용감의 선크림은 어떤 게 좋나요?$AAQ$, $AAA$촉촉한 사용감을 원한다면 **셀퓨전씨 쉴드크림 MD나 조선미녀 맑은쌀선크림 아쿠아프레쉬**를 권해 드립니다. 두 제품 모두 유기자차여서 백탁이 없고 자극이 거의 느껴지지 않는 순한 제품이에요. 셀퓨전씨 쉴드크림은 재생크림 같은 질감으로 피부에 보호막을 친 느낌이 들고 눈 시림이 거의 없는 것이 특징입니다.

조선미녀 아쿠아프레쉬는 **수분크림인지 선크림인지 헷갈릴 정도로 촉촉한 제형이에요**. 18,000원대로 가격까지 합리적이라 인기가 높습니다. 두 제품의 차이는 질감인데, 재생크림 같은 묵직함을 원하면 셀퓨전씨, 수분크림 같은 가벼움을 원하면 조선미녀가 더 잘 맞아요. 유기자차는 흡수 후 작용하기 때문에 외출 30분 전에 발라주시는 것이 좋습니다.$AAA$, array['촉촉선크림', '셀퓨전씨', '조선미녀', '유기자차']::text[], 2025, 'NXMfafKe8pc-1', 'https://youtu.be/NXMfafKe8pc?t=74s', null, '2025-06-05 00:00:00+00'::timestamptz, '2025-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 바를 때 적정량은 얼마인가요?$AAQ$, $AAA$선크림은 얼굴에 **500원짜리 동전 크기**만큼 발라야 표시된 SPF 효과를 볼 수 있습니다. 양이 부족하면 제품에 적힌 차단지수만큼의 효과가 나오지 않기 때문에 양이 무조건 중요해요. 처음에 말씀드린 양을 기준으로 충분히 발라주시는 게 핵심입니다.

중간에 외출할 일이 있으면 **선쿠션 같은 걸로 한 번 더 덧발라 주시는 것이 좋아요**. 유기자차는 피부에 흡수돼야 작용하므로 외출 30분 전에 바르셔야 하고, 무기자차는 피부에 막을 씌우는 원리라 외출 직전에 발라도 효과가 있어요. 톤업이나 컬러가 들어간 선크림은 작은 돌가루가 모공을 막아 트러블을 일으킬 수 있으므로 세안할 때 꼼꼼히 지워주는 것이 중요합니다. 다만 이중세안은 피부가 약한 분들에게 오히려 트러블을 일으킬 수 있어요.$AAA$, array['선크림양', 'SPF효과', '덧바르기', '세안법']::text[], 2025, 'NXMfafKe8pc-2', 'https://youtu.be/NXMfafKe8pc?t=402s', null, '2025-06-05 00:00:00+00'::timestamptz, '2025-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$유기자차와 무기자차는 어떻게 다른가요?$AAQ$, $AAA$유기자차는 피부에 **흡수돼 작용하고**, 무기자차는 피부에 막을 씌우는 방식으로 자외선을 차단합니다. 유기자차는 발랐을 때 백탁이 없고 가벼운 사용감이 특징이지만 흡수돼야 작용하기 때문에 외출 30분 전에 미리 발라주셔야 해요. 셀퓨전씨, 조선미녀 제품이 대표적인 유기자차입니다.

무기자차는 **돌가루를 빻아 얼굴에 막을 씌우는 방식**이라 외출 직전에 발라도 효과가 있어요. ASF 피지컬 톤업 선블럭이 무기자차이며 톤업 효과까지 있어 노란 쿨톤 피부 보정에도 좋습니다. 다만 돌가루가 모공에 끼면 트러블이 일어날 수 있어 잘 닦아내야 해요. 라로슈포제 안뗄리오스 멜트인 크림과 키엘 울트라 라이트 같은 혼합자차는 살짝 백탁과 톤업이 있어 화장 전 베이스로 잘 어울립니다.$AAA$, array['유기자차', '무기자차', '차단원리', '톤업선크림']::text[], 2025, 'NXMfafKe8pc-3', 'https://youtu.be/NXMfafKe8pc?t=375s', null, '2025-06-05 00:00:00+00'::timestamptz, '2025-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 들어간 선크림은 어떤 게 있나요?$AAQ$, $AAA$비타민C와 선크림을 한 번에 쓸 수 있는 제품으로 **닥터지 비타 클리어 선세럼**을 권해 드립니다. 비타민C와 선크림을 합친 앰플 타입으로, 아침마다 비타민C 바르고 다시 선크림을 바르기 귀찮은 분들에게 잘 맞아요. 제형이 수분감 가득한 앰플처럼 발리기 때문에 굉장히 촉촉하고 부담이 적습니다.

게다가 **나이아신아마이드가 5% 들어 있어 미백 기능까지 기대할 수 있는 제품이에요**. 이것저것 발라서 답답한 게 싫은 분들이 한 번에 두 가지를 해결하기에 좋아요. 여름에는 자외선이 노화의 가장 큰 원인이기 때문에 자외선 차단제와 함께 항산화 성분을 활용하면 노화 예방에 도움이 됩니다. 피부가 약한 분은 이중세안 대신 한 번 세안만으로 깨끗하게 지우는 것이 트러블을 줄이는 방법입니다.$AAA$, array['비타민C선크림', '닥터지', '나이아신아마이드', '미백기능']::text[], 2025, 'NXMfafKe8pc-4', 'https://youtu.be/NXMfafKe8pc?t=326s', null, '2025-06-05 00:00:00+00'::timestamptz, '2025-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건조하고 예민한 피부에 닦토를 해도 되나요?$AAQ$, $AAA$각질이 많고 건조한 피부는 **닦토를 안 하는 것이 좋습니다**. 각질이 보인다고 닦아내고 싶지만, 이런 피부의 각질은 피부장벽이 망가졌을 때 생기는 것이기 때문이에요. 그 위에 화장솜으로 계속 문지르며 자극을 주면 오히려 피부장벽에 더 안 좋을 수 있습니다.

각질이 많고 속건조가 심하며 가끔 따가운데 좁쌀과 화농성 여드름이 계속 나는 분들은 **애기 피부 다루듯이 굉장히 살살 관리해 주셔야 해요**. 라운드랩 독도 토너처럼 자극이 없고 순한 토너라도 닦아내는 방식 자체가 자극이 될 수 있습니다. 일반 피부라면 닦토를 해도 괜찮지만, 예민하고 건조한 피부는 닦아내는 방식 대신 PHA 같이 각질을 부드럽게 녹여 주는 성분이 든 토너로 케어하는 것이 좋아요.$AAA$, array['닦토', '예민피부', '피부장벽', '각질케어']::text[], 2025, 'JUmz9-G5i50-1', 'https://youtu.be/JUmz9-G5i50?t=181s', null, '2025-06-11 00:00:00+00'::timestamptz, '2025-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 여드름 피부는 어떤 클렌저를 써야 하나요?$AAQ$, $AAA$지성 여드름 피부는 **약알칼리성 클렌저나 세정력이 좋은 약산성 클렌저를 사용**하는 것이 좋습니다. 메이크프렘 세이프 미 같은 약산성에 순한 계면활성제 클렌저는 자극이 적지만 기름이 많은 피부에는 세정력이 부족할 수 있어요. 약산성만 고집하기보다는 유분기를 잘 씻어내 줄 수 있는 클렌저가 필요합니다.

구체적으로는 **약알칼리성 클렌저를 번갈아 사용하거나, 라로슈포제 에빠끌라 아이소바이옴 폼클렌저처럼 약산성이면서 세정력이 좋은 제품을 활용**해 보세요. 또는 BHA 같은 각질·피지 케어 성분이 들어간 클렌저도 좋습니다. 다만 BHA 토너 패드인 스트라이덱스 센서티브 패드는 각질을 문지르지 않고 부드럽게 녹여 주는 방식이라 지성 피부에 도움이 돼요. 모공이 막혀 피지가 갇히는 것을 풀어 주는 게 핵심입니다.$AAA$, array['지성여드름', '약알칼리성클렌저', 'BHA', '유분세정']::text[], 2025, 'JUmz9-G5i50-2', 'https://youtu.be/JUmz9-G5i50?t=385s', null, '2025-06-11 00:00:00+00'::timestamptz, '2025-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름성 피부에 꼭 필요한 성분 카테고리는 무엇인가요?$AAQ$, $AAA$여드름성 피부가 꼭 써야 하는 성분 카테고리는 **다섯 가지**입니다. 첫째는 피지 조절 성분으로 나이아신아마이드, 징크, EGCG(녹차 추출물)가 대표적이에요. 둘째는 각질을 녹여 주는 성분으로 BHA 살리실산, AHA 글라이콜릭산, 레티노이드 계열(처방약은 아다팔렌·트레티노인, 일반 화장품은 레티놀·레티날)이 있습니다.

셋째는 **항염 성분으로 BHA, 나이아신아마이드, 바쿠치올**이 효과적이에요. 넷째는 항균 성분으로 티트리오일, BHA, 징크, 석류 추출물인 필로바이오마가 도움이 됩니다. 마지막은 피부 장벽 강화 성분으로 나이아신아마이드, 세라마이드, 판테놀, 글리세린이 있어요. 좁쌀이 많다면 피지·각질 케어, 화농성 여드름이면 항염·항균, 장벽이 약하면 장벽 강화 성분 중심으로 골라 쓰시는 것이 좋습니다.$AAA$, array['여드름성분', '피지조절', '항염성분', '장벽강화']::text[], 2025, 'JUmz9-G5i50-3', 'https://youtu.be/JUmz9-G5i50?t=701s', null, '2025-06-11 00:00:00+00'::timestamptz, '2025-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$CE 페룰릭과 실리마린 CF는 어떻게 다른가요?$AAQ$, $AAA$두 제품 모두 비타민C 항산화 세럼이지만, **실리마린 CF는 피지를 잡아 주는 성분이 추가**되어 지성 피부에 더 적합합니다. 스킨수티컬즈 CE 페룰릭은 비타민C와 페룰릭애씨드로 강력한 항산화 효과를 내며, 여드름 자국 같은 색소침착에도 도움이 되는 유명한 제품이에요.

실리마린 CF는 **CE 페룰릭과 비슷한 조성에 피지 조절 성분인 실리마린이 더해진 제품**입니다. 비타민C와 페룰릭애씨드가 동일하게 들어가 항산화 효과를 그대로 누리면서, 피지를 잡아 주는 효과까지 함께 얻을 수 있어요. 그래서 여드름이 잘 나는 지성 피부에는 CE 페룰릭보다 실리마린 CF가 더 잘 맞습니다. 비타민C는 미백 효과로 여드름 자국에도 도움이 되어 발라 주는 것 자체가 좋은 습관이에요.$AAA$, array['CE페룰릭', '실리마린CF', '비타민C', '지성피부']::text[], 2025, 'JUmz9-G5i50-4', 'https://youtu.be/JUmz9-G5i50?t=493s', null, '2025-06-11 00:00:00+00'::timestamptz, '2025-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스트레스가 피부 노화를 일으키나요?$AAQ$, $AAA$극심한 스트레스는 **머리카락이 하얗게 변하고 피부도 쭈글쭈글해지는** 급속노화의 직접 원인입니다. 이 현상을 '마리 앙투아네트 증후군'이라 부르는데, 단두대에 오른 왕비가 폭삭 늙은 모습에서 유래한 이름이에요. 더글로리 작가 김은숙 작가님도 집필 스트레스로 머리가 하얗게 변했다고 합니다.

과학적으로도 증명돼 있어요. **2020년 하버드대학 연구진이 쥐에게 극심한 스트레스를 주자 실제로 털이 하얗게 변했다는 결과**를 발표했습니다. 머리카락 색을 만드는 멜라닌 줄기세포가 스트레스 호르몬 급증으로 빠르게 고갈되고, 그러면서 새치가 빨리 늘어나는 거예요. 그러니 흰머리와 노화를 피하려면 스트레스 관리가 핵심입니다. 운동, 영화, 따뜻한 목욕 등 본인에게 맞는 방법으로 스트레스를 너무 많이 쌓지 않도록 관리해 주세요.$AAA$, array['스트레스노화', '마리앙투아네트증후군', '멜라닌줄기세포', '흰머리']::text[], 2025, '5JN_OfEnREg-1', 'https://youtu.be/5JN_OfEnREg?t=170s', null, '2025-06-12 00:00:00+00'::timestamptz, '2025-06-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$잠을 못 자면 피부가 정말 빨리 늙나요?$AAQ$, $AAA$수면 부족은 **피부 재생 호르몬 분비를 막아 급속노화의 원인**이 됩니다. 피부 재생은 주로 숙면 중에 이루어지는데, 특히 밤 10시부터 새벽 2시 사이에 피부 재생과 관련된 성장 호르몬이 가장 많이 분비돼요. 숙면을 못 취하면 이 시간대의 재생이 원활히 이루어지지 않습니다.

우주비행사들의 평균 수면 시간은 6시간 정도인데 **75% 이상이 수면제를 복용하며 잘 정도로 수면의 질이 낮아져요**. 그 결과 급속노화가 일어납니다. 국제우주정거장은 24시간 동안 지구를 16바퀴 도는 환경이라 1시간 30분마다 낮과 밤이 바뀌어 바이오 리듬이 깨지기 때문이에요. 일상에서도 규칙적 수면이 필요한데, 현실적으로 10시 취침이 어렵다면 12시 전에는 자려고 노력하시는 게 좋습니다.$AAA$, array['수면노화', '성장호르몬', '피부재생', '바이오리듬']::text[], 2025, '5JN_OfEnREg-2', 'https://youtu.be/5JN_OfEnREg?t=176s', null, '2025-06-12 00:00:00+00'::timestamptz, '2025-06-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무중력 환경에서 피부가 더 빨리 늙는 이유는 무엇인가요?$AAQ$, $AAA$중력이 사라지면 **얼굴 근육이 위로 끌어당기는 힘을 내지 않아 콜라겐과 엘라스틴 자극이 줄어들기** 때문입니다. 평소 서 있을 때 중력은 피부와 근육을 아래로 끌어당기고, 이를 버티기 위해 얼굴 근육이 무의식적으로 미세하게 수축하면서 위로 끌어올리는 힘을 냅니다. 이 긴장 상태가 반복되면 콜라겐과 엘라스틴이 계속 만들어져 자연적인 운동 효과가 생기는 거예요.

무중력에서는 위로 올리는 힘이 사라져 **피부가 게을러집니다**. 실제 연구에서 우주에서 6개월을 지낸 비행사들의 피부 표피 두께가 약 10% 감소했는데, **이는 7~10년의 노화와 맞먹는 수준**이에요. 그래서 지구에서는 '은' 운동이나 '어흥' 같은 얼굴 근육 운동으로 가운데 중요한 근육들을 살리고 처짐을 막아주는 것이 도움이 됩니다.$AAA$, array['무중력노화', '표피두께', '얼굴근육운동', '콜라겐자극']::text[], 2025, '5JN_OfEnREg-3', 'https://youtu.be/5JN_OfEnREg?t=252s', null, '2025-06-12 00:00:00+00'::timestamptz, '2025-06-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$급속노화를 예방하는 방법은 무엇인가요?$AAQ$, $AAA$급속노화를 막는 **슬로우에이징 비결은 자극 운동, 자외선 차단, 스트레스 관리, 규칙적 수면 네 가지**입니다. 첫째는 끌어내리는 중력을 거슬러 얼굴 근육이 위쪽으로 올라가도록 하는 운동이에요. '은' 운동이나 '어흥' 같은 얼굴 근육 운동을 꾸준히 해서 가운데 근육을 자극하면 얼굴 처짐이 덜해집니다.

둘째는 **자외선 차단인데, 자외선은 피부를 노화시키는 가장 주요한 원인**이라 주름과 기미·잡티를 막기 위해 차단제를 꼭 발라야 해요. 비타민C 같은 항산화 성분도 함께 발라 주면 좋습니다. 셋째 스트레스 관리는 운동, 영화, 따뜻한 목욕 등 자신에게 맞는 방법으로 해 주세요. 넷째 규칙적 수면은 밤 10시부터 새벽 2시 사이가 가장 중요하고, 현실적으로 12시 전 취침을 권해 드립니다.$AAA$, array['슬로우에이징', '급속노화예방', '얼굴근육운동', '자외선차단']::text[], 2025, '5JN_OfEnREg-4', 'https://youtu.be/5JN_OfEnREg?t=420s', null, '2025-06-12 00:00:00+00'::timestamptz, '2025-06-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C를 바르면 따가운데 정상인가요?$AAQ$, $AAA$비타민C는 **바르면 따가운 것이 정상**입니다. 비타민C의 주 성분은 '아스코르브산'으로 말 그대로 산성 성분이기 때문이에요. 산성일 때 흡수가 더 잘되기 때문에 효과가 좋은 만큼 자극도 따라옵니다. 일부러 약산성 토너를 먼저 바르고 사용하는 분들도 있을 정도예요.

바르는 방법으로 자극을 줄일 수 있어요. **이마와 양 뺨에 한 방울씩 떨어뜨려 문지른 뒤 1~2분 흡수 시간을 두면 됩니다**. 양 조절을 잘하면 별로 따갑지 않고, 따가워도 그 정도는 참고 기다린 뒤 재생크림을 위에 덧발라 주면 진정돼요. 판테놀 성분이 든 재생크림이 진정에 도움이 됩니다. 피부 컨디션이 안 좋을 때는 따가움이 더 심하니 그날엔 비타민C를 건너뛰고 재생크림만 바르는 것이 좋습니다.$AAA$, array['비타민C따가움', '아스코르브산', '사용법', '재생크림']::text[], 2025, 'SAK00m8_5RY-1', 'https://youtu.be/SAK00m8_5RY?t=149s', null, '2025-06-13 00:00:00+00'::timestamptz, '2025-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C와 레티놀을 같이 발라도 되나요?$AAQ$, $AAA$비타민C와 레티놀을 **같이 바르면 피부가 뒤집어질 수 있어 권하지 않습니다**. 레티놀은 자극감이 있는 성분이라 비타민C와 함께 쓰면 자극이 겹치기 때문이에요. 두 성분 모두 효과적이지만 동시 사용은 피부에 부담을 줍니다.

나이트 케어로 활용할 때는 **하루는 비타민C, 하루는 레티놀 이렇게 번갈아 발라 주시는 것이 좋아요**. 비타민C는 산성이라 따갑고, 레티놀은 자극감이 있어 두 자극이 겹치면 피부 트러블로 이어질 수 있습니다. 또한 비타민C는 아침에 햇빛을 받을 때 생기는 활성산소를 막아 주는 역할이 있어 아침 사용도 의미가 있어요. 다만 아침에 비타민C와 재생크림을 같이 바르면 화장이 밀릴 수 있으므로 저농도 앰플을 활용하는 것이 좋습니다.$AAA$, array['비타민C레티놀', '병용주의', '번갈아사용', '자극중복']::text[], 2025, 'SAK00m8_5RY-2', 'https://youtu.be/SAK00m8_5RY?t=118s', null, '2025-06-13 00:00:00+00'::timestamptz, '2025-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 항산화 효과를 높이는 성분 조합은 무엇인가요?$AAQ$, $AAA$비타민C 항산화 효과를 극대화하려면 **비타민C, 토코페롤, 페룰릭애씨드 세 가지가 함께 든 제품**이 좋습니다. 이 세 성분이 함께 들어가야 비타민C의 항산화 효과가 더 좋아지는 것으로 알려져 있어요.

대표적으로 **피지오겔 데일리뮨 비타민C 앰플 세럼은 순수 비타민C 6%와 함께 토코페롤·페룰릭애씨드 세 가지를 모두 함유**하고 있습니다. 비타민C는 산화되기 매우 쉽기 때문에 햇빛이 들지 않게 갈색병에 담겨 있어 오래 변질 없이 사용할 수 있어요. 스킨수티컬즈 CE 페룰릭도 같은 조성의 원조 격 제품이지만 가격이 부담스러운 편입니다. 닥터디퍼런트 CEQ 안티옥시던트 세럼은 비타민C 17%로 CE 페룰릭의 가성비 버전이며 15ml 용량이라 산화 걱정이 적어요.$AAA$, array['비타민C조합', '토코페롤', '페룰릭애씨드', '항산화']::text[], 2025, 'SAK00m8_5RY-3', 'https://youtu.be/SAK00m8_5RY?t=233s', null, '2025-06-13 00:00:00+00'::timestamptz, '2025-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$고농도와 저농도 비타민C 앰플 중 어떤 게 좋나요?$AAQ$, $AAA$고농도와 저농도는 **사용 시간대와 피부 컨디션에 따라 다르게 선택**하면 됩니다. 아침에는 화장이 밀리는 문제를 피하려고 저농도 앰플을 권해 드려요. 자극이 적으니 꾸준히 쓸 수 있고, 길게 보면 한 통을 다 쓰면서 효과를 더 많이 볼 수 있습니다.

저녁 집중 케어에는 **고농도 앰플이 적합한데, 라로슈포제 순수 비타민C 12 세럼은 꿀 같은 제형으로 보호막 같은 보습감이 강해 건성에게 좋아요**. 코스알엑스 더 비타민씨 23 세럼은 23%지만 물·오일 2층 제형이라 생각보다 안 따갑고 촉촉합니다. 다만 페룰릭애씨드가 없어 냉장보관이 필요해요. 이니스프리 비타민C 7일 톤업 세럼은 비타민C 유도체 2%로 아침용 입문템에 적합하고 묽어서 흡수가 빠릅니다.$AAA$, array['고농도앰플', '저농도앰플', '비타민C농도', '아침저녁구분']::text[], 2025, 'SAK00m8_5RY-4', 'https://youtu.be/SAK00m8_5RY?t=156s', null, '2025-06-13 00:00:00+00'::timestamptz, '2025-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 경구약 리트풀로 효과는 어느 정도인가요?$AAQ$, $AAA$리트풀로는 백반증 최초의 경구 JAK 억제제로 **얼굴 회복률이 48주에 63%**까지 보고됐습니다. 비분절형 백반증 환자에게 50mg을 매일 복용하게 한 연구에서 평균 얼굴 회복률은 24주에 19%, 48주에 63%였습니다. 치료 기간이 길어질수록 효과가 더 좋아지는 경향이 뚜렷했습니다.

환자의 나이, 성별, 인종, 피부색, 유병 기간 등 다양한 특성을 분석한 결과 거의 모든 환자 그룹에서 효과를 보였고, **백반증 침범 범위가 넓은 경우에도 48주 동안 점차 효과가 더 좋아지는 경향**을 보였습니다. 리트풀로는 이미 2024년 9월에 우리나라에서 원형 탈모증 치료제로 허가를 받았으며, 백반증 임상 연구가 종료되면 백반증 치료제로도 승인될 가능성이 높습니다. 기존의 바르는 연고나 자외선 치료보다 알약으로 복용한다는 점에서 편리하고 넓은 면적의 백반증 환자에게 유용합니다.$AAA$, array['리트풀로', '백반증경구약', 'JAK억제제', '회복률', '비분절형백반증']::text[], 2025, 'nxok2MdqEFE-1', 'https://youtu.be/nxok2MdqEFE?t=40s', null, '2025-06-17 00:00:00+00'::timestamptz, '2025-06-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$엑시머 레이저 저용량 치료가 부작용이 더 적나요?$AAQ$, $AAA$얼굴 백반증에서는 **저용량 엑시머 레이저로도 표준 용량과 동일한 효과**를 보였습니다. 연구팀은 18명의 환자의 얼굴 좌우를 나눠서 한쪽은 붉은기가 발생하는 표준 용량, 반대쪽은 그 에너지의 절반으로 치료했습니다. 그 결과 양쪽 모두 동일한 치료 결과를 얻었습니다.

표준 용량에서는 화상과 색소침착이 종종 발생했지만 저용량 치료에서는 **이런 부작용이 한 명도 발생하지 않아 색소침착 없이 더 안전하고 깨끗한 치료가 가능**했습니다. 다만 일본의 모리타 교수님은 몸통과 팔다리처럼 치료 반응이 미진한 부위에서는 붉은기가 생기는 에너지에 9배가량 강하게 치료하는 고용량 치료가 멈췄던 효과를 다시 낼 수 있다고 강조했습니다. 결국 얼굴은 색소침착을 최소화할 수 있는 저용량으로 시작하고, 반응이 적은 몸통과 팔다리는 필요에 따라 고용량을 고려하는 맞춤형 적용이 중요합니다.$AAA$, array['엑시머레이저', '저용량치료', '백반증부작용', '색소침착', '맞춤형치료']::text[], 2025, 'nxok2MdqEFE-2', 'https://youtu.be/nxok2MdqEFE?t=161s', null, '2025-06-17 00:00:00+00'::timestamptz, '2025-06-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$손끝 백반증 냉동 물집술은 기존 수술과 어떻게 다른가요?$AAQ$, $AAA$냉동 물집술은 **피부를 벗겨내지 않고 물집 안에 멜라닌 세포를 주입하는 새로운 수술법**입니다. 액체 질소로 손끝을 살짝 얼려서 물집을 만든 다음 그 안에 멜라닌 세포와 각질 형성 세포의 혼합액을 주입하는 방식으로, 12명의 환자를 대상으로 진행한 비교 연구에서 처음으로 시도됐습니다.

총 10명의 환자의 52개 손가락을 1년 동안 관찰한 결과, 냉동 물집술을 받은 **18개 손가락 중 4개인 22%에서 75% 이상의 색소 회복**이 있었습니다. 반면 CO2 레이저 박피술과 미니펀치 이식술에서는 아무도 75% 이상 회복을 달성하지 못했고, 회복 기간이 길거나 흉터가 남는 경우가 많았습니다. 냉동 물집술은 피부를 완전히 벗겨내지 않기 때문에 회복기간이 짧으면서도 더 효과적이었습니다. 다만 우리나라에서는 세포 이식술에 대한 규제가 까다로워 당장 시도하기는 어렵습니다.$AAA$, array['냉동물집술', '손끝백반증', '멜라닌세포이식', '세포이식술', '수술비교']::text[], 2025, 'nxok2MdqEFE-3', 'https://youtu.be/nxok2MdqEFE?t=287s', null, '2025-06-17 00:00:00+00'::timestamptz, '2025-06-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 재발을 막을 새로운 약물도 개발되고 있나요?$AAQ$, $AAA$**인터루킨-15 신호를 차단하는 AMG-714라는 약물이 미국에서 1상 임상시험 중**에 있습니다. 해리스 교수님 연구팀은 백반증이 회복된 후에도 피부에 조직 상주 기억 T세포가 오랫동안 남아 있어 언제든 다시 멜라닌 세포를 공격해 재발할 수 있다는 점을 밝혔습니다.

이 기억 T세포들이 피부에서 생존하기 위해서는 **인터루킨-15라는 물질이 필요한데, 동물실험에서 이를 차단했을 때 약물 투입을 종료한 후에도 수십 주 동안 백반증이 재발하지 않고 장기간 안정**이 유지됐습니다. 기존 JAK 억제제인 옵젤루라와 리트풀로는 면역세포가 멜라닌 세포를 공격하는 것을 막지만, 면역세포가 완전히 사라지지는 않기 때문에 재발 예방 효과는 현재로서 불분명합니다. 다만 동물실험 결과는 유망하지만 아직 인체 실험 결과는 발표되지 않았고, 실제 환자에게 적용되기까지는 10년 이상의 긴 시간이 걸릴 수 있습니다.$AAA$, array['AMG-714', '인터루킨15', '백반증재발', '기억T세포', '백반증신약']::text[], 2025, 'nxok2MdqEFE-4', 'https://youtu.be/nxok2MdqEFE?t=439s', null, '2025-06-17 00:00:00+00'::timestamptz, '2025-06-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔꿈치 무릎이 까매지는 이유는 무엇인가요?$AAQ$, $AAA$**팔꿈치나 무릎이 까매지는 가장 큰 원인은 마찰과 자극**입니다. 피부가 자극을 받으면 공격받고 있다고 생각하고 멜라닌 색소를 만들어서 더 까매지는 원리로, 겨드랑이와 사타구니가 까매지는 것도 같은 이유입니다.

그래서 우선 너무 꽉 끼는 옷이나 땀 차는 소재는 피하고 면, 모달 같은 통기성이 좋고 자극이 덜 되는 소재로 바꿔야 합니다. 씻을 때는 절대 때를 밀지 말고, 타월로 거품만 내서 부드럽게 씻어 주세요. 책상에 팔꿈치 닿는 자세, 턱을 괴는 자세, **무릎 꿇고 앉는 자세도 마찰로 자극이 될 수 있으니 피해야** 합니다. 겨드랑이에 색소침착이 생겼다면 데오드란트 사용을 잠시 중단하고, 제모할 때 스트립처럼 자극이 될 수 있는 제품은 피하는 것이 좋습니다.$AAA$, array['팔꿈치색소침착', '마찰자극', '멜라닌색소', '때밀기금지', '옷소재']::text[], 2025, 'rB6cLbp6GAM-1', 'https://youtu.be/rB6cLbp6GAM?t=43s', null, '2025-06-19 00:00:00+00'::timestamptz, '2025-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$AHA BHA PHA 산성분으로 각질 관리 얼마나 자주 해야 하나요?$AAQ$, $AAA$AHA, BHA, PHA 같은 산성분이 포함된 제품은 **일주일에 1-2회 정도 관리하는 것이 적절**합니다. 팔꿈치나 무릎이 까맣게 보이는 것은 색소침착뿐 아니라 각질층이 두꺼워져서 그런 것도 있어 각질 관리가 중요한데, 자극을 줄 수 있는 때 타월 대신 산성분 제품으로 부드럽게 관리하는 것이 좋습니다.

각질을 제거한 후에는 **보습에 더욱 신경 써야 하고, 다른 부위보다 건조한 곳이므로 유분기가 많은 제품으로 관리해 주는 것**이 좋습니다. 보습과 각질관리 성분인 우레아가 들어있는 유리아 크림을 같이 써주면 더 효과를 볼 수 있는데, 유리아 크림은 처방전 없이 약국에서 구매할 수 있는 일반 의약품입니다. 처방전이 있어야 살 수 있는 멜라논 크림, 아크리프 크림 같은 전문 의약품은 효과와 함께 부작용이 있어 꼭 병원 방문 후 처방을 받아야 합니다.$AAA$, array['AHABHAPHA', '각질관리', '유리아크림', '우레아', '미백연고']::text[], 2025, 'rB6cLbp6GAM-2', 'https://youtu.be/rB6cLbp6GAM?t=146s', null, '2025-06-19 00:00:00+00'::timestamptz, '2025-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔꿈치 겨드랑이 색소침착에 레이저토닝 몇 회 받아야 하나요?$AAQ$, $AAA$**보통 1주에서 2주 간격으로 5에서 10회 이상의 레이저토닝 치료가 필요**합니다. 1-2회 만으로는 큰 효과가 없고, 부위와 색소의 깊이에 따라 차이가 있지만 꾸준히 받으면 피부 톤이 서서히 밝아지는 것을 느낄 수 있습니다.

토닝 레이저는 **상처 없이 피부에 있는 멜라닌 색소만 골라서 잘게 없애주는 레이저**로, 얼굴 기미·잡티 시술뿐 아니라 몸 어디든 다 적용할 수 있습니다. 그래서 팔꿈치, 무릎, 겨드랑이, 사타구니 모두 시술이 가능합니다. 토닝뿐 아니라 이온자임이나 미백관리, 고주파 같은 시술을 병행하면 효과가 더 좋고, 꾸준히 노력했지만 호전이 없는 경우 피부과 치료를 받는 것이 도움이 됩니다. 색소침착은 단번에 사라지지 않지만 마찰을 줄이고 보습을 충분히 하면서 전문가 도움을 받으면 충분히 달라질 수 있습니다.$AAA$, array['레이저토닝', '치료횟수', '색소침착치료', '몸레이저', '병행시술']::text[], 2025, 'rB6cLbp6GAM-3', 'https://youtu.be/rB6cLbp6GAM?t=241s', null, '2025-06-19 00:00:00+00'::timestamptz, '2025-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흑색가시세포증과 일반 색소침착은 어떻게 구분하나요?$AAQ$, $AAA$**흑색가시세포증은 단순 색소침착과 달리 피부결이 벨벳처럼 두꺼워 보이는 것이 특징**입니다. 단순 색소침착은 피부 두께는 그대로 유지되는 반면, 흑색가시세포증은 빛을 받았을 때 검게 광택이 도는 모습이 관찰될 수 있어 시각적으로 구분이 가능합니다.

원인도 전혀 다른데 **흑색가시세포증은 보통 비만이나 인슐린 저항성이 있는 분들에게 주로 나타나기 때문에 체중 감량과 인슐린 저항성 치료**가 필요합니다. 그렇게 하면 피부색도 같이 좋아집니다. 드물지만 위샘암종이나 난소암, 폐암, 유방암 등에서도 동반될 수 있다고 알려져 있어, 성인인데 갑자기 광범위하게 발생한 경우에는 위장관 내시경 등 악성종양 검사를 해봐야 할 수도 있습니다. 다만 암 때문에 생기는 경우는 흔치 않으니 너무 걱정하지 않으셔도 됩니다.$AAA$, array['흑색가시세포증', '색소침착구분', '인슐린저항성', '비만피부', '벨벳피부']::text[], 2025, 'rB6cLbp6GAM-4', 'https://youtu.be/rB6cLbp6GAM?t=331s', null, '2025-06-19 00:00:00+00'::timestamptz, '2025-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 의사들이 가장 많이 쓰는 선크림 브랜드는 무엇인가요?$AAQ$, $AAA$**피부과 전문의 120명 설문에서 1위는 셀퓨전씨로 30명이 넘게 응답**했습니다. 주관식으로 선크림 브랜드를 물어본 결과 4분의 1에 해당하는 선생님들이 셀퓨전씨를 인생 선크림으로 꼽았고, 2위는 17명이 답한 라로슈포제, 3위는 ASF였습니다.

셀퓨전씨가 1위가 된 이유는 **기본적으로 무겁지 않고 흡수력이 좋아 발랐을 때 착 붙는 느낌이 있기 때문**입니다. 셀퓨전씨에서는 레이저 선스크린, 베리덤 쉴드, 베리덤 센서티브, 어드밴스드 클리어 4개 제품이 주로 언급됐고 모두 흡수력과 발림성이 좋다는 공통점이 있었습니다. 라로슈포제는 유비데아 안뗄리오스 멜트인 틴티드가 대표적인데 기미·잡티를 만드는 가시광선과 블루라이트까지 차단해주고, ASF는 아주대학교 의과대학 초대 학장님이 창립한 브랜드입니다. 피부과 의사들도 비싼 백화점 브랜드가 아니라 차단 잘 되고 발림성 좋은 제품을 선택한다는 점이 인상적입니다.$AAA$, array['피부과의사선크림', '셀퓨전씨', '라로슈포제', 'ASF', '선크림추천']::text[], 2025, '4L1MKekRLp0-1', 'https://youtu.be/4L1MKekRLp0?t=123s', null, '2025-06-20 00:00:00+00'::timestamptz, '2025-06-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무기자차와 유기자차는 어떻게 다른가요?$AAQ$, $AAA$**무기자차는 피부에 코팅을 만들어 자외선을 튕겨내고, 유기자차는 자외선을 흡수해 열에너지로 바꿔주는 방식**입니다. 무기자차는 보통 물리적 차단제로 피부에다 선크림으로 코팅을 해서 자외선을 막고, 유기자차는 성분들이 자외선을 흡수해서 그걸 열에너지로 바꿔버립니다.

유기자차는 보통 산뜻하고 발림성이 좋지만 **피부가 민감하거나 예민한 분들은 발랐을 때 눈 시림, 화함, 따가움이 느껴질 수 있어 무기자차를 권합니다**. 둘의 장점을 섞은 것이 혼합자차입니다. 또한 무기자차는 바르고 나면 피부결 따라 선크림이 끼는 느낌이 있어 몸에 바르기보다 얼굴에 적합하고, 유기자차는 씻을 때 잘 씻기는 장점이 있어 몸에도 바르기 좋습니다. 라로슈포제 안뗄리오스 UV뮨 400은 라로슈포제에서 개발한 차단 성분으로 가장 긴 UVA 파장을 막아줘 피부 노화 예방에 특화된 유기자차 제품입니다.$AAA$, array['무기자차유기자차', '물리적차단제', '혼합자차', '민감성피부선크림', '자외선차단원리']::text[], 2025, '4L1MKekRLp0-2', 'https://youtu.be/4L1MKekRLp0?t=319s', null, '2025-06-20 00:00:00+00'::timestamptz, '2025-06-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림은 실내에서도 발라야 하나요?$AAQ$, $AAA$**창가에서 활동할 때는 발라야 하지만, 창문과 멀리 떨어진 일반 실내에서는 안 발라도 됩니다.** 자외선A는 창문을 뚫고 들어오기 때문에 창가에서 계속 활동해야 한다면 발라야 합니다. 단, 창문과 멀리 떨어져서 차 한 잔 하는 정도라면 바르지 않아도 됩니다.

많이 물어보시는 실내 형광등의 경우 **자외선이 정말 미미하게 나와 피부에 영향을 줄 정도는 아니기 때문에 안 발라도 됩니다**. 피부과 의사들도 비슷한 양상이라 설문에서 남자 선생님 47%는 야외활동 있는 날만 바르고, 여자 선생님도 22%는 야외활동 시에만 바른다고 응답했습니다. 보통 출근 후 하루 종일 실내에서 생활하고 레이저실은 창문이 없는 경우가 많아 실내에서는 거의 안 바르는 경우가 많습니다. 또한 한 번 바를 때 적정량으로 완두콩 두 개 크기가 31.7%로 가장 많이 응답한 양이었습니다.$AAA$, array['실내선크림', '창가자외선', '선크림횟수', '선크림양', '자외선A창문']::text[], 2025, '4L1MKekRLp0-3', 'https://youtu.be/4L1MKekRLp0?t=624s', null, '2025-06-20 00:00:00+00'::timestamptz, '2025-06-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 한 번에 얼마나 발라야 하나요?$AAQ$, $AAA$**적정량은 500원짜리 동전 크기 또는 손가락 두 마디지만 피부과 의사들도 그렇게 많이 바르지는 않습니다.** 120명을 대상으로 한 설문에서 완두콩 두 개 크기를 바른다고 한 분이 31.7%로 가장 많았고, 그다음으로 세 개 크기, 한 개 크기 순서로 응답이 많았습니다.

적정량인 두 마디나 동전 크기로 바르면 **흘러내릴 정도로 많은 양이라 실제로 그렇게 바르기 어려운 것이 현실**입니다. 그래서 결론적으로 피부과 선생님들도 500원짜리만큼은 안 바르지만, 자기관리를 열심히 하는 일부는 완두콩 5개 이상이나 4개 정도의 양을 바르기도 합니다. 이런 분들은 보통 야외활동을 많이 하는 경우가 많습니다. 적게 바르더라도 자외선이 강한 야외 활동이 있을 때는 충분히 덧발라주는 것이 중요합니다.$AAA$, array['선크림양', '완두콩두개', '선크림덧바르기', '적정량', '선크림설문']::text[], 2025, '4L1MKekRLp0-4', 'https://youtu.be/4L1MKekRLp0?t=924s', null, '2025-06-20 00:00:00+00'::timestamptz, '2025-06-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 1-2개 났을 때 병원에 가는 게 나을까요 약국 연고가 나을까요?$AAQ$, $AAA$**초기 여드름 1-2개는 병원에서 3일 이내에 90% 이상 깔끔하게 치료**됩니다. 염증성, 화농성 여드름은 무조건 초기에 확실히 잡아야 하는 여드름이며, 병원에서는 간단히 약 바르면 개선되는지 주사 맞고 약을 먹어야 하는지 진찰 후 처방을 받게 됩니다.

비용 측면에서도 **염증 주사는 노스카나겔이나 애크논 크림 값이랑 거의 비슷하지만 확실한 효과가 있고 연고는 효과가 불분명**해 병원에 오는 것이 훨씬 경제적입니다. 노스카나겔의 주성분인 해파린, 덱스판테놀, 알란토인은 상처 회복을 도와주지만 효과가 불분명하고 염증 자체를 감소시키는 연고는 아닙니다. 약국 연고를 잘못 써서 방치되고 염증이 더 깊어질 수 있어, 짜는 것도 색소침착이 100% 남기 때문에 피해야 합니다. 감기처럼 후딱 치료받고 끝내는 게 가장 효과적입니다.$AAA$, array['여드름초기치료', '염증주사', '노스카나겔', '병원치료비용', '화농성여드름']::text[], 2025, 'JTnMtRVgNjg-1', 'https://youtu.be/JTnMtRVgNjg?t=52s', null, '2025-06-23 00:00:00+00'::timestamptz, '2025-06-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 스케일링을 많이 받으면 피부가 얇아지나요?$AAQ$, $AAA$**스케일링을 많이 하면 오히려 피부가 더 튼튼해집니다.** 스케일링은 진피층에서 콜라겐이 생성되고 재생이 촉진되어 피부가 전반적으로 튼튼해지는 효과가 있어, 벗겨내는 시술이 아니라 잔디깎기나 가지치기 정도로 생각하는 것이 적절합니다.

스케일링은 묵은 각질과 노폐물을 부드럽게 제거하고, 압출은 안에서 곪고 염증을 일으키는 물질을 빼주는 시술입니다. 스케일링 후에는 **정돈된 모공으로 비타민 성분의 좋은 앰플들을 침투시켜 여드름 자국을 개선시켜주고 발생도 줄여줍니다**. 다만 피부가 많이 민감하고 건조하면서 여드름이 많이 나는 분들은 스케일링이 자극을 많이 줄 수 있어 적합하지 않을 수 있습니다. 그럴 때는 LDM 같은 고밀도 초음파 관리가 피부 염증을 줄여주고 촉촉하게 해주는 데 도움이 됩니다. 비용은 보통 10만 원 정도 내로 가능합니다.$AAA$, array['스케일링압출', '여드름관리', '콜라겐생성', 'LDM초음파', '피부두께']::text[], 2025, 'JTnMtRVgNjg-2', 'https://youtu.be/JTnMtRVgNjg?t=139s', null, '2025-06-23 00:00:00+00'::timestamptz, '2025-06-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 자국이나 색소침착에는 어떤 레이저가 좋나요?$AAQ$, $AAA$**염증 후 붉은 자국에는 브이빔, 색소침착에는 제네시스가 효과적**입니다. 제네시스는 얼굴 전반적인 홍조와 붉은 자국뿐 아니라 색소침착에도 어느 정도 효과가 있는 레이저이고, 브이빔은 염증 후 생긴 붉은 자국을 효과적으로 억제할 수 있는 레이저입니다.

IPL은 레이저와 달리 **여러 파장의 강한 빛이 나오는 시술로 상대적으로 안전하면서 여드름 자국이 퍼져 있고 전반적인 피부톤까지 개선하고 싶을 때** 적합합니다. 이런 레이저 치료는 보통 5회에서 10회 정도가 필요하며, 다운타임이 거의 없다는 점이 큰 장점입니다. 너무 오래 걸린다고 느낄 수 있지만 해결되지 않는 것들은 레이저로만 해결할 수밖에 없습니다. 그리고 실펌엑스라는 바늘 고주파는 미세바늘로 고주파를 흘려보내 진피의 리모델링을 유도해 혈관 수축과 염증 감소, 진피 환경 개선에 도움을 주는 장기적 치료입니다.$AAA$, array['제네시스', '브이빔', 'IPL', '여드름자국', '레이저치료횟수']::text[], 2025, 'JTnMtRVgNjg-3', 'https://youtu.be/JTnMtRVgNjg?t=303s', null, '2025-06-23 00:00:00+00'::timestamptz, '2025-06-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$염증성 여드름이 심할 때는 어떤 시술이 효과적인가요?$AAQ$, $AAA$**염증이 심한 여드름에는 아그네스, 골드 PTT, 애플토닝 같은 시술이 효과적**입니다. 아그네스는 아주 작은 절연침에서 고주파가 나오면서 염증성 여드름 포인트들을 지지는 장비로, 염증이 있는 곳에 즉각적인 효과를 줄 수 있고 심한 부분들은 개별적으로 시술할 수 있습니다.

골드 PTT는 **골드 나노 입자를 피지선까지 침투시킨 다음 레이저나 고주파로 열을 발생시켜 피지선을 억제**하는 시술입니다. 얼굴 전체에 바를 수 있어 병변이 광범위할 때, 여드름 재발을 더 확실히 감소시키고 싶을 때 아그네스를 대신해 써볼 수 있습니다. 애플토닝(A플러스 레이저)은 레이저 토닝과 비슷한데 피지선 수축을 시켜주는 레이저로, 이소티논을 먹은 것 같은 효과를 보이면서 색소침착이나 붉은 자국에도 효과가 있는 안전한 치료입니다. 이소티논 같은 약 먹기가 어렵거나 염증주사 받기가 두려운 분들에게 대안이 됩니다.$AAA$, array['아그네스', '골드PTT', '애플토닝', '염증성여드름시술', '피지선억제']::text[], 2025, 'JTnMtRVgNjg-4', 'https://youtu.be/JTnMtRVgNjg?t=233s', null, '2025-06-23 00:00:00+00'::timestamptz, '2025-06-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여성형 탈모 자가진단은 어떻게 할 수 있나요?$AAQ$, $AAA$**집에서 손쉽게 해볼 수 있는 탈모 자가진단 방법은 세 가지**가 있습니다. 첫 번째는 50-60가닥 정도의 머리카락을 두 손가락으로 부드럽게 당겼을 때 6가닥 이상 빠지면 탈모를 의심해 봐야 합니다.

두 번째 파팅 테스트는 **주로 타는 가르마 쪽이 확연하게 하얘졌거나 넓어졌는지 보는 방법**입니다. 세 번째는 사진으로 비교하는 방법으로, 항상 같은 가르마나 정수리 라인을 기준으로 손가락으로 전체를 잡은 다음 가족에게 핸드폰 카메라로 찍어달라고 합니다. 한 달에 한 번 또는 3개월에 한 번 꾸준히 찍어서 비교를 해보면 머리숱 변화를 객관적으로 확인할 수 있습니다. 3개월 전보다 머리숱이 확실히 많이 줄었다고 생각되면 탈모에 대한 경각심을 가져야 합니다. 여성형 탈모는 남성형 탈모처럼 M자로 빠지기보다 점차적으로 머리카락이 얇아지면서 진행되는 특징이 있습니다.$AAA$, array['여성형탈모진단', '탈모자가진단', '파팅테스트', '당김검사', '정수리사진']::text[], 2025, 'nAqWcFwO1ws-1', 'https://youtu.be/nAqWcFwO1ws?t=128s', null, '2025-06-24 00:00:00+00'::timestamptz, '2025-06-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여성형 탈모의 원인은 무엇이 있나요?$AAQ$, $AAA$**여성형 탈모의 원인은 유전, 호르몬 변화, 스트레스, 다이어트 네 가지**가 있습니다. 가족 중에 어머니나 할머니가 여성형 탈모가 있다면 본인도 생길 확률이 높고, 임신·출산·폐경·갑상선 기능 이상·피임약 복용 같은 호르몬 변화 상황에서도 머리숱 변화가 생깁니다.

스트레스의 경우 모발의 생장 주기에 큰 영향을 주는데, **휴지기 탈모증은 큰 스트레스나 과도한 다이어트 이후 3개월 정도 시간이 지났을 때 머리카락이 쑥 빠져버리는 현상**입니다. 다이어트도 중요한데 영양분은 심장, 뇌, 근육 같은 중요한 기관에 먼저 가고 나서 머리카락, 손톱, 피부 같은 외부에 가기 때문에, 너무 적게 먹으면 머리카락까지 갈 영양이 부족해집니다. 특히 다이어트는 모발 성장에 영향을 많이 주는 케라틴 생성을 방해합니다. 20-30대 젊은 분들 중에서도 탈모가 늘어나고 있어 조기 관리가 중요합니다.$AAA$, array['탈모원인', '휴지기탈모증', '다이어트탈모', '호르몬변화', '케라틴']::text[], 2025, 'nAqWcFwO1ws-2', 'https://youtu.be/nAqWcFwO1ws?t=194s', null, '2025-06-24 00:00:00+00'::timestamptz, '2025-06-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탈모 예방을 위한 홈케어는 어떻게 해야 하나요?$AAQ$, $AAA$**탈모 예방 홈케어의 핵심은 밤에 샴푸하기, 두피 자외선 차단, 두피 보습** 세 가지입니다. 아침 스타일링 후 그대로 자는 것은 얼굴에 선크림과 화장을 한 채로 자는 것과 같아서 안 됩니다. 밤에 꼭 샴푸를 해주고 두피를 잘 말려야 두피가 건강해지고 탈모도 잘 안 생깁니다.

두 번째로 **두피 자외선 차단이 중요한데, 해변이나 휴가 갈 때 두피가 타서 새빨개지고 각질이 떨어지는 경우**가 많습니다. 특히 머리카락이 얇아진 분이나 탈모가 진행된 분들은 정수리에 직사광선을 그대로 맞아 새빨개지거나 피부암이 생기기도 합니다. 모자라도 꼭 쓰는 것이 좋습니다. 세 번째로 두피도 피부이기 때문에 세라마이드, 콜레스테롤, 지방산 세 가지가 들어 있는 보습제를 모발에 발라주는 것이 좋습니다. 두피 앰플도 좋고, 미녹시딜은 약국에서 살 수 있는데 하루 한 번 정도 발라주면 탈모에 도움이 됩니다.$AAA$, array['탈모홈케어', '밤샴푸', '두피자외선차단', '두피보습', '미녹시딜']::text[], 2025, 'nAqWcFwO1ws-3', 'https://youtu.be/nAqWcFwO1ws?t=314s', null, '2025-06-24 00:00:00+00'::timestamptz, '2025-06-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탈모 병원 치료에는 어떤 것들이 있나요?$AAQ$, $AAA$**탈모 병원 치료는 약재, 메조테라피 주사, 레이저, 모발 이식 네 가지**가 있습니다. 약재 치료는 가장 간단한 방법으로 먹는 약이나 바르는 약을 사용하고, 메조테라피는 모낭주사라고도 부르는데 모발의 힘을 튼튼하게 하고 모발 재생에 도움을 주는 약재를 두피에 직접 주사하는 방식입니다.

세 번째 레이저 치료는 **두피에 직접 자극을 주는 레이저나 두피에 필요한 유효 빛을 쬐서 모발이 다시 생성되도록 도움을 주는 치료**들입니다. 모발 이식도 가능합니다. 탈모는 모낭을 얼마나 건강하고 튼튼하게 유지하느냐의 싸움이라 피부를 어릴 때부터 관리하는 것처럼 두피, 모낭, 모발도 젊고 건강할 때부터 관리해 주는 것이 좋습니다. 일단 집에서 자가진단을 해보고 스트레스나 다이어트 같은 조절 가능한 원인을 해결한 후, 홈케어를 시도해도 도저히 안 된다면 피부과에서 시술의 도움을 받는 흐름이 적합합니다.$AAA$, array['탈모시술', '모낭주사', '메조테라피', '탈모레이저', '모발이식']::text[], 2025, 'nAqWcFwO1ws-4', 'https://youtu.be/nAqWcFwO1ws?t=489s', null, '2025-06-24 00:00:00+00'::timestamptz, '2025-06-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$1일 1팩에는 어떤 성분의 마스크팩을 골라야 하나요?$AAQ$, $AAA$1일 1팩에는 **보습과 진정 위주의 성분이 적게 들어간 제품**을 골라야 합니다. 매일 팩을 하는데 미백, 주름 개선 같은 효과까지 챙기면 영양 성분이나 다른 성분들이 너무 많이 들어가 피부가 염증이 나고 뒤집어질 수 있습니다.

선택 기준은 충분한 보습감과 자극 없는 진정이며, **시트도 피부에 자극이 되지 않는 부드러운 제품**을 골라야 합니다. 인터넷에 1일 1팩이 안 좋다는 의견이 일부 맞는 이유는 매일 다른 제품을 쓰다 보면 각 팩의 특정 성분들이 접촉 피부염을 일으키거나 피부를 민감하게 만들 수 있기 때문입니다. 또한 1일 1팩을 피해야 하는 피부도 있는데, 지성이나 여드름 피부는 모공을 막고 피지가 갇혀서 안에 있는 여드름 염증이 심해질 수 있고, 민감성 피부는 향료나 티트리·라벤더 오일 같은 식물 추출물이 들어있는 성분을 피하는 것이 안전합니다.$AAA$, array['1일1팩', '마스크팩성분', '보습진정', '접촉피부염', '민감성피부']::text[], 2025, 'TpqTafnbqvw-1', 'https://youtu.be/TpqTafnbqvw?t=98s', null, '2025-07-01 00:00:00+00'::timestamptz, '2025-07-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마스크팩을 붙이고 자면 더 좋을까요?$AAQ$, $AAA$**팩을 붙이고 자는 것은 오히려 피부를 더 건조하게 만들기 때문에 안 됩니다.** 팩 사용법에 15분에서 20분 후에 떼어내라고 적힌 데에는 다 이유가 있습니다.

붙이고 자면 **시트가 마르면서 오히려 피부에 수분을 더 뺏어가서 더 건조해지게 만들기 때문에 적정 시간을 지키는 것**이 중요합니다. 시트에 에센스가 남아있는 게 아까워 보일 수 있지만 그게 흡수 효과로 이어지지 않습니다. 또한 사람의 피부 타입에 따라 팩의 성분이 잘 맞을 수도 안 맞을 수도 있어, 올리브영 세일할 때 한꺼번에 쟁이지 말고 테스트로 먼저 써본 후 잘 맞으면 추가 구매하는 것이 좋습니다. 한 달 동안 매일 팩을 하면 처음 3일은 귀찮지만 습관이 되면 편해지고, 크림만 바를 때 점심시간 후 건조해지던 피부가 자기 전까지 촉촉함을 유지하는 효과를 느낄 수 있습니다.$AAA$, array['팩붙이고자기', '마스크팩시간', '수분증발', '팩사용법', '팩테스트']::text[], 2025, 'TpqTafnbqvw-2', 'https://youtu.be/TpqTafnbqvw?t=1830s', null, '2025-07-01 00:00:00+00'::timestamptz, '2025-07-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$응급으로 피부 진정이 필요할 때는 어떤 팩이 좋나요?$AAQ$, $AAA$응급 진정이 필요할 때는 **쿨링 성분이 있는 팩이나 부직포 시트의 팩**이 좋습니다. 넘버즈인 4번 SOS 응급 진정 얼음장팩은 냉장보관을 안 했는데도 붙이고 나면 시원한 진정 효과가 있고, 시트에 쑥을 갈아 넣어 떼고 나면 가루가 약간 붙는 단점은 있지만 급한 진정에 적합합니다.

이온토코메드 아쿠아 바이오 셀룰로오스 마스크는 **돼지 껍데기처럼 야들야들한 시트가 피부에 착 달라붙는 특징**이 있고, 안에 든 앰플도 쫀쫀해서 일반 시트보다 흡수가 좋습니다. 들어간 성분은 판테놀, 베타인, 베타글루칸으로 보습과 진정에 효과적이며 레이저 같은 피부과 시술 후 진정용으로 많이 쓰입니다. 다만 쿨링 성분이 있는 팩은 눈에 안 들어가게 조심해야 합니다. 한 달간 1일 1팩 후 뽑은 베스트는 1위 넘버즈인 1번 거즈팩, 2위 아비브 어성초 스티커, 3위 에스트라 프로 인텐시브 수딩 마스크였습니다.$AAA$, array['SOS팩', '쿨링팩', '바이오셀룰로오스', '응급진정', '시술후팩']::text[], 2025, 'TpqTafnbqvw-3', 'https://youtu.be/TpqTafnbqvw?t=672s', null, '2025-07-01 00:00:00+00'::timestamptz, '2025-07-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀이 들어간 마스크팩은 효과가 있나요?$AAQ$, $AAA$레티놀 마스크팩은 **자극감이 있어 팩보다 시술 후 레티놀 세럼이나 크림을 바르는 게 더 낫습니다.** 본셉 레티놀 세럼 마스크팩은 항노화 성분으로 유명한 레티놀이 들어있어 피부 결이나 노화에 효과가 있을 것 같지만, 레티놀은 특유의 자극감이 있어 팩으로 사용했을 때 부담이 될 수 있습니다.

메디힐 레티놀 콜라겐 윤곽 마스크는 **얼굴 윗부분과 아랫 부분으로 분리되어 있는데 아랫부분이 잘 안 붙고 시간이 지날수록 떨어져 시트 형태가 애매**합니다. 에센스도 많지 않고 레티놀 성분 때문에 약간의 자극감이 있어 잘 맞는 분이라면 한 번쯤 써볼 만합니다. 한편 글루타치온이 들어간 아비브 약산성 pH 시트 마스크 글루타치온좀 핏은 피부의 약산성 환경에 맞춰 자극감이 적고, 미백 효과가 있는 글루타치온 성분 덕분에 피부가 살짝 밝아진 느낌을 받을 수 있으며 확실한 효과를 보려면 장기 사용을 권합니다.$AAA$, array['레티놀마스크팩', '글루타치온팩', '항노화팩', '약산성마스크', '잡티케어팩']::text[], 2025, 'TpqTafnbqvw-4', 'https://youtu.be/TpqTafnbqvw?t=585s', null, '2025-07-01 00:00:00+00'::timestamptz, '2025-07-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$20대가 받으면 좋은 시술 딱 하나만 추천한다면 무엇인가요?$AAQ$, $AAA$**20대에게 단 하나만 추천한다면 보톡스입니다.** 일반적인 20대는 일생에 피부가 가장 좋을 때라 세수, 선크림, 잠 세 가지만 잘 챙겨도 피부 관리의 반은 성공입니다. 하지만 그 좋은 피부를 60살까지 유지하려는 목적이라면 보톡스가 가장 적합합니다.

보톡스는 **주름을 펴는 기능보다 예방 기능이 훨씬 많아 피부가 팽팽할 때 예방하면 효과가 좋습니다**. 표정 주름이 생기기 전에 이마나 미간처럼 자주 찡그리는 부위에 보톡스 정도는 미래를 위한 투자가 될 수 있습니다. 단 보톡스 그 이상은 과한 시술이며, 여드름이나 흉터가 있는 분들은 그에 맞는 별도 치료가 필요합니다. 20대는 주머니 사정도 가벼운 시기라 한 가지 시술에 집중하는 것이 합리적이고, 피부가 원래 좋기 때문에 예방 목적의 보톡스가 가장 가성비 있는 선택입니다.$AAA$, array['20대보톡스', '표정주름예방', '20대시술', '예방시술', '보톡스투자']::text[], 2025, 'BVEjTja3AFA-1', 'https://youtu.be/BVEjTja3AFA?t=56s', null, '2025-07-03 00:00:00+00'::timestamptz, '2025-07-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$30대에게 가장 우선되는 시술은 무엇인가요?$AAQ$, $AAA$**30대에게 가장 추천되는 시술은 고주파 리프팅**입니다. 30대는 피부 탄력이 빠지고, 턱선이 뭉개지고, 눈가에 잔주름이 자리 잡기 시작하는 시기라 리프팅 계열 시술이 필수입니다. 고주파든 초음파든 뭐라도 해줘야 균형이 맞습니다.

고주파는 **늙지 못하게 하는 시술, 콜라겐을 유지시키는 시술이라 30대부터 받으면 가장 좋은 시술**입니다. 보톡스도 당연히 꾸준히 맞는 게 좋고, 정보가 너무 많아 지칠 때 하나만 정한다면 고주파를 권합니다. 30대에 아무것도 안 하면 어느 날 갑자기 얼굴선이 무너져 있고, 그때 울쎄라나 써마지를 받으면 돈도 더 들고 효과도 느립니다. 티 안 나는 선에서 관리하려면 고주파 리프팅이 양치질 같은 개념으로 미리미리 챙기는 것이 중요합니다.$AAA$, array['30대고주파', '리프팅시술', '콜라겐유지', '30대시술추천', '양치질개념']::text[], 2025, 'BVEjTja3AFA-2', 'https://youtu.be/BVEjTja3AFA?t=144s', null, '2025-07-03 00:00:00+00'::timestamptz, '2025-07-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$40대에게 적합한 시술 조합은 무엇인가요?$AAQ$, $AAA$**40대는 리프팅, 스킨부스터, 레이저 토닝 3박자 조합이 가장 적합**합니다. 탄력, 주름, 모공, 윤기가 하나하나 눈에 띄게 무너지는 시점이라 레이저 리프팅과 스킨부스터 조합이 딱 맞습니다. 겉 라인은 당겨주고 피부 속은 채워주는 것을 동시에 해줘야 합니다.

리프팅을 기본으로 탑재한 상태에서 **스킨부스터를 얹는 형태인데, 스킨 보톡스, 리쥬란, 쥬베룩처럼 피부에 영향을 주는 시술들이 모두 좋은 선택**입니다. 추가로 임신·출산 후나 40대가 되면서 기미가 많아지는 여성분들이 많은데, 기미를 포기하지 않으려면 40대부터 레이저 토닝을 받는 것이 좋습니다. 피부가 지저분하면 어떤 시술을 받아도 시술 받은 티가 안 나고 깔끔해 보이지 않기 때문입니다. 리프팅으로 구조 잡고, 스킨부스터로 결 채우고, 레이저 토닝으로 색 정리까지 3박자가 맞으면 얼굴에 광이 돌게 됩니다.$AAA$, array['40대시술조합', '리프팅스킨부스터', '리쥬란쥬베룩', '레이저토닝기미', '스킨보톡스']::text[], 2025, 'BVEjTja3AFA-3', 'https://youtu.be/BVEjTja3AFA?t=244s', null, '2025-07-03 00:00:00+00'::timestamptz, '2025-07-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$50대 이후에는 어떤 시술이 꼭 필요한가요?$AAQ$, $AAA$**50대에는 리프팅 외에 볼륨을 채워주는 스컬트라나 레디어스 같은 시술이 필수**입니다. 50대부터는 볼륨이 빠지는 것이 문제가 되는 시기이고, 볼륨이 빠지면 그 자리가 더 처져버립니다.

구조 자체가 무너지면 **울쎄라, 써마지, 실리프팅을 아무리 해줘도 피부가 더 무너져 내릴 수밖에 없기 때문에 깊은 볼륨을 채워주는 계열이 반드시 함께 들어가야** 합니다. 50대는 60대, 70대, 80대를 준비하는 시기로, 70-80대에 무너져 내릴 것을 50대부터 미리 볼륨을 채워서 대비하면 훨씬 좋습니다. 50대에 추가적으로 해야 하는 시술 하나만 꼽자면 볼륨을 채워주는 스킨부스터 계열이며, 대표적으로 스컬트라, 레디어스 또는 필러 같은 시술이 좋습니다. 지금 안 하면 나중엔 두 배로 해야 되는 시기이므로 미리미리 복구 공사가 필요합니다.$AAA$, array['50대볼륨시술', '스컬트라', '레디어스', '볼륨채우기', '노화대비']::text[], 2025, 'BVEjTja3AFA-4', 'https://youtu.be/BVEjTja3AFA?t=458s', null, '2025-07-03 00:00:00+00'::timestamptz, '2025-07-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 잔주름엔 꼭 아이크림을 발라야 하나요?$AAQ$, $AAA$눈가 잔주름 관리에 꼭 아이크림이 아니어도 충분합니다. 눈 주변은 건조해서 주름이 잘 생기기 때문에 항상 촉촉하게 유지해 주는 게 핵심이지, 아이크림이라는 형태가 핵심은 아니에요. 아이크림은 양은 적은데 가격이 비싼 편이라, 굳이 비싼 돈을 들이지 않아도 됩니다.

중요한 건 **수분과 막을 형성해 주는 보습**이에요. 판테놀이나 글리세롤 성분이 충분히 들어간 일반 보습제를 발라주시면 됩니다. 바세린은 보습보다 수분이 날아가지 않게 밀폐하는 역할이라, 보습제를 먼저 바른 뒤 그 위에 얇게 덧바르거나 두 가지를 섞어 쓰는 게 좋아요. 다만 바세린을 너무 두껍게 바르면 비립종이나 좁쌀 여드름처럼 모공이 막혀 트러블이 생길 수 있으니 조심하세요. 비판텐도 좋지만 연고라 끈적이고 트러블 성분이 있어 장기 사용엔 일반 보습제가 더 낫습니다.$AAA$, array['눈가주름', '아이크림', '보습제', '바세린', '판테놀']::text[], 2025, '5o0KbFSRGzA-1', 'https://youtu.be/5o0KbFSRGzA?t=56s', null, '2025-07-04 00:00:00+00'::timestamptz, '2025-07-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 주름에 레티놀, 레티날을 어떻게 발라야 하나요?$AAQ$, $AAA$눈가에 레티노이드를 바를 때는 아주 소량을 얇게, 저녁에만 발라야 합니다. 레티놀은 콜라겐 형성을 촉진해 피부를 탄탄하게 하고 잔주름을 완화하며 자외선으로 손상된 피부를 회복시켜요. 레티날은 레티놀보다 약 10배 정도 강력한 성분으로, 효과가 큰 만큼 자극도 심합니다.

레티노이드를 처음 쓰는 분이라면 **레티놀 아주 낮은 농도부터 차근차근** 사용해 보시고, 눈가에는 진짜 눈꼽만큼만 펴서 발라주세요. 많이 바르면 자극, 따가움, 빨갛게 올라옴, 각질이 벗겨지는 트러블이 생길 수 있어요. 또 레티놀은 빛에 매우 민감해 **자외선에 노출되면 분해되고 변질되어 염증이나 색소침착의 원인**이 됩니다. 그래서 꼭 저녁에 바르세요. 비타민 A 성분은 태아 기형을 유발할 수 있어 임산부나 임신 준비 중인 분은 절대 사용하시면 안 됩니다.$AAA$, array['레티놀', '레티날', '눈가관리', '자극', '임산부금기']::text[], 2025, '5o0KbFSRGzA-2', 'https://youtu.be/5o0KbFSRGzA?t=190s', null, '2025-07-04 00:00:00+00'::timestamptz, '2025-07-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 보톡스는 효과가 얼마나 가나요?$AAQ$, $AAA$눈가 보톡스 효과는 한 번 맞으면 보통 4~5개월 정도 지속됩니다. 눈가 주변에 있는 눈둘레근을 일시적으로 마비시켜 주름 자체가 생기지 않도록 해주는 시술이에요. 주기가 돌아올 때마다 반복해서 맞으면 근육의 힘이 점점 떨어져 시술 간격이 길어지고, 그만큼 주름이 생기는 시간도 늦춰지게 됩니다.

다만 **너무 많은 용량이나 엉뚱한 위치에 맞으면** 웃는데 무표정인 어색한 얼굴이 될 수 있어요. 근육이 생긴 모양대로, 주름이 생긴대로 더 깊어지지 않는다는 느낌으로 적당한 양을 살살 놔주는 게 핵심입니다. 그렇게 하면 자연스럽게 주름이 개선되면서 표정도 해치지 않아요. 보톡스는 비교적 저렴하고 시술받을 수 있는 병원도 많아 잘 알아보고 이용하시면 좋은 방법이 됩니다.$AAA$, array['눈가보톡스', '효과지속', '눈둘레근', '재시술주기']::text[], 2025, '5o0KbFSRGzA-3', 'https://youtu.be/5o0KbFSRGzA?t=346s', null, '2025-07-04 00:00:00+00'::timestamptz, '2025-07-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이미 생긴 눈가 주름엔 어떤 시술이 좋은가요?$AAQ$, $AAA$가만히 있을 때도 보이는 눈가 주름엔 크림만으론 한계가 있어 시술의 도움을 받는 게 좋습니다. 아이써마지는 고주파를 눈꺼풀과 주변 잔주름에 적용해 콜라겐 생성을 유도하는 시술로, 눈뜨는 힘이 좋아져 이마 근육을 덜 쓰게 되면서 이마 주름까지 개선되는 일석이조 효과가 있어요.

아이리쥬란은 연어 DNA로 피부를 재생하는 리쥬란을 눈가 전용으로 입자를 작게 만든 시술로, **눈가 주변에 깊어진 주름**에 효과가 좋습니다. 아그네스는 고주파를 미세한 바늘로 찔러 열로 지져 펴주는 방식이라 효과가 드라마틱하며 눈 아래쪽 주름에 특히 강력해요. 울트라펄스 레이저는 피부를 깎아 매끈하게 재생시키는 방식으로 **50대 60대 이상 늘어진 피부에 매우 효과적입니다**. 눈가 필러는 꺼짐이 심하거나 주름이 깊을 때 아주 소량만 사용하면 어려 보이는 효과가 확실해요.$AAA$, array['아이써마지', '아이리쥬란', '아그네스', '울트라펄스', '눈가필러']::text[], 2025, '5o0KbFSRGzA-4', 'https://youtu.be/5o0KbFSRGzA?t=505s', null, '2025-07-04 00:00:00+00'::timestamptz, '2025-07-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅 시술 효과는 얼마나 지속되나요?$AAQ$, $AAA$써마지나 울쎄라 같은 레이저 리프팅 효과는 보통 3개월에서 길게는 1년 정도 지속됩니다. 그 후에는 다시 원래대로 돌아가기 때문에 매년 주기적으로 200~500만 원의 비용을 들여 반복적으로 시술해야만 유지가 되는 구조예요. 그래서 단기적으로는 효과가 있지만 장기적으로는 비용 부담이 누적됩니다.

반면에 **근육은 제대로 치료가 되면 오래 지속**돼서 얼굴형과 탄력이 함께 유지됩니다. 피부 밑 근육을 치료해 주면 스스로 건강해져 피부도 좋아지는 자기주도학습 같은 효과가 있어요. 피부를 텐트, 근육을 폴대로 비유하면 폴대가 충분히 서야 텐트가 팽팽한 것처럼, 근본 원인인 근육을 다뤄야 결과가 오래갑니다. 효과·지속에는 개인차가 있을 수 있습니다.$AAA$, array['리프팅지속', '써마지', '울쎄라', '근육치료']::text[], 2025, 'XQyB-faru3k-1', 'https://youtu.be/XQyB-faru3k?t=106s', null, '2025-07-09 00:00:00+00'::timestamptz, '2025-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스는 일반 주름 보톡스와 어떻게 다른가요?$AAQ$, $AAA$스킨보톡스는 근육을 마비시키는 게 아니라 피부에 얇게 놔서 긴장도를 살짝 떨어뜨리는 시술이라는 점에서 일반 주름 보톡스와 본질적으로 다릅니다. 기존 주름 보톡스는 그 부위의 긴장도가 10에서 0으로 확 떨어져 표정이 부자연스럽고 어색해져요. 스킨보톡스는 **긴장도를 10에서 5 정도로 낮추는** 방식입니다.

그래서 표정도 잘 지어지고 어색함이 없습니다. 너무 강한 부위만 힘을 빼주고 긴장도를 낮춰주면 **그동안 활동하지 않았던 근육은 다시 살아나면서 건강해지는** 자연스러운 흐름이 생겨요. 또 한 부위만 약하게 하면 다른 부위가 보상성으로 커지기 때문에, 관련된 4~5개 근육을 골고루 같이 치료해 줘야 한다는 점도 차이입니다. 그렇게 하면 무리하게 인위적인 시술을 할 필요가 없어집니다.$AAA$, array['스킨보톡스', '주름보톡스', '근육긴장도', '보상성']::text[], 2025, 'XQyB-faru3k-2', 'https://youtu.be/XQyB-faru3k?t=257s', null, '2025-07-09 00:00:00+00'::timestamptz, '2025-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스 내성이 정말 흔하게 생기나요?$AAQ$, $AAA$보톡스 내성은 사실 생각만큼 흔하지 않습니다. 25년간 수천 명을 진료한 결과 내성을 진짜 확인한 경우는 단 두 분뿐이었어요. 확률적으로 보면 **수천 분의 일 정도로 드문 현상**입니다. 그런데 많은 분들이 내성이 흔한 것처럼 이야기하시는데, 실제로는 다른 원인인 경우가 많습니다.

근육은 보통 4~5개가 협력해서 움직여요. 어느 한 부위에 힘이 없어지면 다른 부위가 대신 일을 하면서 그 부위가 발달하고, 결국 힘이 빠졌던 부위도 다른 근육의 도움으로 빨리 원상복귀돼 효과가 떨어집니다. 즉 **내성이 아니라 연관 부위를 같이 치료해 주지 않아서 반응이 떨어지는 것**으로 보는 게 더 맞아요. 다섯 개 근육을 골고루 같이 치료하면 그런 반응은 잘 나타나지 않습니다. 개인차는 있을 수 있습니다.$AAA$, array['보톡스내성', '근육협력', '효과저하', '수천분의일']::text[], 2025, 'XQyB-faru3k-3', 'https://youtu.be/XQyB-faru3k?t=534s', null, '2025-07-09 00:00:00+00'::timestamptz, '2025-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$집에서 할 수 있는 표정 근육 운동은 어떻게 하나요?$AAQ$, $AAA$집에서 하는 표정 피트니스는 약해진 중안면 근육을 살리는 게 핵심입니다. 우리는 평소 무의식적으로 입에 힘을 주고 있어 입, 턱, 미간이 인상 쓰는 모습이 되는데, 본인은 그게 무표정이라 생각해요. 그래서 먼저 "은" 소리를 내며 치아만 살짝 떼주면 턱과 하안면 근육의 힘이 빠집니다.

이 동작을 **15분~30분마다 한 번씩** 해주며 힘 빼는 연습을 하는 게 우선이에요. 그다음으로 호랑이가 어흥 하듯 인상을 쓰면서 5~10초를 버텨주면 미간 옆과 중안면 근육이 살아납니다. 이걸 **아침에 15번, 저녁에 15번씩 3개월** 꾸준히 하면 약해진 중안면 근육이 살아나면서 예쁜 애플 볼이 생긴다는 게 핵심이에요. 효과 정도엔 개인차가 있을 수 있어요. 사람 많은 곳에서 하면 오해받을 수 있으니 혼자 있을 때 해주세요.$AAA$, array['표정피트니스', '중안면근육', '애플볼', '셀프PT']::text[], 2025, 'XQyB-faru3k-4', 'https://youtu.be/XQyB-faru3k?t=381s', null, '2025-07-09 00:00:00+00'::timestamptz, '2025-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스는 효과가 언제부터 나타나고 얼마나 가나요?$AAQ$, $AAA$스킨보톡스는 시술 후 2~3일 정도면 바로 티가 나기 시작하고 일주일 정도면 효과가 거의 다 올라옵니다. 그래서 "피부에 뭐 했어?", "피부 좋아 보인다" 같은 얘기를 듣게 돼요. 소개팅이나 결혼식 같은 중요한 일정을 앞두고 받으러 오시는 분들이 많은 이유입니다.

시술 효과는 보통 **3~4개월 정도** 충분히 유지됩니다. 한 가지 시술만으로 피부결 개선, 잔주름, 리프팅, 모공, 피지, 여드름 개선까지 다양한 효과를 낼 수 있어 가성비가 좋은 편이에요. 처음에 주사 바늘 자국이나 엠보싱, 약간의 멍이 생길 수 있지만 **하루 이틀이면 다 사라지고 시술 자체는 거의 티가 나지 않습니다**. 효과 정도에는 개인차가 있을 수 있어요.$AAA$, array['스킨보톡스', '효과지속', '다운타임', '발현시점']::text[], 2025, 'q0hIuB5M_-Y-1', 'https://youtu.be/q0hIuB5M_-Y?t=244s', null, '2025-07-10 00:00:00+00'::timestamptz, '2025-07-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스는 어떤 사람에게 잘 맞나요?$AAQ$, $AAA$스킨보톡스는 피부가 칙칙하고 모공이 넓으며 잔주름과 T존 기름기까지 함께 고민인 분들에게 잘 맞는 시술입니다. 피부가 좋아지고 싶은데 어떤 걸 해야 할지 모르겠거나 비싼 시술은 부담스럽고, 티는 안 났으면 좋겠지만 효과는 빨랐으면 하는 분들에게 추천돼요. 피부과 입문용으로도 적합합니다.

시술 자체가 피지선 활동을 줄여줘서 **얼굴 기름기와 모공이 확 줄어드는 효과**가 있어요. 그래서 여드름 피부, 홍조, 얼굴이 붉으신 분, 기름기가 많으신 분, 모공이 고민이신 분들 모두에게 효과가 좋습니다. 피부결과 잔주름 개선, 리프팅, 피지·모공·여드름 개선까지 동시에 잡아주는 시술이라 **올인원 시술이라 부를 만큼 다용도**예요. 만족도엔 개인차가 있을 수 있습니다.$AAA$, array['스킨보톡스적응증', '지성피부', '모공', '여드름', '홍조']::text[], 2025, 'q0hIuB5M_-Y-2', 'https://youtu.be/q0hIuB5M_-Y?t=193s', null, '2025-07-10 00:00:00+00'::timestamptz, '2025-07-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스 시술이 많이 아픈가요?$AAQ$, $AAA$스킨보톡스는 원래 아픈 시술이지만 요즘은 마취크림을 잘 바르면 거의 아프지 않게 받으실 수 있습니다. 얇은 바늘로 피부 표면을 계속 찌르며 보톡스를 조금씩 주입하는 방식이라 원래는 얼굴 전체를 찌르는 만큼 통증이 강해요. 피부 바깥쪽에는 신경세포가 많아 아픔이 더 강하게 느껴지는 부분도 있어요.

그래서 예전에는 **아파서 울면서 시술받는 분들도 많았던** 시술입니다. 최근에는 안 아프게 놓는 방법이 개발되어, 마취크림만 잘 발라도 "진짜 거의 안 아픈데요?", "하나도 안 아픈데요?"라는 반응을 보이는 분들이 많아요. 통증을 거의 느끼지 못할 정도로 받을 수 있어 시술 진입 장벽이 크게 낮아졌습니다. 통증 체감엔 개인차가 있을 수 있습니다.$AAA$, array['스킨보톡스통증', '마취크림', '주사통증', '시술경험']::text[], 2025, 'q0hIuB5M_-Y-3', 'https://youtu.be/q0hIuB5M_-Y?t=451s', null, '2025-07-10 00:00:00+00'::timestamptz, '2025-07-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스에 윤곽 보톡스를 추가하면 뭐가 달라지나요?$AAQ$, $AAA$스킨보톡스에 윤곽 보톡스를 함께하면 피부결 개선 위에 얼굴 작아 보이는 효과까지 더해져 전체 실루엣이 달라집니다. 스킨보톡스는 피부 전체에 골고루 맞아 결과 톤을 정리하는 반면, 윤곽 보톡스는 이마, 얼굴 옆라인, 관자놀이 위, 귀 뒤, 턱 라인을 따라 놓아 윤곽을 잡아줘요.

두 시술을 함께하면 **갸름하고 잘 빚어놓은 도자기 같은 반짝반짝한 느낌**이 듭니다. 스킨보톡스만으로도 피부가 매끈해지지만 윤곽 보톡스가 더해지면 "얼굴 작아졌다, 살 빠져 보인다"는 반응이 더 강해져요. 사각턱이나 침샘이 크거나 이중턱, 턱 늘어짐이 심한 분, 특히 사각턱이 발달한 남성분들은 **윤곽 부위에 용량을 좀 더 추가해서 따로 조절**해야 합니다. 결과에는 개인차가 있을 수 있어요.$AAA$, array['스킨보톡스', '윤곽보톡스', '사각턱', '얼굴라인']::text[], 2025, 'q0hIuB5M_-Y-4', 'https://youtu.be/q0hIuB5M_-Y?t=360s', null, '2025-07-10 00:00:00+00'::timestamptz, '2025-07-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부도 선크림을 500원 동전만큼 발라야 하나요?$AAQ$, $AAA$지성 피부라면 평소엔 500원 동전만큼 다 바르지 않아도 괜찮습니다. 이론상 500원 동전 크기가 권장량이지만, 메이크업을 하거나 야외 활동이 많지 않다면 그 정도까지는 바르기 어려운 게 현실이에요. 여자들은 화장도 해야 해서 양을 조절하는 경우가 많습니다.

다만 **휴가나 강한 햇빛에 오래 노출될 때는 500원 크기만큼 제대로** 바릅니다. 평소엔 완두콩 두 개 크기만큼 바르고 위에 파운데이션을 얹어 자외선 차단 기능으로 보강하는 방법이 있어요. 지성 피부는 너무 기름진 제품을 쓰면 모공이 두드러지고 기름광이 흘러 화장이 밀리거나 다크닝이 오기 쉬워서, **굉장히 산뜻하게 화장이 안 밀리는 정도의 선크림**을 고르는 게 핵심입니다. 햇빛에 오래 쬐어야 한다면 그땐 화장을 좀 두텁게 합니다.$AAA$, array['선크림용량', '지성피부', '파운데이션', '500원크기']::text[], 2025, 'DyqbYZJxr4I-1', 'https://youtu.be/DyqbYZJxr4I?t=237s', null, '2025-07-11 00:00:00+00'::timestamptz, '2025-07-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림은 눈가에도 발라야 하나요?$AAQ$, $AAA$선크림은 오히려 눈가에 더 잘 발라야 합니다. 눈 주변은 피부가 가장 얇고, 표정을 지을 때 주름도 많이 생기며, 잡티 같은 색소도 잘 생길 수 있는 부위거든요. 그래서 눈꺼풀까지 꼼꼼하게 발라줘야 합니다.

많은 분들이 **눈가는 아이크림 자리지 선크림 자리는 아니라고 오해**해요. 또 눈에 들어가면 안 될 것 같다는 막연한 느낌 때문에 안 바르고 지내다 보니 그 부위만 타서 "펜더처럼" 빨개지는 경우가 생깁니다. 무기자차 제품은 쌍꺼풀 라인, 눈 밑 주름, 모공에 낄 수 있어 발라주신 뒤 자국을 잘 확인해야 하고, 시리거나 따가운 제품이면 **안 시린 제품을 찾아서라도 꼭 눈가에 바르는 게** 좋아요. 따갑다고 안 바르면 안 됩니다.$AAA$, array['눈가선크림', '눈꺼풀', '쌍꺼풀라인', '선크림범위']::text[], 2025, 'DyqbYZJxr4I-2', 'https://youtu.be/DyqbYZJxr4I?t=435s', null, '2025-07-11 00:00:00+00'::timestamptz, '2025-07-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이미 기미가 있는 사람도 틴티드 선크림을 발라도 되나요?$AAQ$, $AAA$이미 기미가 있는 분도 라로슈포제 같은 틴티드 선크림을 바르는 것이 좋습니다. 이 제품이 기존 기미·잡티를 직접 지워주지는 않지만 **앞으로 생길 기미와 잡티를 막아주는** 역할은 분명히 합니다. 그래서 예방 차원에서 충분히 의미가 있어요.

선크림은 피부과 의사들이 가장 강조하는 기본 관리법이에요. 영상에서 양현종 야구 선수의 예시가 나오는데, 야외에서 땡볕에 몇 시간씩 있는 분들이 가부키처럼 선크림을 늘 발라 피부가 늙지 않고 잘 유지된 사례가 자주 언급됩니다. 진짜 한 방에 훅 갈 수 있는 게 자외선 손상이라는 점, 그리고 **20대부터 꾸준히 바르면 안 늙는다**는 점이 핵심입니다. 효과 정도엔 개인차가 있을 수 있어요.$AAA$, array['라로슈포제', '틴티드선크림', '기미예방', '광노화']::text[], 2025, 'DyqbYZJxr4I-3', 'https://youtu.be/DyqbYZJxr4I?t=572s', null, '2025-07-11 00:00:00+00'::timestamptz, '2025-07-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$북방계 얼굴형은 보톡스를 맞으면 안 좋다는데 사실인가요?$AAQ$, $AAA$얼굴이 가늘고 긴 북방계 얼굴형은 보톡스를 무리하게 맞으면 오히려 더 미워질 수 있습니다. 북방계 얼굴은 이미 근육이 발달되지 않은 가늘고 긴 형태인데, 사각턱 같은 부위에 보톡스를 강하게 맞으면 얼굴이 더 뾰족해져 **바나나나 당근형에 가깝게** 변하기 쉽거든요.

그래서 이런 얼굴형에는 근육에 직접 작용하는 주름 보톡스나 많은 양을 쓰는 시술 대신, 살짝 리프팅만 하는 스킨보톡스 시술이 더 적합합니다. 오히려 **볼륨을 채워 계란형을 만드는 시술**이 효과가 좋아요. 대표적으로 지방이식, 볼륨 필러, 그리고 스컬트라 같은 콜라겐 재생 주사 중 하나를 선택해 받는 것이 권장됩니다. 결과엔 개인차가 있을 수 있습니다.$AAA$, array['북방계얼굴', '보톡스금기', '얼굴형', '스컬트라']::text[], 2025, 'kiUtiO132Wk-1', 'https://youtu.be/kiUtiO132Wk?t=149s', null, '2025-07-16 00:00:00+00'::timestamptz, '2025-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라는 어떤 시술인가요?$AAQ$, $AAA$스컬트라는 자가 콜라겐을 만들어내 얼굴을 부드럽게 만들어 주는 시술입니다. 동양에서 가장 예쁘다고 여기는 도자기 같은 곡선형 얼굴, 굴곡 없이 호감 가는 얼굴을 자연스럽게 만들어 주는 게 특징이에요. 자가 콜라겐이 차오르면서 인위적이지 않은 자연스러운 볼륨이 생깁니다.

시술 후 환자분들이 가장 많이 말하는 장점은 **자연스럽고 오래 지속된다는 점**이에요. 다른 필러는 1년~1년 반 정도 가는 반면, 스컬트라는 효과가 2~3년 지속됩니다. "누가 뭐 했는지 티 안 나게 예뻐졌어요" 같은 반응이 많아요. 특히 20~30대 치아 교정으로 앞볼·광대·턱 밑이 꺼진 고구마형이나 땅콩형 얼굴, **40~50대 중안면 볼륨이 빠지면서 처지는 분들**에게 잘 맞는 시술입니다. 결과엔 개인차가 있을 수 있어요.$AAA$, array['스컬트라', '콜라겐재생', '볼륨', '자연스러움', '지속기간']::text[], 2025, 'kiUtiO132Wk-2', 'https://youtu.be/kiUtiO132Wk?t=362s', null, '2025-07-16 00:00:00+00'::timestamptz, '2025-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라와 필러는 어떻게 다른가요?$AAQ$, $AAA$필러는 즉각적으로 결과가 나오는 반면, 스컬트라는 자가 콜라겐을 만들어 자연스럽게 볼륨을 만든다는 점에서 본질적으로 다른 시술입니다. 히알루론산 필러는 몸에 들어가 물을 빨아들이는 성격이라 술 한 잔 하거나 피곤할 때 얼굴이 약간 부어오를 수 있어요.

또 시간이 지나면서 **필러가 녹으며 피부가 울퉁불퉁해지거나** 표정을 짓는 근육의 움직임에 따라 살짝 이동하기도 합니다. 많은 양을 썼을 때 일부 녹지 않는 부분이 남는 경우도 있어요. 그래서 "누가 뭐 했는지 티가 나는 게 싫다"는 분들에게는 부담이 됩니다. 스컬트라는 자가 콜라겐 기반이라 **자연스럽고 효과가 2~3년 정도 오래 지속되는 점**이 차이입니다. 다른 필러가 1년~1년 반인 것과 비교되는 부분이에요. 만족도엔 개인차가 있을 수 있습니다.$AAA$, array['스컬트라', '필러비교', '히알루론산', '지속기간', '자연스러움']::text[], 2025, 'kiUtiO132Wk-3', 'https://youtu.be/kiUtiO132Wk?t=601s', null, '2025-07-16 00:00:00+00'::timestamptz, '2025-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라 결절은 정말 자주 생기나요?$AAQ$, $AAA$스컬트라 결절은 현재 가이드라인을 따르면 부작용 확률이 약 0.1%로 거의 드물게 발생합니다. 결절은 흔히 생각하는 돌이 만들어지는 게 아니라 **콜라겐이 한 곳에 많이 만들어져 생기는 부작용**이에요. 초창기에는 7cc로 희석하라고 했는데 농도가 높다 보니 한 부위에 콜라겐이 과하게 몰리면서 완두콩처럼 만져지는 결절이 생겼습니다.

현재는 가이드라인이 바뀌어 10cc로 희석하면서 이런 문제가 많이 줄었어요. 두 번째로 중요한 건 수화 시간으로, **희석 후 최소 48시간 이상**, 많이 쓰시는 분들은 일주일 정도까지 두면 약물이 잘 녹아 한 곳에 뭉칠 가능성이 낮아집니다. 깊은 층에 소량씩 골고루 퍼뜨려 시술하면 이런 문제는 거의 없어요. 시술하는 분의 테크닉 차이도 큽니다. 결과엔 개인차가 있을 수 있어요.$AAA$, array['스컬트라결절', '희석농도', '수화시간', '부작용확률']::text[], 2025, 'kiUtiO132Wk-4', 'https://youtu.be/kiUtiO132Wk?t=767s', null, '2025-07-16 00:00:00+00'::timestamptz, '2025-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여름 외출 후 피부 열감은 왜 식혀줘야 하나요?$AAQ$, $AAA$외출 후 피부의 열감을 빨리 식히는 게 색소 예방에 중요합니다. 자외선 차단제는 자외선을 막아주지만 **피부가 후끈후끈해지는 원인인 적외선까지는 다 막아주지 못해요**. 그래서 외출 후에도 피부에 열이 남는 경우가 많습니다.

피부에 열이 들어오면 그 열 자체가 염증 반응을 일으키고, 이 염증 반응이 기미나 색소를 유발할 수 있어요. 또 **열 자체가 색소를 많이 만들게 하는 역할**도 알려져 있습니다. 그래서 외출 후 자외선 차단제를 닦아내고 얼굴을 씻은 다음, 알로에 팩이나 쿨링 미스트, 쿨링 패드 등으로 열을 식혀주는 단계가 색소 예방에 도움이 됩니다. 시카 성분이 들어간 패드는 10분 정도 볼에 붙이고 다닐 수 있어 진정 효과까지 함께 노릴 수 있어요. 효과 정도엔 개인차가 있을 수 있습니다.$AAA$, array['피부열감', '적외선', '쿨링', '색소침착예방']::text[], 2025, 'uQHv4h4f3Hg-1', 'https://youtu.be/uQHv4h4f3Hg?t=39s', null, '2025-07-17 00:00:00+00'::timestamptz, '2025-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C와 글루타치온, 나이아신아마이드는 어떻게 다른가요?$AAQ$, $AAA$이 세 가지는 작용 방식이 달라 함께 쓰면 미백 시너지를 낼 수 있는 성분들입니다. 비타민C는 미백뿐 아니라 강력한 항산화 효과까지 가지고 있어 색소 예방과 자외선 손상 방어를 동시에 합니다. 다만 **빛과 열에 불안정**해 보관과 사용에 주의가 필요해요.

글루타치온은 우리 몸에서 자연적으로 만들어지는 항산화 물질로, 이미 만들어진 색소를 줄이고 색소 생성을 억제하는 역할을 합니다. 나이아신아마이드는 색소가 멜라닌 세포에서 각질세포로 전달되는 과정을 차단해, 마치 "제품이 만들어졌는데 택배로 배달되는 과정을 막는" 방식이에요. **빛과 열에 안정적이고 자극이 적어** 넓은 부위에도 무리 없이 쓸 수 있습니다. 각 성분의 효과 정도엔 개인차가 있을 수 있어요.$AAA$, array['비타민C', '글루타치온', '나이아신아마이드', '미백성분']::text[], 2025, 'uQHv4h4f3Hg-2', 'https://youtu.be/uQHv4h4f3Hg?t=203s', null, '2025-07-17 00:00:00+00'::timestamptz, '2025-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자외선 차단제만으로 햇빛 차단이 충분한가요?$AAQ$, $AAA$자외선 차단제만으로는 햇빛을 충분히 차단할 수 없습니다. 첫째, 자외선 차단제는 자외선을 100% 다 막아주지 못해요. 둘째, **자외선이 아닌 가시광선이나 적외선까지는 막아주지 못합니다**. 그래서 물리적 차단을 함께해야 합니다.

선캡, 양산, 선글라스 중 적어도 두 가지는 챙겨 나가는 게 좋아요. 자외선 차단제 바르고 선캡을 쓰거나, 양산과 선글라스를 함께 쓰는 식입니다. 선캡만 쓰면 옆쪽으로 해가 들어오기 때문에 **여러 도구를 조합하는 게 효과적**이에요. 양산을 들기 애매한 상황에서는 UV 차단되는 큰 챙 모자나 옆까지 가려주는 제품을 사용하면 옆쪽까지 햇빛이 거의 안 들어옵니다. 차단 효과엔 개인차가 있을 수 있어요.$AAA$, array['자외선차단', '물리적차단', '선캡', '양산', '가시광선']::text[], 2025, 'uQHv4h4f3Hg-3', 'https://youtu.be/uQHv4h4f3Hg?t=574s', null, '2025-07-17 00:00:00+00'::timestamptz, '2025-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여름철 바디 미백엔 어떤 성분이 도움이 되나요?$AAQ$, $AAA$여름철 바디 미백엔 글루타치온과 나이아신아마이드가 들어간 제품이 도움이 됩니다. 비욘드의 바디타민 라인처럼 **나이아신아마이드 5%가 들어간 바디로션**은 끈적이지 않고 산뜻하면서 몸의 미백을 같이 챙겨주는 제품이에요.

나이아신아마이드는 이미 만들어진 색소가 피부 위쪽 각질세포로 전달되는 과정을 차단해 색소가 진해 보이는 것을 막아 줍니다. 또 빛과 열에 안정적이고 **다른 미백 성분에 비해 자극이 적어 바디에 넓게 발라도 큰 문제가 없는 점**이 장점이에요. 여름엔 반팔·반바지·샌들을 신어 팔·다리·발등까지 타기 쉬우므로, 샤워 후 미백 성분 들어간 바디로션을 발라주면 잡티 관리에 도움이 됩니다. 효과 정도엔 개인차가 있을 수 있습니다.$AAA$, array['바디미백', '나이아신아마이드', '글루타치온', '바디로션']::text[], 2025, 'uQHv4h4f3Hg-4', 'https://youtu.be/uQHv4h4f3Hg?t=670s', null, '2025-07-17 00:00:00+00'::timestamptz, '2025-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여행 갈 때 리도멕스 연고는 어떨 때 발라야 하나요?$AAQ$, $AAA$리도멕스는 벌레 물림, 알러지, 가려움이 있을 때 바르기 무난한 약국용 스테로이드 연고입니다. 스테로이드는 강함·중간·약함 세 등급이 있는데 **리도멕스는 가장 약한 스테로이드**라 여행지에서 가볍게 사용하기 적합해요. 동남아 여행지의 벌레 물림이나 유럽의 배드버그로 인한 염증·알러지 반응에 활용도가 높습니다.

스테로이드 사용이 부담스럽거나 어디에 발라야 할지 모르겠다면 비판텐도 괜찮은 대안이에요. **비판텐은 피부 재생과 보습에 효과가 있다고 알려져** 있습니다. 상처가 났을 때는 에스로반 항생제 연고를 주변을 깨끗하게 닦은 뒤 발라주면 2차 감염을 방지하고 피부 환경을 깨끗하게 해줍니다. 자녀가 있다면 듀오덤 성분의 하이드로콜로이드 키즈밴드도 흉터 예방에 좋아요. 사용 후 증상이 지속되면 진료를 받는 게 좋습니다.$AAA$, array['리도멕스', '스테로이드연고', '여행상비약', '벌레물림']::text[], 2025, 'u76XOkZVaqY-1', 'https://youtu.be/u76XOkZVaqY?t=74s', null, '2025-07-18 00:00:00+00'::timestamptz, '2025-07-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여행 갈 때 샤워기 필터가 정말 필요한가요?$AAQ$, $AAA$민감한 피부거나 아토피, 습진이 있는 분은 여행지의 수돗물 환경을 고려해 샤워기 필터를 챙기는 게 좋습니다. 우리나라는 어딜 가도 물이 깨끗한 편이라 트러블이 잘 안 나지만, **동남아와 유럽은 수돗물 성질이 달라** 피부와 머릿결에 영향을 줄 수 있어요.

필터는 용도가 달라 행선지에 맞춰 선택해야 합니다. 유럽은 물에 석회질이 섞여 있어 **석회질 필터**가 좋고, 머릿결이 뻣뻣해질 수 있으니 트리트먼트도 함께 챙기는 걸 권합니다. 동남아 수돗물은 잔류염소가 남아 있어 **염소를 거를 수 있는 필터**가 적합해요. 녹물이 많이 나오는 환경에서도 염소 필터가 도움이 됩니다. 피부가 건강하거나 지성이라면 굳이 필요하진 않지만, 민감 피부에는 큰 차이를 만들 수 있어요. 효과엔 개인차가 있을 수 있습니다.$AAA$, array['샤워기필터', '석회질', '잔류염소', '민감피부', '여행준비']::text[], 2025, 'u76XOkZVaqY-2', 'https://youtu.be/u76XOkZVaqY?t=209s', null, '2025-07-18 00:00:00+00'::timestamptz, '2025-07-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$SPF 50과 SPF 100은 차단력 차이가 큰가요?$AAQ$, $AAA$SPF 50과 SPF 100은 차단율에서 거의 차이가 없습니다. 숫자가 두 배라고 차단력이 두 배가 되는 게 아니에요. **SPF는 일광화상을 일으키는 UVB를 차단**하는 지표인데, SPF 50 이상이면 차단율이 이미 매우 높은 구간에 있어 그 이상은 큰 의미가 없습니다.

그래서 SPF 숫자를 올리는 것보다 **SPF 50 이상 제품을 2~3시간마다 덧발라 주는 것**이 가장 좋습니다. PA는 피부를 주름지고 늙어 보이게 하는 UVA를 차단해 주는 지표로, 플러스 개수가 많을수록 차단력이 강해요. 그래서 PA+++나 PA++++인 선크림을 선택하는 게 좋습니다. 색소나 노화가 걱정되는 분은 산화철 성분이 들어가 가시광선까지 차단하는 틴티드 선크림 표기 여부도 확인해 보세요. 효과엔 개인차가 있을 수 있어요.$AAA$, array['SPF50', 'SPF100', 'PA지수', '덧바르기', '틴티드선크림']::text[], 2025, 'u76XOkZVaqY-3', 'https://youtu.be/u76XOkZVaqY?t=525s', null, '2025-07-18 00:00:00+00'::timestamptz, '2025-07-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여행 중 가벼운 햇볕 화상엔 어떻게 응급처치하나요?$AAQ$, $AAA$가벼운 햇볕 화상엔 가장 먼저 쿨링이 필요합니다. 약국에서 파는 일회용 생리식염수를 거즈에 적셔 화상 부위에 올려주는 게 가장 좋아요. 거즈가 없다면 **화장솜에 생리식염수를 적셔 올려주기만 해도 쿨링** 효과를 볼 수 있습니다. 생리식염수는 냉장고에 넣어 두면 더 시원하게 사용할 수 있어요.

쿨링 다음으로 중요한 건 보습입니다. **로션이나 크림을 바로 발라 보습을 잘 해주는 단계를 잊지 않는 것**이 회복에 핵심이에요. 통증이 심하면 타이레놀이나 이지엔6 같은 진통제로 통증을 줄여줄 수 있고, 화상이 심해 피부가 벗겨질 정도일 때도 진통제가 도움이 됩니다. 다만 화상이 광범위하거나 물집이 크거나 통증이 심하면 현지 의료기관을 찾는 게 안전합니다. 회복 정도엔 개인차가 있을 수 있어요.$AAA$, array['햇볕화상', '응급처치', '생리식염수쿨링', '보습', '진통제']::text[], 2025, 'u76XOkZVaqY-4', 'https://youtu.be/u76XOkZVaqY?t=629s', null, '2025-07-18 00:00:00+00'::timestamptz, '2025-07-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모기 물린 곳에 침 발라도 괜찮나요?$AAQ$, $AAA$모기 물린 부위에 침을 바르면 세균 감염 위험이 커서 절대 피해야 합니다. 모기에 물려 상처가 난 자리에 침을 바르는 것은 **세균 덩어리를 상처에 바르는 것**과 다름없기 때문이에요.

잘못하면 물린 부위가 붓고 진물이 나고 곪아서 항생제를 먹어야 할 수도 있습니다. 손톱으로 십자가 모양을 눌러서 자국을 만드는 방법도 권장하지 않아요. 잠깐 덜 가렵게 느껴지는 이유는 가려운 감각이 통증에 덮여서 그런 것일 뿐이고, 우리 뇌가 **두 자극 중 더 강한 자극에 집중하기 때문에** 일시적으로 가려움이 줄어든 것처럼 느끼는 거예요. 가장 좋은 방법은 흐르는 물과 비누로 헹군 뒤 얼음팩을 거즈에 감싸 5분에서 10분 정도 냉찜질하는 것입니다.$AAA$, array['모기물림', '침바르기', '세균감염', '냉찜질', '응급처치']::text[], 2025, 'cNDqgARTmSw-1', 'https://youtu.be/cNDqgARTmSw?t=61s', null, '2025-07-22 00:00:00+00'::timestamptz, '2025-07-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모기 물린 후 가려움을 진정시키는 약은 어떤 게 좋나요?$AAQ$, $AAA$모기 물린 곳에는 버물리, 서버쿨, 물린디쿨 같은 디펜하이드라민 염산염 항히스타민제 성분이 들어간 약이 가려움증을 줄여줍니다. 제품에 따라 국소 마취제나 멘톨, 캄파 같은 성분도 들어 있어요.

다만 캄파 성분은 피부로 쉽게 흡수되어 어린이에게 경련 위험이 있을 수 있어 **30개월 이하 아이에게는 사용 금지**입니다. 어린 아이들에게는 버물리 키드나 서버쿨 키드 같은 전용 제품을 써야 해요. 또한 이미 많이 긁어서 상처가 난 부위는 이런 약을 바르면 자극이 될 수 있어, **가려운 곳에는 스테로이드 연고 상처에는 박트로반 같은 항생제 연고**를 도포하는 것이 좋습니다. 그래도 가려우면 약국에서 지르텍 같은 먹는 항히스타민제를 짧게 복용해볼 수 있어요.$AAA$, array['버물리', '항히스타민제', '캄파성분', '어린이주의', '스테로이드연고']::text[], 2025, 'cNDqgARTmSw-2', 'https://youtu.be/cNDqgARTmSw?t=425s', null, '2025-07-22 00:00:00+00'::timestamptz, '2025-07-22 00:00:00+00'::timestamptz);
